import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { 
  Send, 
  Trash2, 
  MessageSquare, 
  Cpu, 
  Keyboard, 
  Globe, 
  Loader2,
  Sparkles
} from 'lucide-react';

// --- API Initialization ---
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Types ---
interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isComposing, setIsComposing] = useState(false); // Track IME composition status

  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  // Focus input on load
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSendMessage = useCallback(async () => {
    if (!inputText.trim() || isLoading || isComposing) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText.trim(),
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: inputText.trim(),
        config: {
          systemInstruction: 'You are a helpful assistant. Respond concisely and professionally. Support multi-language communication including Chinese and Japanese.',
        },
      });

      const modelMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.text || 'Sorry, I couldn't generate a response.',
        timestamp: new Date(),
      };

      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      console.error('Gemini API Error:', error);
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: 'An error occurred while communicating with the AI. Please try again.',
        timestamp: new Date(),
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
      // Re-focus after sending
      inputRef.current?.focus();
    }
  }, [inputText, isLoading, isComposing]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Only send if Enter is pressed without Shift AND we are NOT in the middle of IME composition
    if (e.key === 'Enter' && !e.shiftKey && !isComposing) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearHistory = () => {
    setMessages([]);
    inputRef.current?.focus();
  };

  return (
    <div className="flex flex-col h-screen bg-[#0a0a0c] text-slate-200 font-sans antialiased">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-black/40 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
            <Cpu size={20} className="text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              Gemini IME-Ready Chat
            </h1>
            <p className="text-xs text-slate-500 flex items-center gap-1">
              <Globe size={10} /> Supports 中文, 日本語, English & more
            </p>
          </div>
        </div>
        <button 
          onClick={clearHistory}
          className="p-2 hover:bg-white/5 rounded-full transition-colors text-slate-500 hover:text-red-400"
          title="Clear History"
        >
          <Trash2 size={18} />
        </button>
      </header>

      {/* Chat Area */}
      <main 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 scroll-smooth"
      >
        {messages.length === 0 && !isLoading && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-4 animate-in fade-in zoom-in duration-700">
            <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mb-2">
              <MessageSquare className="text-slate-600" size={32} />
            </div>
            <h2 className="text-xl font-medium text-slate-400">Welcome! Try typing in any language.</h2>
            <p className="max-w-xs text-sm text-slate-500">
              Input Chinese (中文), Japanese (日本語), or any symbols. This interface is optimized for IME stability.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
          >
            <div 
              className={`max-w-[85%] md:max-w-[70%] p-4 rounded-2xl shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white/10 text-slate-200 border border-white/5 rounded-tl-none'
              }`}
            >
              <div className="whitespace-pre-wrap leading-relaxed text-[15px]">{msg.text}</div>
              <div className={`text-[10px] mt-2 opacity-50 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-white/5 p-4 rounded-2xl rounded-tl-none border border-white/5 flex items-center gap-3">
              <Loader2 className="animate-spin text-indigo-400" size={18} />
              <span className="text-sm text-slate-400 italic">Thinking...</span>
            </div>
          </div>
        )}
      </main>

      {/* Input Section */}
      <footer className="p-4 md:p-6 bg-gradient-to-t from-black to-transparent">
        <div className="max-w-4xl mx-auto relative">
          <div className="absolute -top-6 left-2 flex items-center gap-2">
            {isComposing && (
              <span className="flex items-center gap-1.5 px-2 py-0.5 rounded bg-amber-500/20 text-amber-500 text-[10px] font-bold uppercase tracking-wider border border-amber-500/20">
                <Keyboard size={10} /> IME Active
              </span>
            )}
            <span className="flex items-center gap-1.5 px-2 py-0.5 rounded bg-indigo-500/20 text-indigo-400 text-[10px] font-bold uppercase tracking-wider border border-indigo-500/20">
              <Sparkles size={10} /> Gemini 3 Flash
            </span>
          </div>

          <div className="relative flex items-end gap-2 bg-[#16161a] border border-white/10 rounded-2xl p-2 focus-within:border-indigo-500/50 focus-within:ring-1 focus-within:ring-indigo-500/20 transition-all shadow-2xl">
            <textarea
              ref={inputRef}
              rows={1}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={handleKeyDown}
              // CRITICAL: Handle IME events to prevent premature submission or state clashes
              onCompositionStart={() => setIsComposing(true)}
              onCompositionEnd={() => setIsComposing(false)}
              placeholder="Type your message... (支持中文、日本語输入)"
              className="flex-1 max-h-48 min-h-[44px] bg-transparent border-none focus:ring-0 text-slate-200 resize-none py-3 px-3 placeholder:text-slate-600 text-[15px]"
              style={{ height: 'auto' }}
              onInput={(e) => {
                const target = e.target as HTMLTextAreaElement;
                target.style.height = 'auto';
                target.style.height = `${target.scrollHeight}px`;
              }}
            />
            <button
              onClick={handleSendMessage}
              disabled={!inputText.trim() || isLoading || isComposing}
              className={`p-3 rounded-xl transition-all ${
                !inputText.trim() || isLoading || isComposing
                  ? 'text-slate-600 bg-white/5' 
                  : 'text-white bg-indigo-600 hover:bg-indigo-500 shadow-lg shadow-indigo-600/20 active:scale-95'
              }`}
            >
              <Send size={20} />
            </button>
          </div>
          <p className="text-[10px] text-center mt-3 text-slate-500 uppercase tracking-tighter opacity-50">
            Powered by Google Gemini • IME Stable Input v1.0
          </p>
        </div>
      </footer>
    </div>
  );
};

// Render
const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

