import { TEXT } from '../ui/constants';

/**
 * ===== Date Parsing Rules =====
 * iOS Safari compatibility: replaces '-' with '/' for broad support
 */
export const parseConcertDate = (dateStr: string | null | undefined, type: 'CONCERT' | 'NORMAL'): Date | null => {
  if (!dateStr || dateStr === TEXT.GLOBAL.TBD) return null;

  // Standardize format for iOS: "2023-10-27" -> "2023/10/27"
  const standardizedStr = dateStr.replace(/-/g, '/');

  const d = new Date(standardizedStr);
  if (isNaN(d.getTime())) {
    // Fallback parsing for manual extraction if Date still fails
    try {
      const parts = dateStr.split(' ');
      const dateParts = parts[0].split('-').map(Number);
      if (parts.length > 1) {
        const timeParts = parts[1].split(':').map(Number);
        return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], timeParts[0], timeParts[1] || 0);
      }
      if (type === 'CONCERT') {
        return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], 21, 0, 0);
      }
      return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], 12, 0, 0);
    } catch (e) {
      return null;
    }
  }

  // If input was just date, enforce specific hours
  if (!dateStr.includes(' ')) {
    const y = d.getFullYear();
    const m = d.getMonth();
    const day = d.getDate();
    if (type === 'CONCERT') {
      return new Date(y, m, day, 21, 0, 0);
    }
    return new Date(y, m, day, 12, 0, 0);
  }

  return d;
};

/**
 * ===== Calendar Logic =====
 */

export const EVENT_PRIORITY: Record<CalendarEventType, number> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: 1,
  [TEXT.CALENDAR.EVENT_RESULT]: 2,
  [TEXT.CALENDAR.EVENT_DEADLINE]: 3,
  [TEXT.CALENDAR.EVENT_SALE]: 4,
};

const extractDateAndTime = (str: string | null | undefined): { date: string; time?: string } | null => {
  if (!str || str === TEXT.GLOBAL.TBD) return null;
  const parts = str.split(' ');
  return { date: parts[0], time: parts[1] ? parts[1].substring(0, 5) : undefined };
};

export const buildCalendarEvents = (artists: Artist[], settings: { showAttended: boolean; showSkipped: boolean }): CalendarEvent[] => {
  const events: CalendarEvent[] = [];

  artists.forEach(artist => {
    artist.tours.forEach(tour => {
      tour.concerts.forEach(concert => {
        if (!settings.showAttended && concert.status === '参戦済み') return;
        if (!settings.showSkipped && concert.status === '見送') return;

        const title = `${artist.name} / ${tour.name}`;

        // A) 公演
        const cInfo = extractDateAndTime(concert.concertAt || concert.date);
        if (cInfo) {
          events.push({
            dateKey: cInfo.date,
            timeLabel: cInfo.time,
            type: TEXT.CALENDAR.EVENT_CONCERT as CalendarEventType,
            artistId: artist.id,
            tourId: tour.id,
            concertId: concert.id,
            title,
            status: concert.status,
          });
        }

        // B) 抽選結果
        if (concert.status === '抽選中') {
          const rInfo = extractDateAndTime(concert.resultAt);
          if (rInfo) {
            events.push({
              dateKey: rInfo.date,
              timeLabel: rInfo.time,
              type: TEXT.CALENDAR.EVENT_RESULT as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // C) 発売開始
        if (concert.status === '発売前') {
          const sInfo = extractDateAndTime(concert.saleAt);
          if (sInfo) {
            events.push({
              dateKey: sInfo.date,
              timeLabel: sInfo.time,
              type: TEXT.CALENDAR.EVENT_SALE as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // D) 申込締切
        if (concert.status === '検討中') {
          const dInfo = extractDateAndTime(concert.deadlineAt);
          if (dInfo) {
            events.push({
              dateKey: dInfo.date,
              timeLabel: dInfo.time,
              type: TEXT.CALENDAR.EVENT_DEADLINE as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }
      });
    });
  });

  return events;
};

export const getDueAction = (concert: Concert, now: Date = new Date()): DueAction | null => {
  const saleTime = parseConcertDate(concert.saleAt, 'NORMAL');
  const deadlineTime = parseConcertDate(concert.deadlineAt, 'NORMAL');
  const resultTime = parseConcertDate(concert.resultAt, 'NORMAL');
  const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');

  switch (concert.status) {
    case '発売前':
      if (saleTime && now >= saleTime) return 'ASK_BUY_AT_SALE';
      return null;
    case '検討中':
      if (deadlineTime && now >= deadlineTime) return 'ASK_BUY_AT_DEADLINE';
      if (!deadlineTime) return 'NEED_SET_DEADLINE_AT';
      return null;
    case '抽選中':
      if (resultTime && now >= resultTime) return 'ASK_RESULT';
      if (!resultTime) return 'NEED_SET_RESULT_AT';
      return null;
    case '参戦予定':
      if (!concertTime) return 'NEED_SET_CONCERT_AT';
      return null;
    default:
      return null;
  }
};

export const autoAdvanceConcertStatus = (concert: Concert, now: Date = new Date()): Concert => {
  if (concert.status === '参戦予定') {
    const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');
    if (concertTime && now >= concertTime) {
      return { ...concert, status: '参戦済み' };
    }
  }
  return concert;
};

export const applyDecision = (
  concert: Concert, 
  decision: 'BUY' | 'CONSIDER' | 'SKIP' | 'WON' | 'LOST', 
  payload?: { lotteryName?: string; resultAt?: string; concertAt?: string }
): Concert => {
  switch (decision) {
    case 'BUY':
      return { 
        ...concert, 
        status: '抽選中', 
        lotteryName: payload?.lotteryName ?? concert.lotteryName,
        resultAt: payload?.resultAt ?? concert.resultAt 
      };
    case 'CONSIDER':
      return { ...concert, status: '検討中' };
    case 'SKIP':
      return { ...concert, status: '見送', lotteryResult: null };
    case 'WON':
      return { 
        ...concert, 
        status: '参戦予定', 
        lotteryResult: 'WON',
        concertAt: payload?.concertAt ?? (concert.concertAt || concert.date)
      };
    case 'LOST':
      return { ...concert, status: '見送', lotteryResult: 'LOST' };
    default:
      return concert;
  }
};

const ARTIST_SUB_STATUS_ORDER: Status[] = ['発売前', '検討中', '抽選中', '参戦予定', '参戦済み', '見送'];
const ARTIST_SUB_STATUS_PRIORITY: Record<Status, number> = {
  '発売前': 0, '検討中': 1, '抽選中': 2, '参戦予定': 3, '参戦済み': 4, '見送': 5,
};

const pickArtistSubStatus = (concerts: Concert[]): Status | null => {
  const candidates = concerts
    .map(c => c.status)
    .filter((s): s is Status => ARTIST_SUB_STATUS_ORDER.includes(s));
  if (candidates.length === 0) return null;
  candidates.sort((a, b) => ARTIST_SUB_STATUS_PRIORITY[a] - ARTIST_SUB_STATUS_PRIORITY[b]);
  return candidates[0] ?? null;
};

/**
 * 辅助函数：根据 links 的判定能力生成后缀
 * 优先级：存在 supported →（可），否则存在 unsupported →（不可），否则空
 */
const getTrackSuffix = (artist: Artist): string => {
  const activeLinks = (artist.links || []).filter(l => l.autoTrack);
  if (activeLinks.length === 0) return "";

  const hasSupported = activeLinks.some(l => l.trackCapability === 'supported');
  if (hasSupported) return "（可）";

  const hasUnsupported = activeLinks.some(l => l.trackCapability === 'unsupported');
  if (hasUnsupported) return "（不可）";

  return "";
};

export const calcArtistStatus = (artist: Artist): {
  main: string;
  sub: Status | null;
  trackSuffix: string;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);
  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));
  let main: string = TEXT.ARTIST_STATUS.MAIN_NONE;
  if (hasActiveTour) main = TEXT.ARTIST_STATUS.MAIN_TOURING;
  else if (artist.autoTrackConcerts) main = TEXT.ARTIST_STATUS.MAIN_TRACKING;

  const sub = main === TEXT.ARTIST_STATUS.MAIN_TOURING ? pickArtistSubStatus(allConcerts) : null;

  // 计算后缀 (可)/(不可)
  const trackSuffix = (main === TEXT.ARTIST_STATUS.MAIN_TRACKING || main === TEXT.ARTIST_STATUS.MAIN_TOURING) 
    ? getTrackSuffix(artist) 
    : "";

  return { main, sub, trackSuffix };
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') return [...artists];
  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA.main !== prioB.main) return prioA.main - prioB.main;
    if (prioA.sub !== prioB.sub) return prioA.sub - prioB.sub;
    return a.name.localeCompare(b.name);
  });
};

const getArtistPriority = (artist: Artist) => {
  const status = calcArtistStatus(artist);
  if (status.main === TEXT.ARTIST_STATUS.MAIN_TOURING) return { main: 1, sub: status.sub ? ARTIST_SUB_STATUS_PRIORITY[status.sub] : 99 };
  if (status.main === TEXT.ARTIST_STATUS.MAIN_TRACKING) return { main: 2, sub: 0 };
  return { main: 3, sub: 0 };
};

const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  const dated = concerts.filter(c => c.date !== TEXT.GLOBAL.TBD || c.concertAt);
  if (dated.length === 0) return null;
  return [...dated].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);
    if (prioA !== prioB) return prioA - prioB;
    const dateA = a.concertAt || a.date;
    const dateB = b.concertAt || b.date;
    if (dateA !== TEXT.GLOBAL.TBD && dateB === TEXT.GLOBAL.TBD) return -1;
    if (dateA === TEXT.GLOBAL.TBD && dateB !== TEXT.GLOBAL.TBD) return 1;
    if (dateA !== TEXT.GLOBAL.TBD && dateB !== TEXT.GLOBAL.TBD) return dateA.localeCompare(dateB);
    return 0;
  });
};

export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const getMilestoneDate = (c: Concert) => {
    if (c.status === '抽選中') return c.resultAt;
    if (c.status === '検討中') return c.deadlineAt;
    if (c.status === '発売前') return c.saleAt;
    return null;
  };

  return [...concerts].sort((a, b) => {
    const dateA = getMilestoneDate(a);
    const dateB = getMilestoneDate(b);
    if (dateA && !dateB) return -1;
    if (!dateA && dateB) return 1;
    if (dateA && dateB) return dateA.localeCompare(dateB);
    const cA = a.concertAt || a.date;
    const cB = b.concertAt || b.date;
    if (cA !== TEXT.GLOBAL.TBD && cB !== TEXT.GLOBAL.TBD) return cA.localeCompare(cB);
    if (cA !== TEXT.GLOBAL.TBD) return -1;
    if (cB !== TEXT.GLOBAL.TBD) return 1;
    return 0;
  });
};

export const checkGlobalDateConflicts = (allArtists: Artist[], currentTourId: string, formConcerts: Concert[]): string[] => {
  const otherDates = new Set<string>();
  allArtists.forEach(artist => artist.tours.forEach(tour => {
    if (tour.id === currentTourId) return;
    tour.concerts.forEach(concert => {
      const d = concert.concertAt || concert.date;
      if (d !== TEXT.GLOBAL.TBD && d) otherDates.add(d.split(' ')[0]);
    });
  }));
  const conflicts = new Set<string>();
  const currentDatesInForm = new Set<string>();
  formConcerts.forEach(c => {
    const d = c.concertAt || c.date;
    if (d === TEXT.GLOBAL.TBD || !d) return;
    const dateOnly = d.split(' ')[0];
    if (otherDates.has(dateOnly) || currentDatesInForm.has(dateOnly)) conflicts.add(dateOnly);
    currentDatesInForm.add(dateOnly);
  });
  return Array.from(conflicts);
};

export const getTrackTargetConcerts = (artist: Artist, settings: GlobalSettings, now: Date = new Date()): Concert[] => {
  const n = settings.autoTrackIntervalDays;
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const limitStart = new Date(todayStart.getTime() - n * 24 * 60 * 60 * 1000);
  return artist.tours.flatMap(tour => tour.concerts).filter(concert => {
    if (!TICKET_TRACK_STATUSES.includes(concert.status)) return false;
    const d = concert.concertAt || concert.date;
    if (d === TEXT.GLOBAL.TBD || !d) return false;
    const standardized = d.replace(/-/g, '/');
    const concertDate = new Date(standardized);
    return concertDate >= limitStart && concertDate <= todayStart;
  });
};

export const shouldTriggerAutoTrack = (lastCheckedAt: string | undefined, settings: GlobalSettings, now: Date = new Date()): boolean => {
  if (!lastCheckedAt) return true;
  const diffDays = (now.getTime() - new Date(lastCheckedAt.replace(/-/g, '/')).getTime()) / (1000 * 60 * 60 * 24);
  return diffDays >= settings.autoTrackIntervalDays;
};

import React, { useState, useEffect, useRef } from 'react';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Artist, SiteLink } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';
import { PageShell } from '../ui/PageShell';

interface Props {
  artistId?: string;
  artist?: Artist;
  onSave: (updated: Artist) => void;
  onCancel: () => void;
  onDeleteArtist: (artistId: string) => void;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

/**
 * 确保规格化函数包含所有判定相关的字段
 */
const normalizeLink = (link: Partial<SiteLink> | undefined | null): SiteLink => {
  return {
    name: typeof link?.name === 'string' ? link!.name : '',
    url: typeof link?.url === 'string' ? link!.url : '',
    autoTrack: typeof link?.autoTrack === 'boolean' ? link!.autoTrack : false,
    trackCapability: link?.trackCapability || 'unjudged', 
    trackCapabilityCheckedAt: link?.trackCapabilityCheckedAt,
    lastCheckedAt: link?.lastCheckedAt,
    lastSuccessAt: link?.lastSuccessAt,
    trackingStatus: link?.trackingStatus,
    errorMessage: link?.errorMessage,
    matchedKeywords: link?.matchedKeywords,
    lastHitAt: link?.lastHitAt,
    acknowledgedAt: link?.acknowledgedAt,
  };
};

type LinkJudgeResult = NonNullable<SiteLink['trackCapability']>;

export const ArtistEditorPage: React.FC<Props> = ({
  artistId,
  artist,
  onSave,
  onCancel,
  onDeleteArtist,
}) => {
  const createNewArtist = (): Artist => ({
    id: generateId(),
    name: '',
    imageUrl: '',
    links: [],
    autoTrackConcerts: true,
    autoTrackTickets: true,
    tours: [],
    order: 0,
  });

  const [formData, setFormData] = useState<Artist>(artist ? { ...artist } : createNewArtist());
  const initialSnapshotRef = useRef<string>(JSON.stringify(artist ? { ...artist } : formData));
  const [imageUrlDraft, setImageUrlDraft] = useState(formData.imageUrl);
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isBackConfirmOpen, setIsBackConfirmOpen] = useState(false);

  useEffect(() => {
    if (artist) {
      setFormData({ ...artist });
      setImageUrlDraft(artist.imageUrl);
      initialSnapshotRef.current = JSON.stringify(artist);
    }
  }, [artistId, artist]);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== initialSnapshotRef.current);
  }, [formData]);

  const handleUpdateField = (field: keyof Artist, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  /**
   * 增强型 URL 判定规则
   */
  const judgeTrackability = (url: string): LinkJudgeResult => {
    const u = (url || '').trim();
    if (!u) return 'unjudged';

    const lower = u.toLowerCase();

    // 1. 社交媒体：直接判定为不可
    if (lower.includes('twitter.com') || lower.includes('x.com') || lower.includes('instagram.com') || lower.includes('facebook.com')) {
      return 'unsupported';
    }

    // 2. 详情页特征：判定为可 (高优先级)
    const hasDetailHint =
      lower.includes('in.html') ||
      lower.includes('id=') ||
      lower.includes('detail') ||
      lower.includes('article') ||
      lower.includes('post/') ||
      lower.includes('view/');

    if (hasDetailHint) return 'supported';

    // 3. 判定列表页/分页页：判定为不可
    // 匹配包含 /news/、/list/、/page/、/p/ 后面紧跟数字或特定结构的 URL
    const isNumberedList = /\/(news|list|page|p|archive)\/\d+/.test(lower);
    const isMrsGreenAppleList = /\/list\/\d+\/\d+/.test(lower); // 处理 /news/list/1/6/
    const isNewsRoot = /\/(news|list|p)\/?(\?.*)?$/.test(lower); // 处理以 /news 或 /news/ 结尾的路径

    if (isNumberedList || isMrsGreenAppleList || isNewsRoot) {
      return 'unsupported';
    }

    // 4. 特定的日程/巡演页面：判定为可
    if (lower.includes('/live') || lower.includes('/tour') || lower.includes('/schedule') || lower.includes('/concert')) {
      return 'supported';
    }

    return 'unjudged';
  };

  const getJudgeLabel = (r: LinkJudgeResult | undefined): string => {
    if (r === 'unsupported') return '不可';
    if (r === 'supported') return '可';
    return '未判定';
  };

  const handleLoadImage = () => {
    if (imageUrlDraft.trim()) {
      handleUpdateField('imageUrl', imageUrlDraft.trim());
    }
  };

  const handleBack = () => {
    if (hasChanges) {
      setIsBackConfirmOpen(true);
    } else {
      onCancel();
    }
  };

  const setLinks = (updater: (prev: SiteLink[]) => SiteLink[]) => {
    setFormData((prev) => {
      const current = Array.isArray(prev.links) ? prev.links : [];
      return { ...prev, links: updater(current) };
    });
  };

  const addLink = () => {
    setLinks((prev) => [...prev, normalizeLink({ name: '', url: '', autoTrack: false, trackCapability: 'unjudged' })]);
  };

  const updateLink = (index: number, patch: Partial<SiteLink>) => {
    setLinks((prev) => prev.map((l, i) => (i !== index ? l : { ...normalizeLink(l), ...patch })));
  };

  const removeLink = (index: number) => {
    setLinks((prev) => prev.filter((_, i) => i !== index));
  };

  /**
   * 判定按钮：确保从当前状态读取 URL 并写回结果
   */
  const runJudgeForLink = (index: number) => {
    setLinks((prev) => {
      const current = prev.map((l) => normalizeLink(l));
      const target = current[index];
      if (!target) return current;

      const result = judgeTrackability(target.url);
      const next = [...current];
      next[index] = {
        ...target,
        trackCapability: result,
        trackCapabilityCheckedAt: new Date().toISOString(),
      };
      return next;
    });
  };

  return (
    <PageShell
      header={
        <header style={headerStyle}>
          <IconButton
            icon={<Icons.X />}
            onClick={handleBack}
            size={40}
            style={{
              color: theme.colors.textSecondary,
              borderColor: 'transparent',
              background: 'transparent',
              boxShadow: 'none',
            }}
          />
          <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>
            {artistId ? 'アーティスト編集' : 'アーティスト追加'}
          </h2>
          {artistId ? (
            <IconButton
              icon={<Icons.Trash />}
              onClick={() => setIsDeleteModalOpen(true)}
              size={40}
              style={{
                color: theme.colors.error,
                borderColor: 'transparent',
                background: 'transparent',
                boxShadow: 'none',
              }}
            />
          ) : (
            <div style={{ width: 40 }} />
          )}
        </header>
      }
    >
      <div style={{ paddingBottom: '160px' }}>
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div
            style={{
              width: '100px',
              height: '100px',
              borderRadius: '50%',
              background: '#F3F4F6',
              border: '4px solid white',
              boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
              overflow: 'hidden',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {formData.imageUrl ? (
              <img src={formData.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <span style={{ fontSize: '32px', opacity: 0.2 }}>👤</span>
            )}
          </div>
        </div>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>基本情報</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              <Field label="アーティスト名 (必须)">
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => handleUpdateField('name', e.target.value)}
                  placeholder="名称を入力"
                  style={inputStyle}
                />
              </Field>
              <Field label="画像URL">
                <div style={{ display: 'flex', gap: '8px' }}>
                  <input
                    type="url"
                    value={imageUrlDraft}
                    onChange={(e) => setImageUrlDraft(e.target.value)}
                    placeholder="https://..."
                    style={inputStyle}
                  />
                  <button onClick={handleLoadImage} style={loadButtonStyle}>
                    読み込み
                  </button>
                </div>
              </Field>
            </div>
          </GlassCard>
        </section>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>追跡設定</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.lg }}>
              <ToggleRow
                label="公演自動追跡"
                subLabel="新規ツアー・公演情報を自动取得します"
                active={formData.autoTrackConcerts}
                onToggle={() => handleUpdateField('autoTrackConcerts', !formData.autoTrackConcerts)}
              />
              <ToggleRow
                label="チケット自動追跡"
                subLabel="販売・抽選情報を自动更新します"
                active={formData.autoTrackTickets}
                onToggle={() => handleUpdateField('autoTrackTickets', !formData.autoTrackTickets)}
              />
            </div>
          </GlassCard>
        </section>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>公式サイト・リンク</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              {formData.links.map((link, idx) => {
                const safe = normalizeLink(link);
                return (
                  <div key={idx} style={linkBoxStyle}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                      <span style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 800 }}>
                        サイト {idx + 1}
                      </span>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <Toggle active={safe.autoTrack} onToggle={() => updateLink(idx, { autoTrack: !safe.autoTrack })} />
                        <button onClick={() => removeLink(idx)} style={iconBtnStyle}>
                          <Icons.Trash />
                        </button>
                      </div>
                    </div>
                    <Field label="サイト名">
                      <input
                        type="text"
                        value={safe.name}
                        onChange={(e) => updateLink(idx, { name: e.target.value })}
                        placeholder="公式サイト等"
                        style={inputStyle}
                      />
                    </Field>
                    <div style={{ height: '8px' }} />
                    <Field label="URL">
                      <input
                        type="url"
                        value={safe.url}
                        onChange={(e) => {
                          updateLink(idx, {
                            url: e.target.value,
                            trackCapability: 'unjudged',
                            trackCapabilityCheckedAt: undefined,
                          });
                        }}
                        placeholder="https://..."
                        style={inputStyle}
                      />
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: '6px', minHeight: '18px' }}>
                        <div style={{ 
                          fontSize: '12px', 
                          color: safe.trackCapability === 'unsupported' ? theme.colors.error : theme.colors.textSecondary,
                          fontWeight: safe.trackCapability !== 'unjudged' ? 'bold' : 'normal'
                        }}>
                          {getJudgeLabel(safe.trackCapability)}
                        </div>
                        <button
                          type="button"
                          onClick={() => runJudgeForLink(idx)}
                          style={{
                            padding: '4px 10px',
                            borderRadius: '999px',
                            border: '1px solid rgba(0,0,0,0.10)',
                            background: 'rgba(255,255,255,0.55)',
                            fontSize: '12px',
                            color: theme.colors.textSecondary,
                            cursor: 'pointer',
                            flexShrink: 0,
                          }}
                        >
                          判定
                        </button>
                      </div>
                    </Field>
                  </div>
                );
              })}
              <button onClick={addLink} style={addLinkButtonStyle}>
                ＋ サイトを追加
              </button>
            </div>
          </GlassCard>
        </section>

        <button
          disabled={!hasChanges || !formData.name}
          onClick={() => onSave(formData)}
          style={{
            width: '100%',
            padding: '16px',
            borderRadius: theme.radius.button,
            fontWeight: 'bold',
            fontSize: '16px',
            cursor: 'pointer',
            border: 'none',
            color: 'white',
            background: !hasChanges || !formData.name ? 'rgba(0,0,0,0.05)' : theme.colors.primary,
          }}
        >
          {TEXT.BUTTONS.SAVE}
        </button>

        <ConfirmDialog
          isOpen={isDeleteModalOpen}
          title={TEXT.ALERTS.DELETE_ARTIST_TITLE}
          message={TEXT.ALERTS.DELETE_ARTIST_MSG}
          confirmLabel={TEXT.BUTTONS.DELETE}
          isDestructive
          onClose={() => setIsDeleteModalOpen(false)}
          onConfirm={() => onDeleteArtist(formData.id)}
        />
        <ConfirmDialog
          isOpen={isBackConfirmOpen}
          title="変更を破棄しますか？"
          message="編集した内容は保存されません。戻りますか？"
          confirmLabel="戻る"
          onClose={() => setIsBackConfirmOpen(false)}
          onConfirm={onCancel}
        />
      </div>
    </PageShell>
  );
};

