import React, { useState, useEffect } from 'react';
import { Modal, Form, Input, DatePicker, Select, Button, Space, Tag, Checkbox, Drawer, TimePicker, Divider, Typography } from 'antd';
import { PageShell } from '../ui/PageShell';
import { GlassCard } from '../ui/GlassCard';
import { theme } from '../ui/theme';
import { Icons } from '../ui/IconButton';
import { Exhibition, ExhibitionTicketSalesStatus, ExhibitionOverallStatus } from '../domain/types';
import dayjs from 'dayjs';

const { RangePicker } = DatePicker;
const { Text } = Typography;

interface ExhibitionsPageProps {
  exhibitions: Exhibition[];
  onUpdateExhibitions: (list: Exhibition[]) => void;
  externalModalOpen?: boolean;
  onModalClose?: () => void;
}

export const ExhibitionsPage: React.FC<ExhibitionsPageProps> = ({ exhibitions, onUpdateExhibitions, externalModalOpen, onModalClose }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingExhibition, setEditingExhibition] = useState<Exhibition | null>(null);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 480);
  const [isDateDrawerOpen, setIsDateDrawerOpen] = useState(false);
  const [form] = Form.useForm();

  const holidaySameAsWeekday = Form.useWatch('holidaySameAsWeekday', form);
  const needsReservation = Form.useWatch('needsReservation', form);
  const ticketSalesStatus = Form.useWatch('ticketSalesStatus', form);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth <= 480);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (externalModalOpen) {
      handleAdd();
    }
  }, [externalModalOpen]);

  const handleAdd = () => {
    setEditingExhibition(null);
    form.resetFields();
    // Set Defaults
    form.setFieldsValue({
      holidaySameAsWeekday: true,
      needsReservation: false,
      ticketSalesStatus: 'not_purchased',
      exhibitionStatus: 'preparing'
    });
    setIsModalOpen(true);
  };

  const handleEdit = (ex: Exhibition) => {
    setEditingExhibition(ex);
    form.setFieldsValue({
      ...ex,
      dates: [dayjs(ex.startDate), dayjs(ex.endDate)],
      // Process Time strings back to dayjs objects
      weekdayTimes: ex.weekdayStartTime && ex.weekdayEndTime ? [dayjs(`2000-01-01 ${ex.weekdayStartTime}`), dayjs(`2000-01-01 ${ex.weekdayEndTime}`)] : undefined,
      holidayTimes: ex.holidayStartTime && ex.holidayEndTime ? [dayjs(`2000-01-01 ${ex.holidayStartTime}`), dayjs(`2000-01-01 ${ex.holidayEndTime}`)] : undefined,
      saleStartAt: ex.saleStartAt ? dayjs(ex.saleStartAt) : undefined,
      reservationDates: ex.reservationStartAt && ex.reservationEndAt ? [dayjs(ex.reservationStartAt), dayjs(ex.reservationEndAt)] : undefined,
    });
    setIsModalOpen(true);
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      const { 
        dates, 
        weekdayTimes, 
        holidayTimes, 
        reservationDates, 
        saleStartAt,
        ...rest 
      } = values;

      const newEx: Exhibition = {
        ...rest,
        id: editingExhibition?.id || Math.random().toString(36).substr(2, 9),
        startDate: dates?.[0]?.format('YYYY-MM-DD') || '',
        endDate: dates?.[1]?.format('YYYY-MM-DD') || '',
        weekdayStartTime: weekdayTimes?.[0]?.format('HH:mm'),
        weekdayEndTime: weekdayTimes?.[1]?.format('HH:mm'),
        holidayStartTime: rest.holidaySameAsWeekday ? weekdayTimes?.[0]?.format('HH:mm') : holidayTimes?.[0]?.format('HH:mm'),
        holidayEndTime: rest.holidaySameAsWeekday ? weekdayTimes?.[1]?.format('HH:mm') : holidayTimes?.[1]?.format('HH:mm'),
        saleStartAt: saleStartAt?.format('YYYY-MM-DD HH:mm'),
        reservationStartAt: reservationDates?.[0]?.format('YYYY-MM-DD HH:mm'),
        reservationEndAt: reservationDates?.[1]?.format('YYYY-MM-DD HH:mm'),
      };

      if (editingExhibition) {
        onUpdateExhibitions(exhibitions.map(e => e.id === editingExhibition.id ? newEx : e));
      } else {
        onUpdateExhibitions([...exhibitions, newEx]);
      }
      setIsModalOpen(false);
      onModalClose?.();
    });
  };

  const handleDelete = (id: string) => {
    Modal.confirm({
      title: '削除しますか？',
      content: 'この展覧会情報を削除してもよろしいですか？',
      onOk: () => onUpdateExhibitions(exhibitions.filter(e => e.id !== id))
    });
  };

  const getStatus = (ex: Exhibition) => {
    const today = dayjs().startOf('day');
    const start = dayjs(ex.startDate);
    const end = dayjs(ex.endDate);

    if (today.isBefore(start)) return { label: '開催前', color: '#9CA3AF' };
    if (today.isAfter(end)) return { label: '終了', color: '#D1D5DB' };
    return { label: '開催中', color: theme.colors.primary };
  };

  const ticketStatusOptions = [
    { label: '販売前', value: 'before_sale' },
    { label: '未購入', value: 'not_purchased' },
    { label: '購入済', value: 'purchased' }
  ];

  const exhibitionStatusOptions = [
    { label: '準備中', value: 'preparing' },
    { label: '開催中', value: 'running' },
    { label: '参加済', value: 'visited' },
    { label: '終了（未参加）', value: 'ended_not_visited' }
  ];

  const SectionHeader = ({ title }: { title: string }) => (
    <div style={{ marginBottom: '8px', marginTop: '16px' }}>
      <Text strong style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{title}</Text>
      <Divider style={{ margin: '4px 0 12px 0' }} />
    </div>
  );

  return (
    <PageShell disablePadding>
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: isMobile ? '1fr' : 'repeat(2, 1fr)', 
        gap: '16px',
        padding: '24px 16px 120px 16px',
        marginTop: 'calc(env(safe-area-inset-top) + 60px)'
      }}>
        {exhibitions.length === 0 ? (
          <div style={{ gridColumn: isMobile ? '1' : 'span 2', padding: '80px 0', textAlign: 'center', color: '#9CA3AF' }}>
            展覧会情報がありません。
          </div>
        ) : (
          exhibitions.map(ex => {
            const status = getStatus(ex);
            // Default Status if missing
            const exStatus = ex.exhibitionStatus || 'preparing';
            const exStatusLabel = exhibitionStatusOptions.find(o => o.value === exStatus)?.label || '準備中';

            return (
              <div key={ex.id} onClick={() => handleEdit(ex)} style={{ position: 'relative' }}>
