                    placeholder="作家名" 
                    value={artist.name} 
                    onChange={e => handleUpdate(idx, { name: e.target.value })} 
                  />
                  <Input 
                    placeholder="備考 (オプション)" 
                    size="small"
                    value={artist.note} 
                    onChange={e => handleUpdate(idx, { note: e.target.value })} 
                  />
                </div>
                <Button 
                  danger 
                  type="text" 
                  icon={<Icons.Trash style={{ width: 16 }} />} 
                  onClick={() => handleRemove(idx)} 
                />
              </div>
            ) : (
              <>
