export type Status = 
  | '発売前' 
  | '検討中' 
  | '抽選中' 
  | '参戦予定' 
  | '参戦済み' 
  | '見送'; 

export const TOUR_ACTIVE_STATUSES: Status[] = ['発売前', '検討中', '抽選中', '参戦予定', '见送'];
export const TICKET_TRACK_STATUSES: Status[] = ['発売前', '検討中', '抽選中'];

export type TrackingErrorType = 
  | '接続できませんでした'
  | 'ページの内容が変わりました'
  | 'アクセスが制限されています'
  | '情報を取得できませんでした';

export type TrackingStatus = 'success' | 'failed' | 'hit';

export type DueAction = 
  | 'ASK_BUY_AT_SALE'
  | 'ASK_BUY_AT_DEADLINE'
  | 'ASK_RESULT'
  | 'NEED_SET_SALE_AT'
  | 'NEED_SET_DEADLINE_AT'
  | 'NEED_SET_RESULT_AT'
  | 'NEED_SET_CONCERT_AT';

export type CalendarEventType = 
  | '公演' 
  | '抽選結果' 
  | '発売開始' 
  | '申込締切'
  | '展覧会';

export interface CalendarEvent {
  dateKey: string;        // YYYY-MM-DD
  timeLabel?: string;     // HH:mm
  type: CalendarEventType;
  artistId: string;
  tourId: string;
  concertId: string;
  title: string;          // Artist Name + Tour Name
  status: Status;
}

export interface SiteLink {
  name: string;
  url: string;
  autoTrack: boolean;
  lastCheckedAt?: string;
  lastSuccessAt?: string;
  matchedKeywords?: string[];
  lastHitAt?: string;
  acknowledgedAt?: string;
  trackingStatus?: TrackingStatus;
  errorMessage?: TrackingErrorType;
  trackCapability?: 'supported' | 'unsupported' | 'unjudged';
  trackCapabilityCheckedAt?: string;
}

export interface Concert {
  id: string;
  date: string;
  venue: string;
  price: number;
  saleLink: string;
  status: Status;
  isParticipated: boolean;
  imageIds: string[];
  images?: string[]; 
  saleAt?: string | null;
  deadlineAt?: string | null;
  resultAt?: string | null;
  concertAt?: string | null;
  lotteryName?: string | null;
  lotteryResult?: 'WON' | 'LOST' | null;
}

export interface Tour {
  id: string;
  name: string;
  imageUrl: string;
