        <Checkbox checked={exhibition.holidaySameAsWeekday} onChange={e => onChange({ holidaySameAsWeekday: e.target.checked })}>休日は平日と同じ</Checkbox>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <TimePicker.RangePicker format="HH:mm" style={{ width: '100%' }} value={exhibition.weekdayStartTime ? [dayjs(`2000-01-01 ${exhibition.weekdayStartTime}`), dayjs(`2000-01-01 ${exhibition.weekdayEndTime}`)] : null} onChange={(t) => onChange({ weekdayStartTime: t?.[0]?.format('HH:mm'), weekdayEndTime: t?.[1]?.format('HH:mm') })} placeholder={['平日始', '終']} />
          {!exhibition.holidaySameAsWeekday && (
            <TimePicker.RangePicker format="HH:mm" style={{ width: '100%' }} value={exhibition.holidayStartTime ? [dayjs(`2000-01-01 ${exhibition.holidayStartTime}`), dayjs(`2000-01-01 ${exhibition.holidayEndTime}`)] : null} onChange={(t) => onChange({ holidayStartTime: t?.[0]?.format('HH:mm'), holidayEndTime: t?.[1]?.format('HH:mm') })} placeholder={['休日始', '終']} />
          )}
        </div>

        <SectionTitle title="料金設定" />
        <Checkbox checked={exhibition.holidayPriceSameAsWeekday} onChange={e => onChange({ holidayPriceSameAsWeekday: e.target.checked })}>休日は平日と同じ</Checkbox>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <InputNumber style={{ width: '100%' }} value={exhibition.weekdayPrice} onChange={v => onChange({ weekdayPrice: v || undefined })} placeholder="平日料金" />
          {!exhibition.holidayPriceSameAsWeekday && (
            <InputNumber style={{ width: '100%' }} value={exhibition.holidayPrice} onChange={v => onChange({ holidayPrice: v || undefined })} placeholder="休日料金" />
          )}
        </div>

        <SectionTitle title="予約设置" />
        <Checkbox checked={exhibition.needsReservation} onChange={e => onChange({ needsReservation: e.target.checked })}>予約が必要</Checkbox>
        {exhibition.needsReservation && (
          <div onClick={() => isMobile && setReserveDrawerOpen(true)}>
             <RangePicker 
              showTime
              style={{ width: '100%' }}
              value={exhibition.reservationStartAt ? [dayjs(exhibition.reservationStartAt), dayjs(exhibition.reservationEndAt)] : null}
              onChange={(dates) => onChange({ 
                reservationStartAt: dates?.[0]?.format('YYYY-MM-DD HH:mm') || '', 
                reservationEndAt: dates?.[1]?.format('YYYY-MM-DD HH:mm') || '' 
              })}
            />
          </div>
        )}
      </div>

      {/* Drawers for mobile selection */}
      <Drawer title="会期を選択" placement="bottom" onClose={() => setDateDrawerOpen(false)} open={dateDrawerOpen} height="auto">
        <RangePicker open style={{ visibility: 'hidden', height: 0 }} getPopupContainer={t => t.parentElement!} onChange={(dates) => onChange({ startDate: dates?.[0]?.format('YYYY-MM-DD') || '', endDate: dates?.[1]?.format('YYYY-MM-DD') || '' })} />
        <div style={{ height: '300px' }} />
      </Drawer>

      <Drawer title="参戦日時" placement="bottom" onClose={() => setVisitDrawerOpen(false)} open={visitDrawerOpen} height="auto">
        <DatePicker showTime open style={{ visibility: 'hidden', height: 0 }} getPopupContainer={t => t.parentElement!} onChange={v => onChange({ visitedAt: v?.format('YYYY-MM-DD HH:mm') })} />
        <div style={{ height: '360px' }} />
      </Drawer>

      <Drawer title="チケット発売" placement="bottom" onClose={() => setTicketDrawerOpen(false)} open={ticketDrawerOpen} height="auto">
        <DatePicker showTime open style={{ visibility: 'hidden', height: 0 }} getPopupContainer={t => t.parentElement!} onChange={v => onChange({ saleStartAt: v?.format('YYYY-MM-DD HH:mm') })} />
        <div style={{ height: '360px' }} />
      </Drawer>
    </GlassCard>
  );
};

