                  <div onClick={() => setTicketDrawerOpen(true)} style={mobileInputStyle}>
                    {exhibition.saleStartAt ? exhibition.saleStartAt : '未設定'}
                  </div>
                ) : (
                  <DatePicker 
                    showTime 
                    getPopupContainer={() => document.body}
                    style={{ width: '100%' }} 
