          </div>
        )}
      </div>

      {/* MOBILE PICKER DRAWERS */}

      {/* 1. 会期 */}
      <Drawer 
        title="会期を選択" 
        placement="bottom" 
        height="420px"
        onClose={() => setDateDrawerOpen(false)} 
        open={dateDrawerOpen}
        extra={<Button type="primary" onClick={() => setDateDrawerOpen(false)}>確定</Button>}
      >
        <div id="drawer-date-container" style={{ display: 'flex', justifyContent: 'center', paddingTop: '20px' }}>
          <RangePicker 
            open
            getPopupContainer={() => document.getElementById('drawer-date-container')!}
            value={exhibition.startDate ? [dayjs(exhibition.startDate), dayjs(exhibition.endDate)] : null}
            onChange={(dates) => onChange({ 
