const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import React, { useState, useRef } from 'react';
import { Drawer, Button, Tag, Divider, Typography } from 'antd';
import { PageShell } from '../ui/PageShell';
import { GlassCard } from '../ui/GlassCard';
import { theme } from '../ui/theme';
import { Icons } from '../ui/IconButton';
import { Exhibition } from '../domain/types';
import { ConfirmDialog } from '../components/ConfirmDialog';
import dayjs from 'dayjs';

const { Text } = Typography;

interface ExhibitionsPageProps {
  exhibitions: Exhibition[];
  onUpdateExhibitions: (list: Exhibition[]) => void;
  onOpenDetail: (id: string) => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
  onAddNew: () => void;
  onExport: () => void;
  onImport: (data: any) => void;
}

export const ExhibitionsPage: React.FC<ExhibitionsPageProps> = ({ 
  exhibitions, 
  onUpdateExhibitions, 
  onOpenDetail,
  isMenuOpenExternally, 
  onMenuClose,
  onAddNew,
  onExport,
  onImport
}) => {
  const [isMobile] = useState(window.innerWidth <= 480);
  const [isImportConfirmOpen, setIsImportConfirmOpen] = useState(false);
  const [stagedImportData, setStagedImportData] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImportClick = () => {
    onMenuClose?.();
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        setStagedImportData(json);
        setIsImportConfirmOpen(true);
      } catch (err) {
        console.error('Import failed:', err);
        window.alert('ファイルの読み込みに失敗しました。');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const executeImport = () => {
    if (stagedImportData) {
      onImport(stagedImportData);
      setStagedImportData(null);
    }
    setIsImportConfirmOpen(false);
  };

  const getStatus = (ex: Exhibition): { label: string; color: string } => {
    if (ex.visitedAt) return { label: '参加済', color: '#10B981' };

    const today = dayjs().startOf('day');
    const start = dayjs(ex.startDate).startOf('day');
    const end = dayjs(ex.endDate).endOf('day');

    if (today.isBefore(start)) return { label: '準備中', color: '#9CA3AF' };
    if (today.isAfter(end)) return { label: '終了', color: '#6B7280' };
    return { label: '開催中', color: theme.colors.primary };
  };

  return (
    <PageShell disablePadding>
      <input 
        type="file" 
        ref={fileInputRef} 
        style={{ display: 'none' }} 
        accept=".json" 
        onChange={handleFileChange} 
      />

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))', 
        gap: '16px',
        padding: '24px 16px 140px 16px',
        marginTop: 'calc(env(safe-area-inset-top) + 20px)'
      }}>
        {exhibitions.length === 0 ? (
          <div style={{ gridColumn: '1 / -1', padding: '120px 0', textAlign: 'center', color: '#9CA3AF', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px' }}>
            <div style={{ fontSize: '48px', opacity: 0.3 }}><Icons.Exhibitions /></div>
            <div style={{ fontWeight: '600' }}>展覧会情報がありません。</div>
          </div>
        ) : (
          exhibitions.map(ex => {
            const status = getStatus(ex);
            return (
              <div key={ex.id} onClick={() => onOpenDetail(ex.id)} style={{ position: 'relative' }}>
                <GlassCard padding="0" style={{ overflow: 'hidden', height: '100%', borderRadius: '24px', boxShadow: '0 4px 20px rgba(0,0,0,0.06)' }}>
                  <div style={{ position: 'relative', paddingTop: '140%', background: '#F3F4F6' }}>
                    {ex.imageUrl ? (
                      <img 
                        src={ex.imageUrl} 
                        style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover' }}
                        alt={ex.title}
                      />
                    ) : (
                      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0.2 }}>
                         <Icons.Exhibitions style={{ width: 48, height: 48 }} />
                      </div>
                    )}

                    <div style={{ position: 'absolute', top: '10px', left: '10px', display: 'flex', gap: '4px' }}>
                      <Tag color={status.color} style={{ margin: 0, borderRadius: '8px', border: 'none', fontWeight: 900, fontSize: '11px', padding: '2px 10px' }}>
                        {status.label}
                      </Tag>
                    </div>

                    <div style={{ 
                      position: 'absolute', 
                      bottom: 0, 
                      left: 0, 
                      right: 0, 
                      padding: '24px 12px 12px', 
                      background: 'linear-gradient(to top, rgba(0,0,0,0.8) 0%, rgba(0,0,0,0.4) 60%, transparent 100%)',
                      color: 'white'
                    }}>
                      <div style={{ fontSize: '16px', fontWeight: '900', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', marginBottom: '2px' }}>
                        {ex.title}
                      </div>
                      <div style={{ fontSize: '11px', opacity: 0.8, fontWeight: '600' }}>
                        {ex.startDate?.replace(/-/g, '.')} - {ex.endDate?.replace(/-/g, '.')}
                      </div>
                    </div>
                  </div>
                </GlassCard>
                {ex.ticketSalesStatus === 'purchased' && (
                  <div style={{ 
                    position: 'absolute', 
                    top: '10px', 
                    right: '10px', 
                    background: '#10B981', 
                    color: 'white',
                    padding: '4px 12px', 
                    borderRadius: '8px', 
                    fontSize: '11px', 
                    fontWeight: 900, 
                    boxShadow: '0 4px 12px rgba(16, 185, 129, 0.3)'
                  }}>
                    購入済
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      {/* ACTION MENU DRAWER */}
      <Drawer
        title={<span style={{ fontWeight: 900, fontSize: '16px' }}>メニュー</span>}
        placement="bottom"
        onClose={onMenuClose}
        open={isMenuOpenExternally}
        height="auto"
        styles={{ 
          body: { padding: '16px 24px 32px 24px' },
          header: { borderBottom: 'none', padding: '20px 24px 0 24px' }
        }}
        contentWrapperStyle={{ 
          borderRadius: '32px 32px 0 0',
          overflow: 'hidden'
        }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          <Button 
            block 
            size="large" 
            type="primary" 
            icon={<Icons.Plus style={{ width: 18 }} />}
            onClick={() => { onAddNew(); onMenuClose?.(); }}
            style={{ 
              height: '54px', 
              borderRadius: '16px', 
              fontSize: '15px', 
              fontWeight: 800,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px',
              background: theme.colors.primary,
              border: 'none',
              boxShadow: '0 8px 16px rgba(83, 190, 232, 0.25)'
            }}
          >
            新規展覧を追加
          </Button>

          <Divider style={{ margin: '12px 0', opacity: 0.05 }} />

          <Button 
            block 
            size="large" 
            icon={<Icons.Upload style={{ width: 18 }} />}
            onClick={() => { onExport(); onMenuClose?.(); }}
            style={menuButtonStyle}
          >
            データをエクスポート
          </Button>

          <Button 
            block 
            size="large" 
            icon={<Icons.Download style={{ width: 18 }} />}
            onClick={handleImportClick}
            style={menuButtonStyle}
          >
            データをインポート
          </Button>
        </div>
      </Drawer>

      <ConfirmDialog 
        isOpen={isImportConfirmOpen} 
        title="データをインポート" 
        message="選択されたファイルで現在のすべてのデータが上書きされます。よろしいですか？" 
        confirmLabel="読み込む" 
        isDestructive 
        onClose={() => { setIsImportConfirmOpen(false); setStagedImportData(null); }} 
        onConfirm={executeImport} 
      />
    </PageShell>
  );
};

const menuButtonStyle: React.CSSProperties = {
  height: '54px',
  borderRadius: '16px',
  fontSize: '15px',
  fontWeight: 700,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '8px',
  background: 'rgba(0,0,0,0.03)',
  border: 'none',
  color: theme.colors.textMain
};

import React, { useState, useEffect, useMemo } from 'react';
import { theme } from '../ui/theme';
import { Icons, IconButton } from '../ui/IconButton';
import { PageShell } from '../ui/PageShell';
import { Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { ExhibitionInfoSection } from './exhibition-detail/ExhibitionInfoSection';
import { ExhibitionDescriptionSection } from './exhibition-detail/ExhibitionDescriptionSection';
import { ExhibitionArtistsSection } from './exhibition-detail/ExhibitionArtistsSection';
import { ExhibitionGallerySection } from './exhibition-detail/ExhibitionGallerySection';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Tag } from 'antd';
import dayjs from 'dayjs';

interface ExhibitionDetailPageProps {
  exhibition: Exhibition;
  allExhibitions: Exhibition[];
  onUpdateExhibition: (ex: Exhibition) => void;
  onDeleteExhibition: (id: string) => void;
  onBack: () => void;
  initialEditMode?: boolean; // Prop to force edit mode on load
}

export const ExhibitionDetailPage: React.FC<ExhibitionDetailPageProps> = ({
  exhibition,
  allExhibitions,
  onUpdateExhibition,
  onDeleteExhibition,
  onBack,
  initialEditMode = false
}) => {
  const [isEditMode, setIsEditMode] = useState(initialEditMode);
  const [formData, setFormData] = useState<Exhibition>(exhibition);
  const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

  useEffect(() => {
    setFormData(exhibition);
  }, [exhibition]);

  // Automatic Status Calculation
  const computedStatus = useMemo(() => {
    if (formData.visitedAt) return 'visited' as ExhibitionOverallStatus;

    const now = dayjs().startOf('day');
    const start = dayjs(formData.startDate).startOf('day');
    const end = dayjs(formData.endDate).endOf('day');

    if (now.isBefore(start)) return 'preparing' as ExhibitionOverallStatus;
    if (now.isAfter(end)) return 'ended_not_visited' as ExhibitionOverallStatus;
    return 'running' as ExhibitionOverallStatus;
  }, [formData.startDate, formData.endDate, formData.visitedAt]);

  const handleSave = () => {
    const updated = { ...formData, exhibitionStatus: computedStatus };
    onUpdateExhibition(updated);
    setIsEditMode(false);
  };

  const handleCancel = () => {
    setFormData(exhibition);
    setIsEditMode(false);
  };

  const exhibitionStatusLabelMap: Record<ExhibitionOverallStatus, string> = {
    'preparing': '準備中',
    'running': '開催中',
    'visited': '参加済',
    'ended_not_visited': '終了（未参加）'
  };

  const statusColors: Record<ExhibitionOverallStatus, string> = {
    'preparing': '#9CA3AF',
    'running': theme.colors.primary,
    'visited': '#10B981',
    'ended_not_visited': '#6B7280'
  };

  return (
    <PageShell disablePadding>
      <div style={{ position: 'relative', minHeight: '100vh', background: '#F5F5F7' }}>

        {/* Hero Background */}
        <div style={{ 
          position: 'absolute', 
          top: 0, 
          left: 0, 
          right: 0, 
          height: 'min(28vh, 220px)', 
          zIndex: 0,
          overflow: 'hidden'
        }}>
          {formData.imageUrl ? (
            <img 
              src={formData.imageUrl} 
              style={{ width: '100%', height: '100%', objectFit: 'cover', filter: 'brightness(0.9)' }} 
              alt=""
            />
          ) : (
            <div style={{ width: '100%', height: '100%', background: 'linear-gradient(180deg, #E5E7EB 0%, #F5F5F7 100%)' }} />
          )}
          {/* Gradient Overlay */}
          <div style={{ 
            position: 'absolute', 
            inset: 0, 
            background: 'linear-gradient(180deg, rgba(245, 245, 247, 0) 0%, #F5F5F7 100%)' 
          }} />
        </div>

        <div style={{ position: 'relative', zIndex: 1, padding: 'calc(env(safe-area-inset-top) + 12px) 16px 140px 16px' }}>

          {/* Top Actions Bar */}
          <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
            <button 
              onClick={onBack}
              style={{ border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', color: theme.colors.textSecondary, cursor: 'pointer', padding: '8px', borderRadius: '50%', display: 'flex', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
            >
              <Icons.ChevronLeft />
            </button>

            <div style={{ display: 'flex', gap: '8px' }}>
              {formData.websiteUrl && !isEditMode && (
                <button 
                  onClick={() => window.open(formData.websiteUrl, '_blank')}
                  style={{ 
                    border: 'none', 
                    background: 'rgba(255,255,255,0.8)', 
                    backdropFilter: 'blur(10px)', 
                    color: theme.colors.primary, 
                    cursor: 'pointer', 
                    width: '40px',
                    height: '40px',
                    borderRadius: '50%', 
                    display: 'flex', 
                    alignItems: 'center',
                    justifyContent: 'center',
                    boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
                    padding: 0
                  }}
                >
                  <Icons.Globe style={{ width: 18, height: 18, display: 'block' }} />
                </button>
              )}
              {isEditMode ? (
                <IconButton 
                  icon={<Icons.Trash />} 
                  onClick={() => setIsDeleteConfirmOpen(true)} 
                  style={{ color: theme.colors.error, border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
                />
              ) : (
                <IconButton 
                  icon={<Icons.Edit />} 
                  onClick={() => setIsEditMode(true)} 
                  style={{ color: theme.colors.primary, border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
                />
              )}
            </div>
          </header>

          {/* Centered Title & Badge Section */}
          <div style={{ textAlign: 'center', margin: '24px 0 32px 0' }}>
            <h1 style={{ 
              fontSize: '24px', 
              fontWeight: '900', 
              margin: '0 0 12px 0', 
              letterSpacing: '-0.02em',
              color: theme.colors.text,
              lineHeight: '1.3'
            }}>
              {formData.title}
            </h1>
            <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', alignItems: 'center' }}>
              <span style={{ fontSize: '13px', fontWeight: '700', color: theme.colors.textSecondary, letterSpacing: '0.02em' }}>
                {formData.startDate?.replace(/-/g, '/')} ～ {formData.endDate?.replace(/-/g, '/')}
              </span>
              <Tag 
                color={statusColors[computedStatus]} 
                style={{ borderRadius: '6px', border: 'none', fontWeight: 800, fontSize: '10px', margin: 0, padding: '0 8px' }}
              >
                {exhibitionStatusLabelMap[computedStatus]}
              </Tag>
            </div>
          </div>

          {/* Content Sections */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <ExhibitionInfoSection 
              exhibition={{ ...formData, exhibitionStatus: computedStatus }} 
              allExhibitions={allExhibitions}
              isEditMode={isEditMode} 
              onChange={(updates) => setFormData(prev => ({ ...prev, ...updates }))} 
            />

            <ExhibitionDescriptionSection 
              exhibition={formData} 
              isEditMode={isEditMode} 
              onChange={(description) => setFormData(prev => ({ ...prev, description }))} 
            />

            <ExhibitionArtistsSection 
              exhibition={formData} 
              isEditMode={isEditMode} 
              onChange={(artists) => setFormData(prev => ({ ...prev, artists }))} 
            />

            <ExhibitionGallerySection 
              exhibition={formData} 
              onChange={(imageIds) => {
                const updated = { ...formData, imageIds };
                setFormData(updated);
                if (!isEditMode) onUpdateExhibition(updated);
              }} 
            />
          </div>

          {/* Footer Actions */}
          {isEditMode && (
            <div style={{
              position: 'fixed',
              bottom: 'calc(20px + env(safe-area-inset-bottom))',
              left: '16px',
              right: '16px',
              background: 'rgba(255, 255, 255, 0.9)',
              backdropFilter: 'blur(20px)',
              padding: '12px 20px',
              borderRadius: '24px',
              boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
              display: 'flex',
              gap: '12px',
              zIndex: 1000
            }}>
              <button 
                onClick={handleCancel}
                style={{ flex: 1, padding: '14px', borderRadius: '14px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: 'bold', cursor: 'pointer', color: theme.colors.textMain }}
              >
                キャンセル
              </button>
              <button 
                onClick={handleSave}
                style={{ flex: 1, padding: '14px', borderRadius: '14px', border: 'none', background: theme.colors.primary, color: 'white', fontWeight: 'bold', cursor: 'pointer' }}
              >
                保存
              </button>
            </div>
          )}

          <ConfirmDialog
            isOpen={isDeleteConfirmOpen}
            title="展覧会を削除"
            message="この展覧会情報を完全に削除しますか？この操作は取り消せません。"
            confirmLabel="削除"
            isDestructive
            onClose={() => setIsDeleteConfirmOpen(false)}
            onConfirm={() => onDeleteExhibition(exhibition.id)}
          />
        </div>
      </div>
    </PageShell>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
