            position: 'absolute', 
            inset: 0, 
            background: 'linear-gradient(180deg, rgba(245, 245, 247, 0) 0%, #F5F5F7 100%)' 
          }} />
        </div>

        <div style={{ position: 'relative', zIndex: 1, padding: 'calc(env(safe-area-inset-top) + 12px) 16px 140px 16px' }}>

          {/* Top Actions Bar */}
