                  onClick={() => setIsEditMode(true)} 
                  style={{ color: theme.colors.primary, border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
