import React, { useState, useEffect, useMemo } from 'react';
import { theme } from '../ui/theme';
import { Icons, IconButton } from '../ui/IconButton';
import { PageShell } from '../ui/PageShell';
import { Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { ExhibitionInfoSection } from './exhibition-detail/ExhibitionInfoSection';
import { ExhibitionDescriptionSection } from './exhibition-detail/ExhibitionDescriptionSection';
import { ExhibitionGallerySection } from './exhibition-detail/ExhibitionGallerySection';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Tag, Input } from 'antd';
import dayjs from 'dayjs';

interface ExhibitionDetailPageProps {
  exhibition: Exhibition;
  allExhibitions: Exhibition[];
  onUpdateExhibition: (ex: Exhibition) => void;
  onDeleteExhibition: (id: string) => void;
  onBack: () => void;
  initialEditMode?: boolean; // Prop to force edit mode on load
}

export const ExhibitionDetailPage: React.FC<ExhibitionDetailPageProps> = ({
  exhibition,
  allExhibitions,
  onUpdateExhibition,
  onDeleteExhibition,
  onBack,
  initialEditMode = false
}) => {
  const [isEditMode, setIsEditMode] = useState(initialEditMode);
  const [formData, setFormData] = useState<Exhibition>(exhibition);
  const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

  useEffect(() => {
    setFormData(exhibition);
  }, [exhibition]);

  // Automatic Status Calculation
  const computedStatus = useMemo(() => {
    if (formData.visitedAt) return 'visited' as ExhibitionOverallStatus;

    const now = dayjs().startOf('day');
    const start = dayjs(formData.startDate).startOf('day');
    const end = dayjs(formData.endDate).endOf('day');

    if (now.isBefore(start)) return 'preparing' as ExhibitionOverallStatus;
    if (now.isAfter(end)) return 'ended_not_visited' as ExhibitionOverallStatus;
    return 'running' as ExhibitionOverallStatus;
  }, [formData.startDate, formData.endDate, formData.visitedAt]);

  const handleSave = () => {
    const updated = { ...formData, exhibitionStatus: computedStatus };
    onUpdateExhibition(updated);
    setIsEditMode(false);
  };

  const handleCancel = () => {
    setFormData(exhibition);
    setIsEditMode(false);
  };

  const exhibitionStatusLabelMap: Record<ExhibitionOverallStatus, string> = {
    'preparing': '準備中',
    'running': '開催中',
    'visited': '参加済',
    'ended_not_visited': '終了（未参加）'
  };

  const statusColors: Record<ExhibitionOverallStatus, string> = {
    'preparing': '#9CA3AF',
    'running': theme.colors.primary,
    'visited': '#10B981',
    'ended_not_visited': '#6B7280'
  };

  return (
    <div style={{ position: 'relative', minHeight: '100vh', background: '#F5F5F7' }}>

      {/* 1. Fixed Background Layer - Full Screen */}
      <div style={{ 
        position: 'fixed', 
        inset: 0, 
        zIndex: 0,
        overflow: 'hidden'
      }}>
        {formData.imageUrl ? (
          <img 
            src={formData.imageUrl} 
            style={{ width: '100%', height: '100%', objectFit: 'cover', filter: 'brightness(0.9) blur(0px)' }} 
            alt=""
          />
        ) : (
          <div style={{ width: '100%', height: '100%', background: 'linear-gradient(180deg, #E5E7EB 0%, #F5F5F7 100%)' }} />
        )}
      </div>

      {/* 2. Fixed Gradient Overlay - Smooth transition to page background */}
      <div style={{ 
        position: 'fixed', 
        inset: 0, 
        zIndex: 1, 
        background: 'linear-gradient(180deg, rgba(245, 245, 247, 0) 0%, rgba(245, 245, 247, 0.4) 150px, #F5F5F7 350px, #F5F5F7 100%)',
        pointerEvents: 'none'
      }} />

      {/* 3. Scrollable Content Layer */}
      <div style={{ position: 'relative', zIndex: 2 }}>
        <PageShell disablePadding>
          <div style={{ padding: 'calc(env(safe-area-inset-top) + 12px) 16px 140px 16px' }}>

            {/* Top Actions Bar */}
            <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
              <button 
                onClick={onBack}
                style={{ border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', color: theme.colors.textSecondary, cursor: 'pointer', padding: '8px', borderRadius: '50%', display: 'flex', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
              >
                <Icons.ChevronLeft />
              </button>

              <div style={{ display: 'flex', gap: '8px' }}>
                {formData.websiteUrl && !isEditMode && (
                  <button 
                    onClick={() => window.open(formData.websiteUrl, '_blank')}
                    style={{ 
                      border: 'none', 
                      background: 'rgba(255,255,255,0.8)', 
                      backdropFilter: 'blur(10px)', 
                      color: theme.colors.primary, 
                      cursor: 'pointer', 
                      width: '40px',
                      height: '40px',
                      borderRadius: '50%', 
                      display: 'flex', 
                      alignItems: 'center',
                      justifyContent: 'center',
                      boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
                      padding: 0
                    }}
                  >
                    <Icons.Globe style={{ width: 18, height: 18, display: 'block' }} />
                  </button>
                )}
                {isEditMode ? (
                  <IconButton 
                    icon={<Icons.Trash />} 
                    onClick={() => setIsDeleteConfirmOpen(true)} 
                    style={{ color: theme.colors.error, border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
                  />
                ) : (
                  <IconButton 
                    icon={<Icons.Edit />} 
                    onClick={() => setIsEditMode(true)} 
                    style={{ color: theme.colors.primary, border: 'none', background: 'rgba(255,255,255,0.8)', backdropFilter: 'blur(10px)', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}
                  />
                )}
              </div>
            </header>

            {/* Centered Title & Badge Section */}
            <div style={{ textAlign: 'center', margin: '24px 0 32px 0' }}>
              {isEditMode ? (
                <Input
                  variant="borderless"
                  value={formData.title}
                  onChange={e => setFormData(prev => ({ ...prev, title: e.target.value }))}
                  autoFocus={formData.title === '新規展覧会'}
                  placeholder="展覧会名を入力"
                  style={{ 
                    fontSize: '24px', 
                    fontWeight: '900', 
                    margin: '0 0 12px 0', 
                    letterSpacing: '-0.02em',
                    color: theme.colors.text,
                    lineHeight: '1.3',
                    textAlign: 'center',
                    padding: 0,
                    background: 'transparent'
                  }}
                />
              ) : (
                <h1 style={{ 
                  fontSize: '24px', 
                  fontWeight: '900', 
                  margin: '0 0 12px 0', 
                  letterSpacing: '-0.02em',
                  color: theme.colors.text,
                  lineHeight: '1.3'
                }}>
                  {formData.title}
                </h1>
              )}

              <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', alignItems: 'center' }}>
                <span style={{ fontSize: '13px', fontWeight: '700', color: theme.colors.textSecondary, letterSpacing: '0.02em' }}>
                  {formData.startDate?.replace(/-/g, '/')} ～ {formData.endDate?.replace(/-/g, '/')}
                </span>
                <Tag 
                  color={statusColors[computedStatus]} 
                  style={{ borderRadius: '6px', border: 'none', fontWeight: 800, fontSize: '10px', margin: 0, padding: '0 8px' }}
                >
                  {exhibitionStatusLabelMap[computedStatus]}
                </Tag>
              </div>
            </div>

            {/* Content Sections */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              <ExhibitionInfoSection 
                exhibition={{ ...formData, exhibitionStatus: computedStatus }} 
                allExhibitions={allExhibitions}
                isEditMode={isEditMode} 
                onChange={(updates) => setFormData(prev => ({ ...prev, ...updates }))} 
              />

              <ExhibitionDescriptionSection 
                exhibition={formData} 
                isEditMode={isEditMode} 
                onUpdateDescription={(description) => setFormData(prev => ({ ...prev, description }))}
                onUpdateArtists={(artists) => setFormData(prev => ({ ...prev, artists }))}
              />

              <ExhibitionGallerySection 
                exhibition={formData} 
                onChange={(imageIds) => {
                  const updated = { ...formData, imageIds };
                  setFormData(updated);
                  if (!isEditMode) onUpdateExhibition(updated);
                }} 
              />
            </div>

            {/* Footer Actions */}
            {isEditMode && (
              <div style={{
                position: 'fixed',
                bottom: 'calc(20px + env(safe-area-inset-bottom))',
                left: '16px',
                right: '16px',
                background: 'rgba(255, 255, 255, 0.9)',
                backdropFilter: 'blur(20px)',
                padding: '12px 20px',
                borderRadius: '24px',
                boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
                display: 'flex',
                gap: '12px',
                zIndex: 1000
              }}>
                <button 
                  onClick={handleCancel}
                  style={{ flex: 1, padding: '14px', borderRadius: '14px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: 'bold', cursor: 'pointer', color: theme.colors.textMain }}
                >
                  キャンセル
                </button>
                <button 
                  onClick={handleSave}
                  style={{ flex: 1, padding: '14px', borderRadius: '14px', border: 'none', background: theme.colors.primary, color: 'white', fontWeight: 'bold', cursor: 'pointer' }}
                >
                  保存
                </button>
              </div>
            )}

            <ConfirmDialog
              isOpen={isDeleteConfirmOpen}
              title="展覧会を削除"
              message="この展覧会情報を完全に削除しますか？この操作は取り消せません。"
              confirmLabel="削除"
              isDestructive
              onClose={() => setIsDeleteConfirmOpen(false)}
              onConfirm={() => onDeleteExhibition(exhibition.id)}
            />
          </div>
        </PageShell>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType, Concert, Exhibition } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { MusicPage } from './pages/MusicPage';
import { ExhibitionsPage } from './pages/ExhibitionsPage';
import { ExhibitionDetailPage } from './pages/ExhibitionDetailPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts, getDueAction, autoAdvanceConcertStatus, prepareFullDataForExport } from './domain/logic';
import dayjs from 'dayjs';

type NavContext = { 
  path: PageId; 
  artistId?: string; 
  tourId?: string; 
  concertId?: string; 
  exhibitionId?: string; 
  from?: PageId;
  edit?: boolean; // Navigation flag to start in edit mode
};

const STORAGE_KEYS = {
  ARTISTS: 'livetrack_jp_artists',
  EXHIBITIONS: 'livetrack_jp_exhibitions',
  GLOBAL_SETTINGS: 'livetrack_jp_global_settings',
  DISPLAY_SETTINGS: 'livetrack_jp_display_settings',
  ARTIST_SORT: 'livetrack_jp_artist_sort',
  CONCERT_SORT: 'livetrack_jp_concert_sort'
};

const safeSave = (key: string, data: any) => {
  try {
    const serialized = JSON.stringify(data);
    localStorage.setItem(key, serialized);
  } catch (err: any) {
    console.error(`Persistence Error for key [${key}]:`, err);
    let userMsg = "データの保存に失敗しました。";
    if (err.name === 'QuotaExceededError' || err.code === 22) {
      userMsg += "\nストレージ容量が不足しています。";
    }
    window.alert(userMsg);
  }
};

const normalizeUrl = (raw: string): string => {
  const v = (raw || '').trim();
  if (!v) return '';
  if (v.startsWith('http://') || v.startsWith('https://')) return v;
  return `https://${v}`;
};

const fetchWithTimeout = async (url: string, timeoutMs: number) => {
  const controller = new AbortController();
  const t = window.setTimeout(() => controller.abort(), timeoutMs);
  try {
    await fetch(url, { method: 'GET', mode: 'no-cors', cache: 'no-store', signal: controller.signal });
    return true;
  } finally {
    window.clearTimeout(t);
  }
};

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'EXHIBITIONS' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [isTracking, setIsTracking] = useState(false);
  const trackingLockRef = useRef(false);

  const [isArtistMenuOpen, setIsArtistMenuOpen] = useState(false);
  const [isConcertMenuOpen, setIsConcertMenuOpen] = useState(false);
  const [isCalendarMenuOpen, setIsCalendarMenuOpen] = useState(false);
  const [isExhibitionMenuOpen, setIsExhibitionMenuOpen] = useState(false);

  const [musicActiveTab, setMusicActiveTab] = useState('artists');

  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.GLOBAL_SETTINGS);
      return saved ? JSON.parse(saved) : { autoTrackIntervalDays: 7 };
    } catch { return { autoTrackIntervalDays: 7 }; }
  });

  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.DISPLAY_SETTINGS);
      return saved ? JSON.parse(saved) : { showAttended: true, showSkipped: true };
    } catch { return { showAttended: true, showSkipped: true }; }
  });

  const [artistSortMode, setArtistSortMode] = useState<'manual' | 'status'>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ARTIST_SORT);
    return (saved as 'manual' | 'status') || 'status';
  });

  const [concertSortMode, setConcertSortMode] = useState<'status' | 'lottery'>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONCERT_SORT);
    return (saved as 'status' | 'lottery') || 'status';
  });

  const [artists, setArtists] = useState<Artist[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.ARTISTS);
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [exhibitions, setExhibitions] = useState<Exhibition[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.EXHIBITIONS);
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  useEffect(() => { safeSave(STORAGE_KEYS.ARTISTS, artists); }, [artists]);
  useEffect(() => { safeSave(STORAGE_KEYS.EXHIBITIONS, exhibitions); }, [exhibitions]);
  useEffect(() => { safeSave(STORAGE_KEYS.GLOBAL_SETTINGS, globalSettings); }, [globalSettings]);
  useEffect(() => { safeSave(STORAGE_KEYS.DISPLAY_SETTINGS, displaySettings); }, [displaySettings]);
  useEffect(() => { safeSave(STORAGE_KEYS.ARTIST_SORT, artistSortMode); }, [artistSortMode]);
  useEffect(() => { safeSave(STORAGE_KEYS.CONCERT_SORT, concertSortMode); }, [concertSortMode]);

  const hasGlobalConcertAlert = useMemo(() => {
    const now = new Date();
    return artists.some(a => a.tours.some(t => t.concerts.some(c => !!getDueAction(c, now))));
  }, [artists]);

  const runTrackingAll = useCallback(async (reason: 'manual' | 'auto' = 'manual') => {
    if (trackingLockRef.current) return;
    trackingLockRef.current = true;
    setIsTracking(true);
    const now = new Date();
    const nowIso = now.toISOString();

    try {
      const snapshot = artists;
      const targets: Array<{ artistId: string; linkIndex: number; url: string }> = [];

      snapshot.forEach((artist) => {
        (artist.links || []).forEach((link, idx) => {
          if (!link?.autoTrack) return;
          if (reason === 'auto' && !shouldTriggerAutoTrack(link.lastCheckedAt, globalSettings, now)) return;
          const url = normalizeUrl(link.url);
          if (url) targets.push({ artistId: artist.id, linkIndex: idx, url });
        });
      });

      if (targets.length === 0) return;

      const results = new Map<string, { ok: boolean; error?: TrackingErrorType }>();
      for (const t of targets) {
        const key = `${t.artistId}::${t.linkIndex}`;
        try {
          const ok = await fetchWithTimeout(t.url, 12000);
          results.set(key, { ok });
        } catch (e) {
          results.set(key, { ok: false, error: '接続できませんでした' });
        }
      }

      setArtists((prev) =>
        prev.map((artist) => {
          const nextLinks = (artist.links || []).map((link, idx) => {
            const key = `${artist.id}::${idx}`;
            if (!results.has(key)) return link;
            const r = results.get(key)!;
            const next: SiteLink = {
              ...link,
              lastCheckedAt: nowIso,
              trackingStatus: (r.ok ? 'success' : 'failed') as TrackingStatus,
              errorMessage: r.ok ? undefined : (r.error || '情報を取得できませんでした'),
            };
            if (r.ok) next.lastSuccessAt = nowIso;
            return next;
          });
          return { ...artist, links: nextLinks };
        })
      );
    } finally {
      setIsTracking(false);
      trackingLockRef.current = false;
    }
  }, [artists, globalSettings]);

  useEffect(() => {
    const timer = window.setInterval(() => runTrackingAll('auto'), 60 * 1000);
    return () => window.clearInterval(timer);
  }, [runTrackingAll]);

  const runAutoAdvance = useCallback(() => {
    const now = new Date();
    setArtists(prev => prev.map(a => ({
      ...a,
      tours: a.tours.map(t => ({
        ...t,
        concerts: t.concerts.map(c => autoAdvanceConcertStatus(c, now))
      }))
    })));
  }, []);

  const handleRefreshAll = useCallback(() => {
    runAutoAdvance();
    runTrackingAll('manual');
  }, [runAutoAdvance, runTrackingAll]);

  useEffect(() => { runAutoAdvance(); }, [nav.path, runAutoAdvance]);

  // Unified Export Logic
  const handleExportAll = async () => {
    try {
      const fullData = await prepareFullDataForExport(artists, exhibitions);
      const dataStr = JSON.stringify(fullData, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      const date = new Date().toISOString().split('T')[0];
      link.href = url;
      link.download = `LiveTrack_JP_Full_Backup_${date}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Unified Export failed:', error);
      window.alert('エクスポートに失敗しました。');
    }
  };

  // Unified Import Logic
  const handleImportAll = (importedData: any) => {
    // Handle both old single-array format and new unified object format
    if (Array.isArray(importedData)) {
      setArtists(importedData);
    } else if (importedData && typeof importedData === 'object') {
      if (importedData.artists) setArtists(importedData.artists);
      if (importedData.exhibitions) setExhibitions(importedData.exhibitions);
    }
  };

  const navigateToArtistList = () => setNav({ path: 'MUSIC' });
  const navigateToArtistDetail = (artistId: string, from?: PageId) => setNav({ path: 'ARTIST_DETAIL', artistId, from });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string, from?: PageId) => setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId, from });

  const navigateToExhibitionDetail = (exhibitionId: string, edit?: boolean) => setNav({ path: 'EXHIBITION_DETAIL', exhibitionId, edit });

  const addNewExhibition = () => {
    const newEx: Exhibition = {
      id: Math.random().toString(36).substr(2, 9),
      title: '新規展覧会',
      startDate: dayjs().format('YYYY-MM-DD'),
      endDate: dayjs().add(1, 'month').format('YYYY-MM-DD'),
      exhibitionStatus: 'preparing',
      ticketSalesStatus: 'none',
      holidaySameAsWeekday: true,
      holidayPriceSameAsWeekday: true,
      needsReservation: false,
      imageIds: []
    };
    setExhibitions(prev => [...prev, newEx]);
    navigateToExhibitionDetail(newEx.id, true);
  };

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id, nav.from);
  };

  const updateConcert = (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => {
    setArtists(prev => prev.map(a => {
      if (a.id !== artistId) return a;
      return {
        ...a,
        tours: a.tours.map(t => {
          if (t.id !== tourId) return t;
          return { ...t, concerts: t.concerts.map(c => c.id === concertId ? { ...c, ...updates } : c) };
        })
      };
    }));
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return { 
        ...artist, 
        tours: tourExists ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t) : [...artist.tours, updatedTour] 
      };
    }));
    navigateToArtistDetail(artistId, nav.from);
  };

  const handleAcknowledgeArtistTracking = useCallback((artistId: string) => {
    const nowIso = new Date().toISOString();
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        links: (artist.links || []).map(link => ({
          ...link,
          acknowledgedAt: link.lastHitAt ? nowIso : link.acknowledgedAt
        }))
      };
    }));
  }, []);

  const handleClearAllTrackingNotices = useCallback(() => {
    const nowIso = new Date().toISOString();
    setArtists(prev => prev.map(artist => ({
      ...artist,
      links: (artist.links || []).map(link => ({
        ...link,
        acknowledgedAt: link.lastHitAt ? nowIso : link.acknowledgedAt
      }))
    })));
  }, []);

  const handlePlusClick = useCallback(() => {
    if (nav.path === 'EXHIBITIONS') {
      setIsExhibitionMenuOpen(true);
    } else if (nav.path === 'MUSIC') {
      if (musicActiveTab === 'artists') {
        setIsArtistMenuOpen(true);
      } else {
        setIsConcertMenuOpen(true);
      }
    } else if (nav.path === 'CALENDAR') {
      setIsCalendarMenuOpen(true);
    }
  }, [nav.path, musicActiveTab]);

  const renderPage = () => {
    switch (nav.path) {
      case 'EXHIBITIONS':
        return (
          <ExhibitionsPage 
            exhibitions={exhibitions}
            onUpdateExhibitions={setExhibitions}
            onOpenDetail={navigateToExhibitionDetail}
            isMenuOpenExternally={isExhibitionMenuOpen}
            onMenuClose={() => setIsExhibitionMenuOpen(false)}
            onAddNew={addNewExhibition}
            onExport={handleExportAll}
            onImport={handleImportAll}
          />
        );
      case 'EXHIBITION_DETAIL': {
        const exhibition = exhibitions.find(e => e.id === nav.exhibitionId);
        if (!exhibition) return null;
        return (
          <ExhibitionDetailPage
            exhibition={exhibition}
            allExhibitions={exhibitions}
            onUpdateExhibition={(updated) => {
              setExhibitions(prev => prev.map(e => e.id === updated.id ? updated : e));
            }}
            onDeleteExhibition={(id) => {
              setExhibitions(prev => prev.filter(e => e.id !== id));
              setNav({ path: 'EXHIBITIONS' });
            }}
            onBack={() => setNav({ path: 'EXHIBITIONS' })}
            initialEditMode={nav.edit}
          />
        );
      }
      case 'MUSIC':
        return (
          <MusicPage 
            activeTab={musicActiveTab}
            onTabChange={setMusicActiveTab}
            artists={artists} 
            onOpenArtist={(id) => navigateToArtistDetail(id, 'MUSIC')} 
            onOpenArtistEditor={() => navigateToArtistEditor()} 
            onRefreshAll={handleRefreshAll} 
            onImportData={handleImportAll} // Updated to unified
            globalSettings={globalSettings} 
            onUpdateGlobalSettings={setGlobalSettings}
            artistSortMode={artistSortMode}
            onSetArtistSort={setArtistSortMode}
            onUpdateOrder={(newList) => setArtists(newList.map((a, i) => ({ ...a, order: i })))}
            onAcknowledgeArtistTracking={handleAcknowledgeArtistTracking}
            onClearAllTrackingNotices={handleClearAllTrackingNotices}
            onOpenConcert={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, 'MUSIC')} 
            onCreateConcert={() => setIsArtistPickerOpen(true)} 
            onUpdateConcert={updateConcert} 
            concertSortMode={concertSortMode}
            onSetSort={setConcertSortMode}
            isArtistMenuOpen={isArtistMenuOpen}
            onArtistMenuClose={() => setIsArtistMenuOpen(false)}
            isConcertMenuOpen={isConcertMenuOpen}
            onConcertMenuClose={() => setIsConcertMenuOpen(false)}
            onExport={handleExportAll} // Pass unified export
          />
        );
      case 'CALENDAR': 
        return (
          <CalendarPage 
            artists={artists} 
            exhibitions={exhibitions}
            onOpenArtist={(id) => navigateToArtistDetail(id, 'CALENDAR')} 
            onOpenConcert={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, 'CALENDAR')} 
            onOpenExhibition={(id) => navigateToExhibitionDetail(id)}
            onRefreshAll={handleRefreshAll}
            isMenuOpenExternally={isCalendarMenuOpen}
            onMenuClose={() => setIsCalendarMenuOpen(false)}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={nav.artistId!} 
            artist={artist} 
            settings={displaySettings} 
            onOpenArtistEditor={navigateToArtistEditor} 
            onOpenConcertEditor={navigateToConcertEditor} 
            onOpenConcertHome={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, nav.from)} 
            onChangeSettings={s => setDisplaySettings(p => ({...p, ...s}))} 
            onBack={() => {
              if (nav.from === 'CALENDAR') setNav({ path: 'CALENDAR' });
              else navigateToArtistList();
            }} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) return null;
        return (
          <ConcertHomePage 
            artistId={artist.id} 
            concertId={concert.id} 
            artist={artist} 
            tour={tour} 
            concert={concert} 
            onBack={() => navigateToArtistDetail(artist.id, nav.from)} 
            onOpenConcertEditor={navigateToConcertEditor} 
            onUpdateConcertAlbum={(aid, tid, cid, imgs) => updateConcert(aid, tid, cid, { imageIds: imgs })} 
          />
        );
      }
      case 'ARTIST_EDITOR': return (
        <ArtistEditorPage 
          artistId={nav.artistId} 
          artist={artists.find(a => a.id === nav.artistId)} 
          onSave={upsertArtist} 
          onCancel={() => nav.artistId ? navigateToArtistDetail(nav.artistId, nav.from) : navigateToArtistList()} 
          onDeleteArtist={id => { setArtists(p => p.filter(a => a.id !== id)); navigateToArtistList(); }} 
        />
      );
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ConcertEditorPage 
            artistId={artist.id} 
            tourId={nav.tourId} 
            tour={artist.tours.find(t => t.id === nav.tourId)} 
            allArtists={artists} 
            onSave={t => upsertTour(artist.id, t)} 
            onCancel={() => navigateToArtistDetail(artist.id, nav.from)} 
            onDeleteTour={(aid, tid) => { setArtists(p => p.map(a => a.id !== aid ? a : { ...a, tours: a.tours.filter(tour => tour.id !== tid) })); navigateToArtistDetail(aid, nav.from); }} 
          />
        );
      }
      default: return null;
    }
  };

  return (
    <div className="app-root">
      <Layout 
        currentPath={nav.path} 
        onNavigate={p => setNav({ path: p })} 
        onPlusClick={handlePlusClick}
        hasConcertAlert={hasGlobalConcertAlert}
      >
        {renderPage()}
      </Layout>
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3>アーティストを選択</h3>
            <div style={pickerListStyle}>
              {artists.map(a => (
                <button 
                  key={a.id} 
                  type="button"
                  onClick={() => { navigateToConcertEditor(a.id); setIsArtistPickerOpen(false); }} 
                  style={pickerButtonStyle}
                >
                  {a.name}
                </button>
              ))}
            </div>
            <button type="button" onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const typeColorMap: Record<CalendarEventType, string> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: theme.colors.status['参戦予定'],
  [TEXT.CALENDAR.EVENT_RESULT]: theme.colors.status['抽選中'],
  [TEXT.CALENDAR.EVENT_DEADLINE]: theme.colors.status['検討中'],
  [TEXT.CALENDAR.EVENT_SALE]: theme.colors.status['発売前'],
  ['展覧会']: theme.colors.primary,
};

const CONCERT_DOT_COLOR_UNDECIDED = '#377D99';
const CONCERT_DOT_COLOR_SKIPPED = '#6B7280';

const getConcertDotColor = (status: string): string => {
  if (status === '参戦予定' || status === '参戦済み') return theme.colors.status['参戦予定'];
  if (status === '抽選中' || status === '発売前' || status === '検討中') return CONCERT_DOT_COLOR_UNDECIDED;
  if (status === '見送' || status === '見送り') return CONCERT_DOT_COLOR_SKIPPED;
  return CONCERT_DOT_COLOR_UNDECIDED;
};

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  'running': 1,
  'preparing': 2,
  'visited': 3,
  'ended_not_visited': 4,
};

export const CalendarPage: React.FC<Props> = ({ artists, exhibitions, onOpenArtist, onOpenConcert, onOpenExhibition, onRefreshAll, isMenuOpenExternally, onMenuClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');

  const [yearOpen, setYearOpen] = useState(false);
  const [monthOpen, setMonthOpen] = useState(false);
  const yearBtnRef = useRef<HTMLButtonElement | null>(null);
  const monthBtnRef = useRef<HTMLButtonElement | null>(null);
  const yearPopoverRef = useRef<HTMLDivElement | null>(null);
  const monthPopoverRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!yearOpen && !monthOpen) return;
    const onPointerDown = (e: MouseEvent | TouchEvent) => {
      const target = e.target as Node | null;
      const insideYear =
        (yearBtnRef.current && target && yearBtnRef.current.contains(target)) ||
        (yearPopoverRef.current && target && yearPopoverRef.current.contains(target));
      const insideMonth =
        (monthBtnRef.current && target && monthBtnRef.current.contains(target)) ||
        (monthPopoverRef.current && target && monthPopoverRef.current.contains(target));
      if (!insideYear) setYearOpen(false);
      if (!insideMonth) setMonthOpen(false);
    };
    document.addEventListener('mousedown', onPointerDown);
    document.addEventListener('touchstart', onPointerDown, { passive: true });
    return () => {
      document.removeEventListener('mousedown', onPointerDown);
      document.removeEventListener('touchstart', onPointerDown as any);
    };
  }, [yearOpen, monthOpen]);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  useEffect(() => {
    setSelectedDateKey(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const allMusicEvents = useMemo(() => {
    return buildCalendarEvents(artists, { showAttended, showSkipped });
  }, [artists, showAttended, showSkipped]);

  const musicEventMap = useMemo(() => {
    const map = new Map<string, CalendarEvent[]>();
    allMusicEvents.forEach(ev => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [allMusicEvents]);

  // Compute exhibition period data
  const exhibitionEventsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions.filter(ex => {
      const start = dayjs(ex.startDate);
      const end = dayjs(ex.endDate);
      return (d.isAfter(start) || d.isSame(start, 'day')) && (d.isBefore(end) || d.isSame(end, 'day'));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });
  };

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;
    const days = [];
    for (let i = 0; i < startOffset; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const years = useMemo(() => {
    const currentYear = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => currentYear - 10 + i);
  }, []);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      const list = musicEventMap.get(selectedDateKey) || [];
      return [...list].sort((a, b) => {
        if (a.timeLabel && !b.timeLabel) return -1;
        if (!a.timeLabel && b.timeLabel) return 1;
        if (a.timeLabel && b.timeLabel) {
          const timeCmp = a.timeLabel.localeCompare(b.timeLabel);
          if (timeCmp !== 0) return timeCmp;
        }
        return EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type];
      });
    } else {
      return exhibitionEventsForDay(selectedDateKey);
    }
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionBars = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayExhibitions = exhibitionEventsForDay(dateKey);
    const top2 = dayExhibitions.slice(0, 2);
    const hasMore = dayExhibitions.length > 2;

    return (
      <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '2px', padding: '0 2px' }}>
        {top2.map(ex => {
          const isStart = ex.startDate === dateKey;
          const isEnd = ex.endDate === dateKey;
          const color = theme.colors.status[ex.exhibitionStatus === 'running' ? '参戦予定' : '見送'] || theme.colors.primary;

          return (
            <div 
              key={ex.id}
              style={{
                height: '14px',
                background: ex.exhibitionStatus === 'running' ? theme.colors.primary : 'rgba(83, 190, 232, 0.2)',
                color: ex.exhibitionStatus === 'running' ? 'white' : theme.colors.primary,
                fontSize: '9px',
                fontWeight: '800',
                display: 'flex',
                alignItems: 'center',
                padding: '0 4px',
                borderRadius: `${isStart ? '6px' : '0'} ${isEnd ? '6px' : '0'} ${isEnd ? '6px' : '0'} ${isStart ? '6px' : '0'}`,
                whiteSpace: 'nowrap',
                overflow: 'hidden',
                textOverflow: 'clip',
                margin: `0 ${isStart ? '2px' : '0'} 0 ${isEnd ? '2px' : '0'}`,
              }}
            >
              {isStart && <span style={{ marginRight: '2px' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak, textAlign: 'center', lineHeight: 1 }}>
            +{dayExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>

        {/* Top Toggle Capsule */}
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div style={{ 
            display: 'inline-flex', 
            background: 'white', 
            padding: '4px', 
            borderRadius: '9999px', 
            border: '1px solid rgba(0,0,0,0.06)',
            boxShadow: '0 4px 12px rgba(0,0,0,0.04)'
          }}>
            <button 
              onClick={() => setMode('concert')}
              style={{
                border: 'none', padding: '8px 20px', borderRadius: '9999px', fontSize: '14px', fontWeight: '800', cursor: 'pointer',
                background: mode === 'concert' ? theme.colors.primary : 'transparent',
                color: mode === 'concert' ? 'white' : theme.colors.textSecondary,
                transition: 'all 0.2s'
              }}
            >
              公演
            </button>
            <button 
              onClick={() => setMode('exhibition')}
              style={{
                border: 'none', padding: '8px 20px', borderRadius: '9999px', fontSize: '14px', fontWeight: '800', cursor: 'pointer',
                background: mode === 'exhibition' ? theme.colors.primary : 'transparent',
                color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary,
                transition: 'all 0.2s'
              }}
            >
              展覧
            </button>
          </div>
        </div>

        {/* Calendar Controls */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ position: 'relative' }}>
              <button ref={yearBtnRef} type="button" onClick={() => { setYearOpen(v => !v); setMonthOpen(false); }} style={pickerBtnStyle}>
                <span style={{ fontWeight: 900 }}>{currentDate.getFullYear()}年</span>
                <span style={chevStyle}>▾</span>
              </button>
              {yearOpen && (
                <div ref={yearPopoverRef} style={popoverStyle}>
                  <div style={popoverHeaderStyle}>年を選択</div>
                  <div style={popoverScrollStyle}>
                    {years.map(y => (
                      <button key={y} type="button" onClick={() => { setCurrentDate(new Date(y, currentDate.getMonth(), 1)); setYearOpen(false); }} 
                        style={{ ...popoverItemStyle, ...(y === currentDate.getFullYear() ? popoverItemActiveStyle : null) }}>{y}年</button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div style={{ position: 'relative' }}>
              <button ref={monthBtnRef} type="button" onClick={() => { setMonthOpen(v => !v); setYearOpen(false); }} style={pickerBtnStyle}>
                <span style={{ fontWeight: 900 }}>{currentDate.getMonth() + 1}月</span>
                <span style={chevStyle}>▾</span>
              </button>
              {monthOpen && (
                <div ref={monthPopoverRef} style={{ ...popoverStyle, width: 248 }}>
                  <div style={popoverHeaderStyle}>月を選択</div>
                  <div style={monthGridStyle}>
                    {Array.from({ length: 12 }, (_, i) => (
                      <button key={i} type="button" onClick={() => { setCurrentDate(new Date(currentDate.getFullYear(), i, 1)); setMonthOpen(false); }} 
                        style={{ ...monthCellStyle, ...(i === currentDate.getMonth() ? monthCellActiveStyle : null) }}>{i + 1}月</button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={navBtnStyle}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={navBtnStyle}>▶</button>
          </div>
        </div>

        {/* Grid Area */}
        <div style={{ 
          background: 'white', 
          borderRadius: '28px', 
          padding: '16px 12px', 
          border: '1px solid rgba(0,0,0,0.04)', 
          boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
          overflow: 'hidden'
        }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
            {(weekStart === 'sun' 
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] 
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map(l => (
              <div key={l} style={weekLabelStyle}>{l}</div>
            ))}

            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={`empty-${idx}`} />;
              const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              const isSelected = selectedDateKey === dateKey;
              const isToday = dateKey === todayKey;

              const musicEvents = musicEventMap.get(dateKey) || [];

              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{
                    ...dayCellStyle,
                    background: isSelected ? 'rgba(83, 190, 232, 0.18)' : isToday ? 'rgba(83, 190, 232, 0.05)' : 'transparent',
                    border: isSelected ? `2px solid ${theme.colors.primary}` : isToday ? '2px solid rgba(83, 190, 232, 0.3)' : 'none',
                    minHeight: mode === 'exhibition' ? '70px' : '52px',
                    padding: mode === 'exhibition' ? '4px 0 8px 0' : '4px 0'
                  }}
                >
                  <span style={{ fontSize: '14px', fontWeight: isSelected || isToday ? '900' : '600', marginBottom: mode === 'concert' ? '4px' : '6px' }}>{day}</span>

                  {mode === 'concert' ? (
                    <div style={{ height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                      {musicEvents.length > 0 && (
                        <div style={{ 
                          width: '6px', height: '6px', borderRadius: '50%', 
                          background: getConcertDotColor([...musicEvents].sort((a,b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type])[0].status) 
                        }} />
                      )}
                      {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: '#CBD5E1' }} />}
                    </div>
                  ) : (
                    renderExhibitionBars(day)
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Selected Date List */}
        {selectedDateKey && selectedDayEvents.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
              <div style={{ width: '4px', height: '16px', background: theme.colors.primary, borderRadius: '2px' }} />
              <h3 style={{ fontSize: '14px', fontWeight: '800', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', margin: 0 }}>
                {selectedDateKey.replace(/-/g, '.')} の{mode === 'concert' ? '予定' : '展覧会'}
              </h3>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={`${ev.concertId}-${ev.type}-${idx}`} onClick={() => ev.status === '参戦予定' || ev.status === '参戦済み' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '44px', height: '44px', borderRadius: '12px', background: 'rgba(0,0,0,0.03)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                        <div style={{ fontSize: '10px', fontWeight: '800', color: typeColorMap[ev.type] }}>{ev.type === TEXT.CALENDAR.EVENT_CONCERT ? 'LIVE' : ev.type.substring(0,2)}</div>
                        {ev.timeLabel && <div style={{ fontSize: '10px', fontWeight: '600', color: theme.colors.textSecondary }}>{ev.timeLabel}</div>}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ev.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary, display: 'flex', alignItems: 'center', gap: '6px' }}>
                          <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: typeColorMap[ev.type] }} />{ev.type}
                        </div>
                      </div>
                    </div>
                    <div style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak, padding: '4px 8px', borderRadius: '8px', background: '#F8FAFC' }}>{TEXT.STATUS[ev.status]}</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map(ex => (
                  <div key={ex.id} onClick={() => onOpenExhibition(ex.id)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '44px', height: '44px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0, background: '#F3F4F6' }}>
                        {ex.imageUrl ? <img src={ex.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <Icons.Exhibitions style={{ padding: '10px', opacity: 0.3 }} />}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ex.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ex.area} / {ex.venueName || ex.venue || '会場未定'}</div>
                      </div>
                    </div>
                    <Tag color={ex.exhibitionStatus === 'running' ? theme.colors.primary : '#9CA3AF'} style={{ border: 'none', borderRadius: '6px', fontWeight: 800 }}>
                      {ex.exhibitionStatus === 'running' ? '開催中' : ex.exhibitionStatus === 'preparing' ? '準備中' : '終了'}
                    </Tag>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <CalendarMenu 
        isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart}
        showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

// Styles (mostly same but added few)
const navBtnStyle: React.CSSProperties = { width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', color: '#111827', cursor: 'pointer', fontWeight: 900, fontSize: '18px' };
const weekLabelStyle: React.CSSProperties = { textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, paddingBottom: '8px' };
const dayCellStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-start', borderRadius: '12px', cursor: 'pointer', position: 'relative', transition: 'all 0.1s ease' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '24px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };
const pickerBtnStyle: React.CSSProperties = { display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '8px 12px', borderRadius: '9999px', border: '1px solid rgba(0,0,0,0.06)', background: 'white', fontSize: '16px', fontWeight: 900, color: '#111827', cursor: 'pointer', outline: 'none' };
const chevStyle: React.CSSProperties = { fontSize: '18px', color: 'rgba(17,24,39,0.55)', transform: 'translateY(1px)' };
const popoverStyle: React.CSSProperties = { position: 'absolute', top: 'calc(100% + 10px)', left: 0, width: 220, borderRadius: '18px', border: '1px solid rgba(0,0,0,0.06)', background: 'rgba(255,255,255,0.92)', boxShadow: '0 18px 46px rgba(0,0,0,0.10)', overflow: 'hidden', zIndex: 80, backdropFilter: 'blur(16px)' };
const popoverHeaderStyle: React.CSSProperties = { padding: '10px 12px', fontSize: '12px', fontWeight: 800, color: 'rgba(17,24,39,0.55)', borderBottom: '1px solid rgba(0,0,0,0.06)' };
const popoverScrollStyle: React.CSSProperties = { maxHeight: '240px', overflowY: 'auto', padding: '6px' };
const popoverItemStyle: React.CSSProperties = { width: '100%', textAlign: 'left', padding: '10px', borderRadius: '14px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: '16px', fontWeight: 800, color: '#111827' };
const popoverItemActiveStyle: React.CSSProperties = { background: 'rgba(83, 190, 232, 0.12)', boxShadow: 'inset 0 0 0 2px rgba(83, 190, 232, 0.35)' };
const monthGridStyle: React.CSSProperties = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '8px', padding: '10px' };
const monthCellStyle: React.CSSProperties = { padding: '10px 0', borderRadius: '14px', border: '1px solid rgba(0,0,0,0.06)', background: 'white', cursor: 'pointer', fontSize: '14px', fontWeight: 900, color: '#111827' };
const monthCellActiveStyle: React.CSSProperties = { background: 'rgba(83, 190, 232, 0.12)', border: '1px solid rgba(83, 190, 232, 0.35)' };

const Tag = ({ children, color, style }: any) => (
  <div style={{ background: color, color: 'white', padding: '4px 10px', borderRadius: '8px', fontSize: '10px', fontWeight: '900', ...style }}>{children}</div>
);

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const typeColorMap: Record<CalendarEventType, string> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: theme.colors.status['参戦予定'],
  [TEXT.CALENDAR.EVENT_RESULT]: theme.colors.status['抽選中'],
  [TEXT.CALENDAR.EVENT_DEADLINE]: theme.colors.status['検討中'],
  [TEXT.CALENDAR.EVENT_SALE]: theme.colors.status['発売前'],
  ['展覧会']: theme.colors.primary,
};

const CONCERT_DOT_COLOR_UNDECIDED = '#377D99';
const CONCERT_DOT_COLOR_SKIPPED = '#6B7280';

const getConcertDotColor = (status: string): string => {
  if (status === '参戦予定' || status === '参戦済み') return theme.colors.status['参戦予定'];
  if (status === '抽選中' || status === '発売前' || status === '検討中') return CONCERT_DOT_COLOR_UNDECIDED;
  if (status === '見送' || status === '見送り') return CONCERT_DOT_COLOR_SKIPPED;
  return CONCERT_DOT_COLOR_UNDECIDED;
};

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  'running': 1,
  'preparing': 2,
  'visited': 3,
  'ended_not_visited': 4,
};

export const CalendarPage: React.FC<Props> = ({ artists, exhibitions, onOpenArtist, onOpenConcert, onOpenExhibition, onRefreshAll, isMenuOpenExternally, onMenuClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');

  const [yearOpen, setYearOpen] = useState(false);
  const [monthOpen, setMonthOpen] = useState(false);
  const dateTitleRef = useRef<HTMLDivElement | null>(null);
  const yearPopoverRef = useRef<HTMLDivElement | null>(null);
  const monthPopoverRef = useRef<HTMLDivElement | null>(null);

  // Swipe logic
  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.targetTouches[0].clientX;
  };
  const handleTouchMove = (e: React.TouchEvent) => {
    touchEndX.current = e.targetTouches[0].clientX;
  };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    const isLeftSwipe = distance > 50;
    const isRightSwipe = distance < -50;

    if (isLeftSwipe) {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    } else if (isRightSwipe) {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    }

    touchStartX.current = null;
    touchEndX.current = null;
  };

  useEffect(() => {
    if (!yearOpen && !monthOpen) return;
    const onPointerDown = (e: MouseEvent | TouchEvent) => {
      const target = e.target as Node | null;
      const insideTitle = dateTitleRef.current && target && dateTitleRef.current.contains(target);
      const insideYear = yearPopoverRef.current && target && yearPopoverRef.current.contains(target);
      const insideMonth = monthPopoverRef.current && target && monthPopoverRef.current.contains(target);

      if (!insideTitle && !insideYear && !insideMonth) {
        setYearOpen(false);
        setMonthOpen(false);
      }
    };
    document.addEventListener('mousedown', onPointerDown);
    document.addEventListener('touchstart', onPointerDown, { passive: true });
    return () => {
      document.removeEventListener('mousedown', onPointerDown);
      document.removeEventListener('touchstart', onPointerDown as any);
    };
  }, [yearOpen, monthOpen]);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  useEffect(() => {
    setSelectedDateKey(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const allMusicEvents = useMemo(() => {
    return buildCalendarEvents(artists, { showAttended, showSkipped });
  }, [artists, showAttended, showSkipped]);

  const musicEventMap = useMemo(() => {
    const map = new Map<string, CalendarEvent[]>();
    allMusicEvents.forEach(ev => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [allMusicEvents]);

  // Compute exhibition period data for a specific day
  const exhibitionEventsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions.filter(ex => {
      const start = dayjs(ex.startDate);
      const end = dayjs(ex.endDate);
      return (d.isAfter(start) || d.isSame(start, 'day')) && (d.isBefore(end) || d.isSame(end, 'day'));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });
  };

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;
    const days = [];
    for (let i = 0; i < startOffset; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const years = useMemo(() => {
    const currentYear = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => currentYear - 10 + i);
  }, []);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      const list = musicEventMap.get(selectedDateKey) || [];
      return [...list].sort((a, b) => {
        if (a.timeLabel && !b.timeLabel) return -1;
        if (!a.timeLabel && b.timeLabel) return 1;
        if (a.timeLabel && b.timeLabel) {
          const timeCmp = a.timeLabel.localeCompare(b.timeLabel);
          if (timeCmp !== 0) return timeCmp;
        }
        return EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type];
      });
    } else {
      return exhibitionEventsForDay(selectedDateKey);
    }
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionBars = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayExhibitions = exhibitionEventsForDay(dateKey);
    const top2 = dayExhibitions.slice(0, 2);
    const hasMore = dayExhibitions.length > 2;

    const d = dayjs(dateKey);
    const isStartOfWeek = weekStart === 'sun' ? d.day() === 0 : d.day() === 1;

    return (
      <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '2px', padding: '0 2px' }}>
        {top2.map(ex => {
          const isStart = ex.startDate === dateKey;
          const isEnd = ex.endDate === dateKey;

          // Show text only if it's the start of the exhibition or start of a new week
          // But according to requirement "僅在该展览开始所在周显示" (only show in the week it starts)
          const startDay = dayjs(ex.startDate);
          const currentWeekStart = weekStart === 'sun' ? d.startOf('week') : d.subtract(d.day() === 0 ? 6 : d.day() - 1, 'day').startOf('day');
          const exhibitionWeekStart = weekStart === 'sun' ? startDay.startOf('week') : startDay.subtract(startDay.day() === 0 ? 6 : startDay.day() - 1, 'day').startOf('day');

          const isInStartWeek = currentWeekStart.isSame(exhibitionWeekStart, 'day');
          const shouldShowText = isStart || (isStartOfWeek && isInStartWeek);

          return (
            <div 
              key={ex.id}
              style={{
                height: '6px',
                background: theme.colors.primary,
                opacity: 0.65,
                borderRadius: '999px',
                fontSize: '8px',
                fontWeight: '900',
                display: 'flex',
                alignItems: 'center',
                padding: shouldShowText ? '0 4px' : '0',
                margin: `0 ${isStart ? '2px' : '0'} 0 ${isEnd ? '2px' : '0'}`,
                color: 'white',
                whiteSpace: 'nowrap',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && <span style={{ textShadow: '0 1px 2px rgba(0,0,0,0.2)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak, textAlign: 'center', lineHeight: 1, marginTop: '2px' }}>
            +{dayExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>

        {/* Top Single Row Header */}
        <div style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          marginBottom: '24px',
          height: '44px',
          gap: '8px'
        }}>
          {/* Left: Mode Toggle */}
          <div style={{ 
            display: 'inline-flex', 
            background: 'white', 
            padding: '3px', 
            borderRadius: '999px', 
            border: '1px solid rgba(0,0,0,0.06)',
            boxShadow: '0 2px 8px rgba(0,0,0,0.03)',
            flexShrink: 0
          }}>
            <button 
              onClick={() => setMode('concert')}
              style={{
                border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer',
                background: mode === 'concert' ? theme.colors.primary : 'transparent',
                color: mode === 'concert' ? 'white' : theme.colors.textSecondary,
                transition: 'all 0.2s'
              }}
            >
              公演
            </button>
            <button 
              onClick={() => setMode('exhibition')}
              style={{
                border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer',
                background: mode === 'exhibition' ? theme.colors.primary : 'transparent',
                color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary,
                transition: 'all 0.2s'
              }}
            >
              展覧
            </button>
          </div>

          {/* Middle: Clickable Date Title */}
          <div 
            ref={dateTitleRef}
            onClick={() => { setMonthOpen(!monthOpen); setYearOpen(false); }}
            style={{ 
              fontSize: '18px', 
              fontWeight: '900', 
              color: theme.colors.text, 
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              gap: '4px',
              padding: '4px 12px',
              borderRadius: '12px',
              transition: 'background 0.2s'
            }}
            onMouseEnter={e => e.currentTarget.style.background = 'rgba(0,0,0,0.03)'}
            onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
          >
            {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            <span style={{ fontSize: '12px', opacity: 0.4 }}>▼</span>

            {/* Popovers */}
            {monthOpen && (
              <div 
                ref={monthPopoverRef} 
                style={{ ...popoverStyle, left: '50%', transform: 'translateX(-50%)', top: '100%', width: 260 }}
                onClick={e => e.stopPropagation()}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 16px', borderBottom: '1px solid rgba(0,0,0,0.05)' }}>
                   <div style={{ fontSize: '12px', fontWeight: 800, color: theme.colors.textSecondary }}>年月を選択</div>
                   <button 
                    onClick={() => { setYearOpen(!yearOpen); setMonthOpen(false); }}
                    style={{ border: 'none', background: theme.colors.primary + '11', color: theme.colors.primary, padding: '2px 8px', borderRadius: '6px', fontSize: '11px', fontWeight: 900 }}
                   >
                     {currentDate.getFullYear()}年
                   </button>
                </div>
                <div style={monthGridStyle}>
                  {Array.from({ length: 12 }, (_, i) => (
                    <button key={i} type="button" onClick={() => { setCurrentDate(new Date(currentDate.getFullYear(), i, 1)); setMonthOpen(false); }} 
                      style={{ ...monthCellStyle, ...(i === currentDate.getMonth() ? monthCellActiveStyle : null) }}>{i + 1}月</button>
                  ))}
                </div>
              </div>
            )}

            {yearOpen && (
              <div 
                ref={yearPopoverRef} 
                style={{ ...popoverStyle, left: '50%', transform: 'translateX(-50%)', top: '100%', width: 220 }}
                onClick={e => e.stopPropagation()}
              >
                <div style={popoverHeaderStyle}>年を選択</div>
                <div style={popoverScrollStyle}>
                  {years.map(y => (
                    <button key={y} type="button" onClick={() => { setCurrentDate(new Date(y, currentDate.getMonth(), 1)); setYearOpen(false); setMonthOpen(true); }} 
                      style={{ ...popoverItemStyle, ...(y === currentDate.getFullYear() ? popoverItemActiveStyle : null) }}>{y}年</button>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Right: Refresh/Today button */}
          <div style={{ display: 'flex', gap: '8px' }}>
             <button 
                onClick={() => setCurrentDate(new Date())}
                style={{
                  border: '1px solid rgba(0,0,0,0.06)', 
                  background: 'white', 
                  color: theme.colors.primary, 
                  fontSize: '12px', 
                  fontWeight: 800, 
                  padding: '8px 12px', 
                  borderRadius: '999px',
                  cursor: 'pointer'
                }}
             >今日</button>
             <button onClick={onRefreshAll} style={{ ...navBtnStyle, background: 'white', border: '1px solid rgba(0,0,0,0.06)', width: '38px', height: '38px' }}>
                <Icons.Refresh style={{ width: 18 }} />
             </button>
          </div>
        </div>

        {/* Grid Area with Swipe Support */}
        <div 
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          style={{ 
            background: 'white', 
            borderRadius: '28px', 
            padding: '16px 10px', 
            border: '1px solid rgba(0,0,0,0.04)', 
            boxShadow: '0 4px 20px rgba(0,0,0,0.03)',
            overflow: 'hidden',
            userSelect: 'none'
          }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
            {(weekStart === 'sun' 
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] 
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map(l => (
              <div key={l} style={weekLabelStyle}>{l}</div>
            ))}

            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={`empty-${idx}`} />;
              const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              const isSelected = selectedDateKey === dateKey;
              const isToday = dateKey === todayKey;

              const musicEvents = musicEventMap.get(dateKey) || [];

              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{
                    ...dayCellStyle,
                    background: isSelected ? 'rgba(83, 190, 232, 0.12)' : 'transparent',
                    border: isSelected ? `1.5px solid ${theme.colors.primary}` : 'none',
                    minHeight: '62px',
                    padding: '6px 0'
                  }}
                >
                  <span style={{ 
                    fontSize: '14px', 
                    fontWeight: isSelected || isToday ? '900' : '600', 
                    marginBottom: '4px',
                    color: isToday ? theme.colors.primary : theme.colors.text,
                    opacity: isToday ? 1 : 0.9
                  }}>{day}</span>

                  {mode === 'concert' ? (
                    <div style={{ height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                      {musicEvents.length > 0 && (
                        <div style={{ 
                          width: '5px', height: '5px', borderRadius: '50%', 
                          background: getConcertDotColor([...musicEvents].sort((a,b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type])[0].status) 
                        }} />
                      )}
                      {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: '#CBD5E1' }} />}
                    </div>
                  ) : (
                    <div style={{ marginTop: 'auto', width: '100%' }}>
                      {renderExhibitionBars(day)}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Selected Date List */}
        {selectedDateKey && selectedDayEvents.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
              <div style={{ width: '4px', height: '16px', background: theme.colors.primary, borderRadius: '2px' }} />
              <h3 style={{ fontSize: '14px', fontWeight: '800', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', margin: 0 }}>
                {selectedDateKey.replace(/-/g, '.')} の{mode === 'concert' ? '予定' : '展覧会'}
              </h3>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={`${ev.concertId}-${ev.type}-${idx}`} onClick={() => ev.status === '参戦予定' || ev.status === '参戦済み' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '44px', height: '44px', borderRadius: '12px', background: 'rgba(0,0,0,0.03)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                        <div style={{ fontSize: '10px', fontWeight: '800', color: typeColorMap[ev.type] }}>{ev.type === TEXT.CALENDAR.EVENT_CONCERT ? 'LIVE' : ev.type.substring(0,2)}</div>
                        {ev.timeLabel && <div style={{ fontSize: '10px', fontWeight: '600', color: theme.colors.textSecondary }}>{ev.timeLabel}</div>}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ev.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary, display: 'flex', alignItems: 'center', gap: '6px' }}>
                          <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: typeColorMap[ev.type] }} />{ev.type}
                        </div>
                      </div>
                    </div>
                    <div style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak, padding: '4px 8px', borderRadius: '8px', background: '#F8FAFC' }}>{TEXT.STATUS[ev.status]}</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map(ex => (
                  <div key={ex.id} onClick={() => onOpenExhibition(ex.id)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '44px', height: '44px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0, background: '#F3F4F6' }}>
                        {ex.imageUrl ? <img src={ex.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <Icons.Exhibitions style={{ padding: '10px', opacity: 0.3 }} />}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ex.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ex.area} / {ex.venueName || ex.venue || '会場未定'}</div>
                      </div>
                    </div>
                    <Tag color={ex.exhibitionStatus === 'running' ? theme.colors.primary : '#9CA3AF'} style={{ border: 'none', borderRadius: '6px', fontWeight: 800 }}>
                      {ex.exhibitionStatus === 'running' ? '開催中' : ex.exhibitionStatus === 'preparing' ? '準備中' : '終了'}
                    </Tag>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <CalendarMenu 
        isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart}
        showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

const navBtnStyle: React.CSSProperties = { width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', color: '#111827', cursor: 'pointer', fontWeight: 900, fontSize: '18px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const weekLabelStyle: React.CSSProperties = { textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, paddingBottom: '8px' };
const dayCellStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-start', borderRadius: '12px', cursor: 'pointer', position: 'relative', transition: 'all 0.1s ease' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '24px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };
const popoverStyle: React.CSSProperties = { position: 'absolute', borderRadius: '20px', border: '1px solid rgba(0,0,0,0.06)', background: 'white', boxShadow: '0 20px 50px rgba(0,0,0,0.15)', overflow: 'hidden', zIndex: 150 };
const popoverHeaderStyle: React.CSSProperties = { padding: '12px 16px', fontSize: '12px', fontWeight: 800, color: theme.colors.textSecondary, borderBottom: '1px solid rgba(0,0,0,0.06)' };
const popoverScrollStyle: React.CSSProperties = { maxHeight: '240px', overflowY: 'auto', padding: '6px' };
const popoverItemStyle: React.CSSProperties = { width: '100%', textAlign: 'left', padding: '10px 14px', borderRadius: '12px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: '15px', fontWeight: 800, color: theme.colors.text };
const popoverItemActiveStyle: React.CSSProperties = { background: theme.colors.primary + '15', color: theme.colors.primary };
const monthGridStyle: React.CSSProperties = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '6px', padding: '10px' };
const monthCellStyle: React.CSSProperties = { padding: '12px 0', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.02)', cursor: 'pointer', fontSize: '14px', fontWeight: 900, color: theme.colors.text };
const monthCellActiveStyle: React.CSSProperties = { background: theme.colors.primary, color: 'white' };

const Tag = ({ children, color, style }: any) => (
  <div style={{ background: color, color: 'white', padding: '4px 10px', borderRadius: '8px', fontSize: '10px', fontWeight: '900', ...style }}>{children}</div>
);

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  'running': 1,
  'preparing': 2,
  'visited': 3,
  'ended_not_visited': 4,
};

// --- Wheel Picker Component ---
const WheelPicker = ({ 
  isOpen, 
  onClose, 
  onConfirm, 
  initialYear, 
  initialMonth 
}: { 
  isOpen: boolean; 
  onClose: () => void; 
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 11 }, (_, i) => cur - 5 + i);
  }, []);
  const months = Array.from({ length: 12 }, (_, i) => i + 1);

  const ITEM_HEIGHT = 44;

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Sync initial scroll
      const yIdx = years.indexOf(initialYear);
      const mIdx = months.indexOf(initialMonth);
      setTimeout(() => {
        yearListRef.current?.scrollTo({ top: yIdx * ITEM_HEIGHT });
        monthListRef.current?.scrollTo({ top: mIdx * ITEM_HEIGHT });
      }, 50);
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    const top = ref.current.scrollTop;
    const idx = Math.round(top / ITEM_HEIGHT);
    if (type === 'y') setSelectedY(years[idx] || years[0]);
    else setSelectedM(months[idx] || months[0]);
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(4px)' }} onClick={onClose} />
      <div style={{ 
        position: 'relative', width: '100%', maxWidth: '480px', background: 'white', 
        borderRadius: '32px 32px 0 0', padding: '24px 24px calc(24px + env(safe-area-inset-bottom))', 
        boxShadow: '0 -10px 40px rgba(0,0,0,0.1)' 
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '24px', alignItems: 'center' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '16px' }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer' }}>確定</button>
        </div>

        <div style={{ position: 'relative', height: ITEM_HEIGHT * 5, display: 'flex', overflow: 'hidden' }}>
          {/* Highlight Indicator */}
          <div style={{ 
            position: 'absolute', top: ITEM_HEIGHT * 2, left: '50%', transform: 'translateX(-50%)', width: '90%', height: ITEM_HEIGHT, 
            background: 'rgba(83, 190, 232, 0.08)', borderRadius: '12px', zIndex: 0, pointerEvents: 'none' 
          }} />

          <div 
            ref={yearListRef}
            onScroll={() => handleScroll(yearListRef, 'y')}
            style={{ flex: 1, overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1 }}
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map(y => (
              <div key={y} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: '18px', fontWeight: y === selectedY ? '900' : '500', color: y === selectedY ? theme.colors.text : theme.colors.textWeak }}>{y}年</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>

          <div 
            ref={monthListRef}
            onScroll={() => handleScroll(monthListRef, 'm')}
            style={{ flex: 1, overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1 }}
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map(m => (
              <div key={m} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: '18px', fontWeight: m === selectedM ? '900' : '500', color: m === selectedM ? theme.colors.text : theme.colors.textWeak }}>{m}月</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({ artists, exhibitions, onOpenArtist, onOpenConcert, onOpenExhibition, isMenuOpenExternally, onMenuClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  // Swipe logic
  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 50) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -50) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null;
    touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach(ev => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const exhibitionEventsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions.filter(ex => {
      const start = dayjs(ex.startDate);
      const end = dayjs(ex.endDate);
      return (d.isAfter(start) || d.isSame(start, 'day')) && (d.isBefore(end) || d.isSame(end, 'day'));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });
  };

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;
    const days = [];
    for (let i = 0; i < startOffset; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return exhibitionEventsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionBars = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayExhibitions = exhibitionEventsForDay(dateKey);
    const top2 = dayExhibitions.slice(0, 2);
    const hasMore = dayExhibitions.length > 2;

    const d = dayjs(dateKey);
    const isStartOfWeek = weekStart === 'sun' ? d.day() === 0 : d.day() === 1;

    return (
      <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '2px', padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const isStart = ex.startDate === dateKey;
          const isEnd = ex.endDate === dateKey;

          const startDay = dayjs(ex.startDate);
          const currentWeekStart = weekStart === 'sun' ? d.startOf('week') : d.subtract(d.day() === 0 ? 6 : d.day() - 1, 'day').startOf('day');
          const exhibitionWeekStart = weekStart === 'sun' ? startDay.startOf('week') : startDay.subtract(startDay.day() === 0 ? 6 : startDay.day() - 1, 'day').startOf('day');

          const isInStartWeek = currentWeekStart.isSame(exhibitionWeekStart, 'day');
          const shouldShowText = isStart || (isStartOfWeek && isInStartWeek);

          return (
            <div 
              key={ex.id}
              style={{
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                fontSize: '8px',
                fontWeight: '900',
                display: 'flex',
                alignItems: 'center',
                padding: shouldShowText ? '0 4px' : '0',
                margin: `0 ${isStart ? '2px' : '0'} 0 ${isEnd ? '2px' : '0'}`,
                color: 'white',
                whiteSpace: 'nowrap',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && <span style={{ textShadow: '0 1px 2px rgba(0,0,0,0.1)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak, textAlign: 'center', lineHeight: 1, marginTop: '1px' }}>
            +{dayExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>

        {/* Top Header - Fixed 3 Sections */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', height: '44px' }}>
          {/* Left: Capsule */}
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          {/* Middle: Clickable Title */}
          <div 
            onClick={() => setIsWheelPickerOpen(true)}
            style={{ fontSize: '18px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
          >
            {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            <span style={{ fontSize: '10px', opacity: 0.3 }}>▼</span>
          </div>

          {/* Right: Today Button */}
          <button 
            onClick={() => setCurrentDate(new Date())}
            style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 16px', borderRadius: '999px', cursor: 'pointer' }}
          >今日</button>
        </div>

        {/* Grid Area with Swipe */}
        <div 
          onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd}
          style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none' }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
            {(weekStart === 'sun' 
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] 
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, paddingBottom: '12px' }}>{l}</div>
            ))}

            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={`empty-${idx}`} />;
              const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              const isSelected = selectedDateKey === dateKey;
              const isToday = dateKey === todayKey;

              const musicEvents = musicEventMap.get(dateKey) || [];

              return (
                <div 
                  key={day} onClick={() => handleDayClick(day)} 
                  style={{
                    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-start', borderRadius: '12px', cursor: 'pointer', transition: 'all 0.1s ease',
                    background: isSelected ? 'rgba(83, 190, 232, 0.12)' : 'transparent', border: isSelected ? `1.5px solid ${theme.colors.primary}` : 'none',
                    minHeight: '68px', padding: '6px 0'
                  }}
                >
                  <span style={{ 
                    fontSize: '14px', fontWeight: isSelected || isToday ? '900' : '600', marginBottom: '4px',
                    color: isToday ? theme.colors.primary : theme.colors.text, opacity: isToday ? 1 : 0.9
                  }}>{day}</span>

                  {mode === 'concert' ? (
                    <div style={{ height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                      {musicEvents.length > 0 && (
                        <div style={{ width: '5px', height: '5px', borderRadius: '50%', background: theme.colors.status[musicEvents[0].status] || theme.colors.primary }} />
                      )}
                      {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: '#CBD5E1' }} />}
                    </div>
                  ) : (
                    <div style={{ marginTop: 'auto', width: '100%' }}>{renderExhibitionBars(day)}</div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Details List */}
        {selectedDateKey && selectedDayEvents.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
              <div style={{ width: '4px', height: '16px', background: theme.colors.primary, borderRadius: '2px' }} />
              <h3 style={{ fontSize: '14px', fontWeight: '800', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', margin: 0 }}>
                {selectedDateKey.replace(/-/g, '.')} の{mode === 'concert' ? '予定' : '展覧会'}
              </h3>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} onClick={() => ev.status === '参戦予定' || ev.status === '参戦済み' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '10px', background: 'rgba(0,0,0,0.03)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                        <div style={{ fontSize: '9px', fontWeight: '800', color: theme.colors.primary }}>LIVE</div>
                        {ev.timeLabel && <div style={{ fontSize: '9px', fontWeight: '600', color: theme.colors.textSecondary }}>{ev.timeLabel}</div>}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ev.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ev.type}</div>
                      </div>
                    </div>
                    <div style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak }}>{TEXT.STATUS[ev.status]}</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map(ex => (
                  <div key={ex.id} onClick={() => onOpenExhibition(ex.id)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '10px', overflow: 'hidden', flexShrink: 0, background: '#F3F4F6' }}>
                        {ex.imageUrl ? <img src={ex.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <Icons.Exhibitions style={{ padding: '8px', opacity: 0.3 }} />}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ex.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ex.area} / {ex.venueName || ex.venue || '会場未定'}</div>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPicker 
        isOpen={isWheelPickerOpen} 
        onClose={() => setIsWheelPickerOpen(false)} 
        onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }}
        initialYear={currentDate.getFullYear()}
        initialMonth={currentDate.getMonth() + 1}
      />

      <CalendarMenu 
        isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart}
        showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  'running': 1,
  'preparing': 2,
  'visited': 3,
  'ended_not_visited': 4,
};

// --- Wheel Picker Component ---
const WheelPicker = ({ 
  isOpen, 
  onClose, 
  onConfirm, 
  initialYear, 
  initialMonth 
}: { 
  isOpen: boolean; 
  onClose: () => void; 
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = Array.from({ length: 12 }, (_, i) => i + 1);

  const ITEM_HEIGHT = 44;

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'instant' });
    }
  };

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Use requestAnimationFrame to ensure the container is rendered before scrolling
      requestAnimationFrame(() => {
        syncScroll(yearListRef, initialYear, years);
        syncScroll(monthListRef, initialMonth, months);
        setSelectedY(initialYear);
        setSelectedM(initialMonth);
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    const top = ref.current.scrollTop;
    const idx = Math.round(top / ITEM_HEIGHT);
    if (type === 'y') {
      const val = years[idx];
      if (val && val !== selectedY) setSelectedY(val);
    } else {
      const val = months[idx];
      if (val && val !== selectedM) setSelectedM(val);
    }
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
      <div 
        style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.45)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)' }} 
        onClick={onClose} 
      />
      <div style={{ 
        position: 'relative', width: '100%', maxWidth: '480px', background: 'white', 
        borderRadius: '32px 32px 0 0', padding: '24px 24px calc(24px + env(safe-area-inset-bottom))', 
        boxShadow: '0 -10px 40px rgba(0,0,0,0.15)',
        pointerEvents: 'auto'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '24px', alignItems: 'center' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer', padding: '8px' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '17px' }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer', padding: '8px' }}>確定</button>
        </div>

        <div style={{ position: 'relative', height: ITEM_HEIGHT * 5, display: 'flex', overflow: 'hidden', background: '#f9f9fb', borderRadius: '20px' }}>
          {/* Central Highlight Overlay - MUST HAVE pointer-events: none */}
          <div style={{ 
            position: 'absolute', top: ITEM_HEIGHT * 2, left: 12, right: 12, height: ITEM_HEIGHT, 
            background: 'rgba(83, 190, 232, 0.08)', borderRadius: '12px', zIndex: 0, pointerEvents: 'none',
            borderTop: '1px solid rgba(83, 190, 232, 0.1)', borderBottom: '1px solid rgba(83, 190, 232, 0.1)'
          }} />

          {/* Top/Bottom Gradient Overlays to give wheel look - MUST HAVE pointer-events: none */}
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to bottom, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to top, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />

          <div 
            ref={yearListRef}
            onScroll={() => handleScroll(yearListRef, 'y')}
            style={{ 
              flex: 1, 
              overflowY: 'auto', 
              scrollSnapType: 'y mandatory', 
              textAlign: 'center', 
              zIndex: 1, 
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto'
            }}
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map((y, idx) => (
              <div 
                key={y} 
                onClick={() => handleItemClick(yearListRef, idx)}
                style={{ 
                  height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', 
                  fontSize: y === selectedY ? '20px' : '17px', 
                  fontWeight: y === selectedY ? '900' : '500', 
                  color: y === selectedY ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer'
                }}
              >
                {y}年
              </div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>

          <div 
            ref={monthListRef}
            onScroll={() => handleScroll(monthListRef, 'm')}
            style={{ 
              flex: 1, 
              overflowY: 'auto', 
              scrollSnapType: 'y mandatory', 
              textAlign: 'center', 
              zIndex: 1, 
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto'
            }}
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map((m, idx) => (
              <div 
                key={m} 
                onClick={() => handleItemClick(monthListRef, idx)}
                style={{ 
                  height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', 
                  fontSize: m === selectedM ? '20px' : '17px', 
                  fontWeight: m === selectedM ? '900' : '500', 
                  color: m === selectedM ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer'
                }}
              >
                {m}月
              </div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({ artists, exhibitions, onOpenArtist, onOpenConcert, onOpenExhibition, isMenuOpenExternally, onMenuClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  // Swipe logic
  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null;
    touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach(ev => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const exhibitionEventsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions.filter(ex => {
      const start = dayjs(ex.startDate);
      const end = dayjs(ex.endDate);
      return (d.isAfter(start) || d.isSame(start, 'day')) && (d.isBefore(end) || d.isSame(end, 'day'));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });
  };

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;
    const days = [];
    for (let i = 0; i < startOffset; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return exhibitionEventsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionBars = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayExhibitions = exhibitionEventsForDay(dateKey);
    const top2 = dayExhibitions.slice(0, 2);
    const hasMore = dayExhibitions.length > 2;

    const d = dayjs(dateKey);
    const isStartOfWeek = weekStart === 'sun' ? d.day() === 0 : d.day() === 1;

    return (
      <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '2px', padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const isStart = ex.startDate === dateKey;
          const isEnd = ex.endDate === dateKey;

          const startDay = dayjs(ex.startDate);
          const currentWeekStart = weekStart === 'sun' ? d.startOf('week') : d.subtract(d.day() === 0 ? 6 : d.day() - 1, 'day').startOf('day');
          const exhibitionWeekStart = weekStart === 'sun' ? startDay.startOf('week') : startDay.subtract(startDay.day() === 0 ? 6 : startDay.day() - 1, 'day').startOf('day');

          const isInStartWeek = currentWeekStart.isSame(exhibitionWeekStart, 'day');
          const shouldShowText = isStart || (isStartOfWeek && isInStartWeek);

          return (
            <div 
              key={ex.id}
              style={{
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                fontSize: '8px',
                fontWeight: '900',
                display: 'flex',
                alignItems: 'center',
                padding: shouldShowText ? '0 4px' : '0',
                margin: `0 ${isStart ? '2px' : '0'} 0 ${isEnd ? '2px' : '0'}`,
                color: 'white',
                whiteSpace: 'nowrap',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && <span style={{ textShadow: '0 1px 2px rgba(0,0,0,0.1)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak, textAlign: 'center', lineHeight: 1, marginTop: '1px' }}>
            +{dayExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>

        {/* Top Header - Fixed 3 Sections */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', height: '44px' }}>
          {/* Left: Capsule */}
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          {/* Middle: Clickable Title */}
          <div 
            onClick={() => setIsWheelPickerOpen(true)}
            style={{ fontSize: '18px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 12px', borderRadius: '12px' }}
          >
            {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            <span style={{ fontSize: '10px', opacity: 0.3 }}>▼</span>
          </div>

          {/* Right: Today Button */}
          <button 
            onClick={() => setCurrentDate(new Date())}
            style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 16px', borderRadius: '999px', cursor: 'pointer' }}
          >今日</button>
        </div>

        {/* Grid Area with Swipe */}
        <div 
          onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd}
          style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
            {(weekStart === 'sun' 
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] 
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, paddingBottom: '12px' }}>{l}</div>
            ))}

            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={`empty-${idx}`} />;
              const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              const isSelected = selectedDateKey === dateKey;
              const isToday = dateKey === todayKey;

              const musicEvents = musicEventMap.get(dateKey) || [];

              return (
                <div 
                  key={day} onClick={() => handleDayClick(day)} 
                  style={{
                    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'flex-start', borderRadius: '12px', cursor: 'pointer', transition: 'all 0.1s ease',
                    background: isSelected ? 'rgba(83, 190, 232, 0.12)' : 'transparent', border: isSelected ? `1.5px solid ${theme.colors.primary}` : 'none',
                    minHeight: '68px', padding: '6px 0'
                  }}
                >
                  <span style={{ 
                    fontSize: '14px', fontWeight: isSelected || isToday ? '900' : '600', marginBottom: '4px',
                    color: isToday ? theme.colors.primary : theme.colors.text, opacity: isToday ? 1 : 0.9
                  }}>{day}</span>

                  {mode === 'concert' ? (
                    <div style={{ height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                      {musicEvents.length > 0 && (
                        <div style={{ width: '5px', height: '5px', borderRadius: '50%', background: theme.colors.status[musicEvents[0].status] || theme.colors.primary }} />
                      )}
                      {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: '#CBD5E1' }} />}
                    </div>
                  ) : (
                    <div style={{ marginTop: 'auto', width: '100%' }}>{renderExhibitionBars(day)}</div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Details List */}
        {selectedDateKey && selectedDayEvents.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
              <div style={{ width: '4px', height: '16px', background: theme.colors.primary, borderRadius: '2px' }} />
              <h3 style={{ fontSize: '14px', fontWeight: '800', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', margin: 0 }}>
                {selectedDateKey.replace(/-/g, '.')} の{mode === 'concert' ? '予定' : '展覧会'}
              </h3>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} onClick={() => ev.status === '参戦予定' || ev.status === '参戦済み' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '10px', background: 'rgba(0,0,0,0.03)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                        <div style={{ fontSize: '9px', fontWeight: '800', color: theme.colors.primary }}>LIVE</div>
                        {ev.timeLabel && <div style={{ fontSize: '9px', fontWeight: '600', color: theme.colors.textSecondary }}>{ev.timeLabel}</div>}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ev.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ev.type}</div>
                      </div>
                    </div>
                    <div style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak }}>{TEXT.STATUS[ev.status]}</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map(ex => (
                  <div key={ex.id} onClick={() => onOpenExhibition(ex.id)} style={eventCardStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '10px', overflow: 'hidden', flexShrink: 0, background: '#F3F4F6' }}>
                        {ex.imageUrl ? <img src={ex.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <Icons.Exhibitions style={{ padding: '8px', opacity: 0.3 }} />}
                      </div>
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.text, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ex.title}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{ex.area} / {ex.venueName || ex.venue || '会場未定'}</div>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPicker 
        isOpen={isWheelPickerOpen} 
        onClose={() => setIsWheelPickerOpen(false)} 
        onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }}
        initialYear={currentDate.getFullYear()}
        initialMonth={currentDate.getMonth() + 1}
      />

      <CalendarMenu 
        isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart}
        showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Wheel Picker Component ---
const WheelPicker = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'auto' });
    }
  };

  useEffect(() => {
    if (isOpen) {
      const prevOverflow = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
      requestAnimationFrame(() => {
        syncScroll(yearListRef, initialYear, years);
        syncScroll(monthListRef, initialMonth, months);
        setSelectedY(initialYear);
        setSelectedM(initialMonth);
      });
      return () => {
        document.body.style.overflow = prevOverflow;
      };
    }
    return;
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);
    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;
      const max = type === 'y' ? years.length - 1 : months.length - 1;
      const top = el.scrollTop;
      const idx = Math.max(0, Math.min(Math.round(top / ITEM_HEIGHT), max));
      el.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
      if (type === 'y') {
        const val = years[idx];
        if (val && val !== selectedY) setSelectedY(val);
      } else {
        const val = months[idx];
        if (val && val !== selectedM) setSelectedM(val);
      }
    }, 90);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000, display: 'flex', alignItems: 'flex-end', justifyContent: 'center', pointerEvents: 'auto' }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.45)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)', zIndex: 0 }} onClick={onClose} />
      <div style={{ position: 'relative', width: '100%', maxWidth: '480px', background: 'white', zIndex: 1, borderRadius: '32px 32px 0 0', padding: '24px 24px calc(24px + env(safe-area-inset-bottom))', boxShadow: '0 -10px 40px rgba(0,0,0,0.15)', pointerEvents: 'auto' }} onClick={(e) => e.stopPropagation()} onPointerDown={(e) => e.stopPropagation()}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px', alignItems: 'center' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer', padding: '8px', whiteSpace: 'nowrap' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '17px' }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer', padding: '8px', whiteSpace: 'nowrap' }}>確定</button>
        </div>
        <div style={{ position: 'relative', height: ITEM_HEIGHT * 5, display: 'flex', overflow: 'hidden', background: '#f9f9fb', borderRadius: '20px' }}>
          <div style={{ position: 'absolute', top: ITEM_HEIGHT * 2, left: 12, right: 12, height: ITEM_HEIGHT, background: 'rgba(83, 190, 232, 0.08)', borderRadius: '12px', zIndex: 0, pointerEvents: 'none', borderTop: '1px solid rgba(83, 190, 232, 0.1)', borderBottom: '1px solid rgba(83, 190, 232, 0.1)' }} />
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to bottom, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to top, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div ref={yearListRef} onScroll={() => handleScroll(yearListRef, 'y')} style={{ flex: 1, height: '100%', minHeight: 0, overflowY: 'auto', overflowX: 'hidden', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} className="hide-scrollbar">
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map((y, idx) => (
              <div key={y} onClick={() => handleItemClick(yearListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: y === selectedY ? '20px' : '17px', fontWeight: y === selectedY ? '900' : '500', color: y === selectedY ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{y}年</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
          <div ref={monthListRef} onScroll={() => handleScroll(monthListRef, 'm')} style={{ flex: 1, height: '100%', minHeight: 0, overflowY: 'auto', overflowX: 'hidden', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} className="hide-scrollbar">
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map((m, idx) => (
              <div key={m} onClick={() => handleItemClick(monthListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: m === selectedM ? '20px' : '17px', fontWeight: m === selectedM ? '900' : '500', color: m === selectedM ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{m}月</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null; touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const getExhibitionsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (d.isAfter(start) || d.isSame(start)) && (d.isBefore(end) || d.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const days: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) days.push({ day: null, dateKey: null });
    for (let i = 1; i <= count; i++) {
      days.push({ day: i, dateKey: `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}` });
    }
    // Pad to full weeks
    while (days.length % 7 !== 0) days.push({ day: null, dateKey: null });

    const weeks = [];
    for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  // Logic to calculate bars per week row
  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find(d => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find(d => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    // Find all exhibitions that overlap this week
    const weekExhibitions = exhibitions.filter(ex => {
      const start = dayjs(ex.startDate).startOf('day');
      const end = dayjs(ex.endDate).endOf('day');
      return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && 
             (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          // Find start and end columns (0-6)
          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex(d => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex(d => d.dateKey !== null);

          const left = (startCol * (100 / 7)) + 0.5;
          const width = ((endCol - startCol + 1) * (100 / 7)) - 1;

          const isInStartWeek = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));
          const shouldShowText = isInStartWeek;

          return (
            <div 
              key={ex.id}
              style={{
                position: 'absolute',
                top: `${idx * 8}px`,
                left: `${left}%`,
                width: `${width}%`,
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                display: 'flex',
                alignItems: 'center',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && (
                <span style={{ 
                  fontSize: '8px', fontWeight: '900', color: 'white', 
                  paddingLeft: '4px', whiteSpace: 'nowrap', textShadow: '0 1px 2px rgba(0,0,0,0.1)'
                }}>
                  {ex.title}
                </span>
              )}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ 
            position: 'absolute', top: '18px', right: '4px', 
            fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak 
          }}>
            +{weekExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)', whiteSpace: 'nowrap' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>
          <div onClick={() => setIsWheelPickerOpen(true)} style={{ justifySelf: 'center', fontSize: '17px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'inline-flex', alignItems: 'center', gap: '6px', padding: '6px 10px', borderRadius: '12px', whiteSpace: 'nowrap', maxWidth: '100%', overflow: 'hidden', textOverflow: 'ellipsis' }}>
            <span style={{ whiteSpace: 'nowrap' }}>{currentDate.getFullYear()}年{currentDate.getMonth() + 1}月</span>
            <span style={{ fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>
          <button onClick={() => setCurrentDate(new Date())} style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 14px', borderRadius: '999px', cursor: 'pointer', whiteSpace: 'nowrap' }}>今日</button>
        </div>

        <div onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun' ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];

                  return (
                    <div
                      key={d.day}
                      onClick={() => d.day && handleDayClick(d.day)}
                      style={{
                        position: 'relative',
                        padding: '6px 4px 10px 4px',
                        borderRadius: '12px',
                        cursor: 'pointer',
                        background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent',
                        border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent',
                        zIndex: 0,
                      }}
                    >
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>
                        {d.day}
                      </div>

                      {mode === 'concert' && musicEvents.length > 0 && (
                        <div style={{ marginTop: '6px', display: 'flex', gap: '3px', flexWrap: 'wrap', justifyContent: 'center' }}>
                          {musicEvents.slice(0, 3).map((ev, evIdx) => (
                            <div key={evIdx} style={{ width: '6px', height: '6px', borderRadius: '999px', background: ev.type === '公演' ? theme.colors.primary : '#F7893F', opacity: 0.9 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>
                        {dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}
                        <br />{ex.venueName || ex.venue}
                      </div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPicker isOpen={isWheelPickerOpen} onClose={() => setIsWheelPickerOpen(false)} onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }} initialYear={currentDate.getFullYear()} initialMonth={currentDate.getMonth() + 1} />
      <CalendarMenu isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart} showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped} />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Wheel Picker Component ---
const WheelPicker = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'auto' });
    }
  };

  useEffect(() => {
    if (isOpen) {
      const prevOverflow = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
      requestAnimationFrame(() => {
        syncScroll(yearListRef, initialYear, years);
        syncScroll(monthListRef, initialMonth, months);
        setSelectedY(initialYear);
        setSelectedM(initialMonth);
      });
      return () => {
        document.body.style.overflow = prevOverflow;
      };
    }
    return;
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);
    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;
      const max = type === 'y' ? years.length - 1 : months.length - 1;
      const top = el.scrollTop;
      const idx = Math.max(0, Math.min(Math.round(top / ITEM_HEIGHT), max));
      el.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
      if (type === 'y') {
        const val = years[idx];
        if (val && val !== selectedY) setSelectedY(val);
      } else {
        const val = months[idx];
        if (val && val !== selectedM) setSelectedM(val);
      }
    }, 90);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000, display: 'flex', alignItems: 'flex-end', justifyContent: 'center', pointerEvents: 'auto' }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.45)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)', zIndex: 0 }} onClick={onClose} />
      <div style={{ position: 'relative', width: '100%', maxWidth: '480px', background: 'white', zIndex: 1, borderRadius: '32px 32px 0 0', padding: '24px 24px calc(24px + env(safe-area-inset-bottom))', boxShadow: '0 -10px 40px rgba(0,0,0,0.15)', pointerEvents: 'auto' }} onClick={(e) => e.stopPropagation()} onPointerDown={(e) => e.stopPropagation()}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px', alignItems: 'center' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer', padding: '8px', whiteSpace: 'nowrap' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '17px' }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '15px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer', padding: '8px', whiteSpace: 'nowrap' }}>確定</button>
        </div>
        <div style={{ position: 'relative', height: ITEM_HEIGHT * 5, display: 'flex', overflow: 'hidden', background: '#f9f9fb', borderRadius: '20px' }}>
          <div style={{ position: 'absolute', top: ITEM_HEIGHT * 2, left: 12, right: 12, height: ITEM_HEIGHT, background: 'rgba(83, 190, 232, 0.08)', borderRadius: '12px', zIndex: 0, pointerEvents: 'none', borderTop: '1px solid rgba(83, 190, 232, 0.1)', borderBottom: '1px solid rgba(83, 190, 232, 0.1)' }} />
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to bottom, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to top, white, transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div ref={yearListRef} onScroll={() => handleScroll(yearListRef, 'y')} style={{ flex: 1, height: '100%', minHeight: 0, overflowY: 'auto', overflowX: 'hidden', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} className="hide-scrollbar">
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map((y, idx) => (
              <div key={y} onClick={() => handleItemClick(yearListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: y === selectedY ? '20px' : '17px', fontWeight: y === selectedY ? '900' : '500', color: y === selectedY ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{y}年</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
          <div ref={monthListRef} onScroll={() => handleScroll(monthListRef, 'm')} style={{ flex: 1, height: '100%', minHeight: 0, overflowY: 'auto', overflowX: 'hidden', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} className="hide-scrollbar">
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map((m, idx) => (
              <div key={m} onClick={() => handleItemClick(monthListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: m === selectedM ? '20px' : '17px', fontWeight: m === selectedM ? '900' : '500', color: m === selectedM ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{m}月</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null; touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const getExhibitionsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (d.isAfter(start) || d.isSame(start)) && (d.isBefore(end) || d.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const days: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) days.push({ day: null, dateKey: null });
    for (let i = 1; i <= count; i++) {
      days.push({ day: i, dateKey: `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}` });
    }
    // Pad to full weeks
    while (days.length % 7 !== 0) days.push({ day: null, dateKey: null });

    const weeks = [];
    for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  // Logic to calculate bars per week row
  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find(d => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find(d => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    // Find all exhibitions that overlap this week
    const weekExhibitions = exhibitions.filter(ex => {
      const start = dayjs(ex.startDate).startOf('day');
      const end = dayjs(ex.endDate).endOf('day');
      return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && 
             (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          // Find start and end columns (0-6)
          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex(d => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex(d => d.dateKey !== null);

          const left = (startCol * (100 / 7)) + 0.5;
          const width = ((endCol - startCol + 1) * (100 / 7)) - 1;

          const isInStartWeek = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));
          const shouldShowText = isInStartWeek;

          return (
            <div 
              key={ex.id}
              style={{
                position: 'absolute',
                top: `${idx * 8}px`,
                left: `${left}%`,
                width: `${width}%`,
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                display: 'flex',
                alignItems: 'center',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && (
                <span style={{ 
                  fontSize: '8px', fontWeight: '900', color: 'white', 
                  paddingLeft: '4px', whiteSpace: 'nowrap', textShadow: '0 1px 2px rgba(0,0,0,0.1)'
                }}>
                  {ex.title}
                </span>
              )}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ 
            position: 'absolute', top: '18px', right: '4px', 
            fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak 
          }}>
            +{weekExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)', whiteSpace: 'nowrap' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          <div 
            onClick={() => setIsWheelPickerOpen(true)} 
            style={{ 
              justifySelf: 'center', 
              fontSize: '17px', 
              fontWeight: '900', 
              color: theme.colors.text, 
              cursor: 'pointer', 
              display: 'inline-flex', 
              alignItems: 'center', 
              padding: '6px 10px', 
              borderRadius: '12px', 
              maxWidth: '100%'
            }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button onClick={() => setCurrentDate(new Date())} style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 14px', borderRadius: '999px', cursor: 'pointer', whiteSpace: 'nowrap' }}>今日</button>
        </div>

        <div onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun' ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];

                  return (
                    <div
                      key={d.day}
                      onClick={() => d.day && handleDayClick(d.day)}
                      style={{
                        position: 'relative',
                        padding: '6px 4px 10px 4px',
                        borderRadius: '12px',
                        cursor: 'pointer',
                        background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent',
                        border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent',
                        zIndex: 0,
                      }}
                    >
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>
                        {d.day}
                      </div>

                      {mode === 'concert' && musicEvents.length > 0 && (
                        <div style={{ marginTop: '6px', display: 'flex', gap: '3px', flexWrap: 'wrap', justifyContent: 'center' }}>
                          {musicEvents.slice(0, 3).map((ev, evIdx) => (
                            <div key={evIdx} style={{ width: '6px', height: '6px', borderRadius: '999px', background: ev.type === '公演' ? theme.colors.primary : '#F7893F', opacity: 0.9 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>
                        {dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}
                        <br />{ex.venueName || ex.venue}
                      </div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPicker isOpen={isWheelPickerOpen} onClose={() => setIsWheelPickerOpen(false)} onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }} initialYear={currentDate.getFullYear()} initialMonth={currentDate.getMonth() + 1} />
      <CalendarMenu isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart} showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped} />
    </PageShell>
  );
};

