// --- Wheel Picker Popover Component ---
const WheelPickerPopover = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
  anchorRect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
  anchorRect: DOMRect | null;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;
  const POPOVER_WIDTH = Math.min(340, window.innerWidth - 32);
  const POPOVER_HEIGHT = 340;

  // Positioning Logic
  const position = useMemo(() => {
    if (!anchorRect) return { top: 0, left: 0 };
    let left = anchorRect.left + anchorRect.width / 2 - POPOVER_WIDTH / 2;
    left = Math.min(Math.max(left, 16), window.innerWidth - 16 - POPOVER_WIDTH);

    let top = anchorRect.bottom + 10;
    if (top + POPOVER_HEIGHT > window.innerHeight - 16) {
      top = anchorRect.top - 10 - POPOVER_HEIGHT;
    }
    return { top, left };
  }, [anchorRect, POPOVER_WIDTH, POPOVER_HEIGHT]);

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'auto' });
    }
  };

  useLayoutEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      requestAnimationFrame(() => {
        syncScroll(yearListRef, initialYear, years);
        syncScroll(monthListRef, initialMonth, months);
        setSelectedY(initialYear);
        setSelectedM(initialMonth);
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);
    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;
      const max = type === 'y' ? years.length - 1 : months.length - 1;
      const top = el.scrollTop;
      const idx = Math.max(0, Math.min(Math.round(top / ITEM_HEIGHT), max));
      el.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
      if (type === 'y') {
        const val = years[idx];
        if (val && val !== selectedY) setSelectedY(val);
      } else {
        const val = months[idx];
        if (val && val !== selectedM) setSelectedM(val);
      }
    }, 90);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000 }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      {/* Backdrop */}
      <div 
        style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.18)', backdropFilter: 'blur(4px)', WebkitBackdropFilter: 'blur(4px)' }} 
        onClick={onClose} 
      />

      {/* Popover Card */}
      <div 
        className="fade-in"
        onClick={(e) => e.stopPropagation()}
        style={{ 
          position: 'fixed', 
          top: position.top, 
          left: position.left,
          width: POPOVER_WIDTH,
          height: POPOVER_HEIGHT,
          background: 'rgba(255, 255, 255, 0.86)', 
          backdropFilter: 'blur(24px)',
          WebkitBackdropFilter: 'blur(24px)',
          borderRadius: '24px', 
          padding: '16px', 
          boxShadow: '0 18px 50px rgba(0,0,0,0.12)',
          border: '1px solid rgba(15, 23, 42, 0.06)',
          display: 'flex',
          flexDirection: 'column',
          pointerEvents: 'auto'
        }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px', alignItems: 'center', padding: '0 4px' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '15px' }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer' }}>確定</button>
        </div>

        <div style={{ position: 'relative', flex: 1, display: 'flex', overflow: 'hidden', background: 'rgba(0,0,0,0.03)', borderRadius: '16px' }}>
          {/* Visual Overlays - pointer-events: none is critical */}
          <div style={{ 
            position: 'absolute', top: ITEM_HEIGHT * 2, left: 8, right: 8, height: ITEM_HEIGHT, 
            background: 'rgba(83, 190, 232, 0.08)', borderRadius: '10px', zIndex: 0, pointerEvents: 'none',
            borderTop: '0.5px solid rgba(83, 190, 232, 0.15)', borderBottom: '0.5px solid rgba(83, 190, 232, 0.15)'
          }} />
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to bottom, rgba(255,255,255,0.9), transparent)', zIndex: 2, pointerEvents: 'none' }} />
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: ITEM_HEIGHT, background: 'linear-gradient(to top, rgba(255,255,255,0.9), transparent)', zIndex: 2, pointerEvents: 'none' }} />

          {/* Year Wheel */}
          <div 
            ref={yearListRef} 
            onScroll={() => handleScroll(yearListRef, 'y')} 
            style={{ flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} 
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map((y, idx) => (
              <div key={y} onClick={() => handleItemClick(yearListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: y === selectedY ? '18px' : '16px', fontWeight: y === selectedY ? '900' : '500', color: y === selectedY ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{y}年</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>

          {/* Month Wheel */}
          <div 
            ref={monthListRef} 
            onScroll={() => handleScroll(monthListRef, 'm')} 
            style={{ flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} 
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map((m, idx) => (
              <div key={m} onClick={() => handleItemClick(monthListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: m === selectedM ? '18px' : '16px', fontWeight: m === selectedM ? '900' : '500', color: m === selectedM ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{m}月</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const monthAnchorRef = useRef<HTMLDivElement>(null);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null; touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const getExhibitionsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (d.isAfter(start) || d.isSame(start)) && (d.isBefore(end) || d.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const days: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) days.push({ day: null, dateKey: null });
    for (let i = 1; i <= count; i++) {
      days.push({ day: i, dateKey: `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}` });
    }
    while (days.length % 7 !== 0) days.push({ day: null, dateKey: null });

    const weeks = [];
    for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find(d => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find(d => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    const weekExhibitions = exhibitions.filter(ex => {
      const start = dayjs(ex.startDate).startOf('day');
      const end = dayjs(ex.endDate).endOf('day');
      return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex(d => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex(d => d.dateKey !== null);

          const left = (startCol * (100 / 7)) + 0.5;
          const width = ((endCol - startCol + 1) * (100 / 7)) - 1;
          const shouldShowText = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));

          return (
            <div key={ex.id} style={{ position: 'absolute', top: `${idx * 8}px`, left: `${left}%`, width: `${width}%`, height: '6px', background: theme.colors.primary, opacity: idx === 0 ? 0.75 : 0.45, borderRadius: '999px', display: 'flex', alignItems: 'center', overflow: 'hidden' }}>
              {shouldShowText && <span style={{ fontSize: '8px', fontWeight: '900', color: 'white', paddingLeft: '4px', whiteSpace: 'nowrap', textShadow: '0 1px 2px rgba(0,0,0,0.1)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && <div style={{ position: 'absolute', top: '18px', right: '4px', fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak }}>+{weekExhibitions.length - 2}</div>}
      </div>
    );
  };

  const handleOpenPicker = () => {
    if (monthAnchorRef.current) {
      setAnchorRect(monthAnchorRef.current.getBoundingClientRect());
      setIsWheelPickerOpen(true);
    }
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)', whiteSpace: 'nowrap' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          <div 
            ref={monthAnchorRef}
            onClick={handleOpenPicker} 
            style={{ justifySelf: 'center', fontSize: '17px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'inline-flex', alignItems: 'center', padding: '6px 10px', borderRadius: '12px', maxWidth: '100%' }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button onClick={() => setCurrentDate(new Date())} style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 14px', borderRadius: '999px', cursor: 'pointer', whiteSpace: 'nowrap' }}>今日</button>
        </div>

        <div onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun' ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];
                  return (
                    <div key={d.day} onClick={() => d.day && handleDayClick(d.day)} style={{ position: 'relative', padding: '6px 4px 10px 4px', borderRadius: '12px', cursor: 'pointer', background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent', border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent', zIndex: 0 }}>
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>{d.day}</div>
                      {mode === 'concert' && musicEvents.length > 0 && (
                        <div style={{ marginTop: '6px', display: 'flex', gap: '3px', flexWrap: 'wrap', justifyContent: 'center' }}>
                          {musicEvents.slice(0, 3).map((ev, evIdx) => (
                            <div key={evIdx} style={{ width: '6px', height: '6px', borderRadius: '999px', background: ev.type === '公演' ? theme.colors.primary : '#F7893F', opacity: 0.9 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}<br />{ex.venueName || ex.venue}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPickerPopover 
        isOpen={isWheelPickerOpen} 
        onClose={() => setIsWheelPickerOpen(false)} 
        onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }} 
        initialYear={currentDate.getFullYear()} 
        initialMonth={currentDate.getMonth() + 1} 
        anchorRect={anchorRect}
      />
      <CalendarMenu isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart} showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped} />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Wheel Picker Popover Component ---
const WheelPickerPopover = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
  anchorRect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
  anchorRect: DOMRect | null;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;
  const POPOVER_WIDTH = Math.min(340, window.innerWidth - 32);
  const POPOVER_HEIGHT = 330; 

  // Positioning Logic
  const position = useMemo(() => {
    if (!anchorRect) return { top: 0, left: 0 };
    let left = anchorRect.left + anchorRect.width / 2 - POPOVER_WIDTH / 2;
    left = Math.min(Math.max(left, 16), window.innerWidth - 16 - POPOVER_WIDTH);

    let top = anchorRect.bottom + 10;
    if (top + POPOVER_HEIGHT > window.innerHeight - 16) {
      top = anchorRect.top - 10 - POPOVER_HEIGHT;
    }
    return { top, left };
  }, [anchorRect, POPOVER_WIDTH, POPOVER_HEIGHT]);

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'auto' });
    }
  };

  useLayoutEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      requestAnimationFrame(() => {
        syncScroll(yearListRef, initialYear, years);
        syncScroll(monthListRef, initialMonth, months);
        setSelectedY(initialYear);
        setSelectedM(initialMonth);
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);
    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;
      const options = type === 'y' ? years : months;
      const top = el.scrollTop;
      const idx = Math.max(0, Math.min(Math.round(top / ITEM_HEIGHT), options.length - 1));

      // Snap to exact position
      el.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });

      if (type === 'y') {
        const val = years[idx];
        if (val && val !== selectedY) setSelectedY(val);
      } else {
        const val = months[idx];
        if (val && val !== selectedM) setSelectedM(val);
      }
    }, 90);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    ref.current.scrollTo({ top: idx * ITEM_HEIGHT, behavior: 'smooth' });
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000 }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      {/* Backdrop: Simple gray semi-transparent as requested */}
      <div 
        style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.25)' }} 
        onClick={onClose} 
      />

      {/* Popover Card: Pure white, menu-style borders/shadow */}
      <div 
        className="fade-in"
        onClick={(e) => e.stopPropagation()}
        style={{ 
          position: 'fixed', 
          top: position.top, 
          left: position.left,
          width: POPOVER_WIDTH,
          height: POPOVER_HEIGHT,
          background: '#FFFFFF', 
          borderRadius: '24px', 
          padding: '16px', 
          boxShadow: '0 18px 50px rgba(0,0,0,0.12)',
          border: '1px solid rgba(15, 23, 42, 0.06)',
          display: 'flex',
          flexDirection: 'column',
          pointerEvents: 'auto'
        }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px', alignItems: 'center', padding: '0 4px' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '15px', color: theme.colors.text }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer' }}>確定</button>
        </div>

        <div style={{ position: 'relative', flex: 1, display: 'flex', overflow: 'hidden', background: 'rgba(0,0,0,0.02)', borderRadius: '16px' }}>
          {/* Central Highlight Layer: Center positioning for perfect alignment */}
          <div style={{ 
            position: 'absolute', 
            top: '50%', 
            left: 12, 
            right: 12, 
            height: ITEM_HEIGHT, 
            transform: 'translateY(-50%)',
            background: 'rgba(83, 190, 232, 0.08)', 
            borderRadius: '10px', 
            zIndex: 0, 
            pointerEvents: 'none',
            borderTop: '0.5px solid rgba(83, 190, 232, 0.12)', 
            borderBottom: '0.5px solid rgba(83, 190, 232, 0.12)'
          }} />

          {/* Year Wheel */}
          <div 
            ref={yearListRef} 
            onScroll={() => handleScroll(yearListRef, 'y')} 
            style={{ flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} 
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {years.map((y, idx) => (
              <div key={y} onClick={() => handleItemClick(yearListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: y === selectedY ? '18px' : '16px', fontWeight: y === selectedY ? '900' : '500', color: y === selectedY ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{y}年</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>

          {/* Month Wheel */}
          <div 
            ref={monthListRef} 
            onScroll={() => handleScroll(monthListRef, 'm')} 
            style={{ flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain' }} 
            className="hide-scrollbar"
          >
            <div style={{ height: ITEM_HEIGHT * 2 }} />
            {months.map((m, idx) => (
              <div key={m} onClick={() => handleItemClick(monthListRef, idx)} style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', fontSize: m === selectedM ? '18px' : '16px', fontWeight: m === selectedM ? '900' : '500', color: m === selectedM ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', cursor: 'pointer', userSelect: 'none' }}>{m}月</div>
            ))}
            <div style={{ height: ITEM_HEIGHT * 2 }} />
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const monthAnchorRef = useRef<HTMLDivElement>(null);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null; touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const getExhibitionsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (d.isAfter(start) || d.isSame(start)) && (d.isBefore(end) || d.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const days: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) days.push({ day: null, dateKey: null });
    for (let i = 1; i <= count; i++) {
      days.push({ day: i, dateKey: `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}` });
    }
    while (days.length % 7 !== 0) days.push({ day: null, dateKey: null });

    const weeks = [];
    for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find(d => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find(d => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    const weekExhibitions = exhibitions.filter(ex => {
      const start = dayjs(ex.startDate).startOf('day');
      const end = dayjs(ex.endDate).endOf('day');
      return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex(d => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex(d => d.dateKey !== null);

          const left = (startCol * (100 / 7)) + 0.5;
          const width = ((endCol - startCol + 1) * (100 / 7)) - 1;
          const shouldShowText = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));

          return (
            <div key={ex.id} style={{ position: 'absolute', top: `${idx * 8}px`, left: `${left}%`, width: `${width}%`, height: '6px', background: theme.colors.primary, opacity: idx === 0 ? 0.75 : 0.45, borderRadius: '999px', display: 'flex', alignItems: 'center', overflow: 'hidden' }}>
              {shouldShowText && <span style={{ fontSize: '8px', fontWeight: '900', color: 'white', paddingLeft: '4px', whiteSpace: 'nowrap', textShadow: '0 1px 2px rgba(0,0,0,0.1)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && <div style={{ position: 'absolute', top: '18px', right: '4px', fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak }}>+{weekExhibitions.length - 2}</div>}
      </div>
    );
  };

  const handleOpenPicker = () => {
    if (monthAnchorRef.current) {
      setAnchorRect(monthAnchorRef.current.getBoundingClientRect());
      setIsWheelPickerOpen(true);
    }
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)', whiteSpace: 'nowrap' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          <div 
            ref={monthAnchorRef}
            onClick={handleOpenPicker} 
            style={{ justifySelf: 'center', fontSize: '17px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'inline-flex', alignItems: 'center', padding: '6px 10px', borderRadius: '12px', maxWidth: '100%' }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button onClick={() => setCurrentDate(new Date())} style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 14px', borderRadius: '999px', cursor: 'pointer', whiteSpace: 'nowrap' }}>今日</button>
        </div>

        <div onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun' ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];
                  return (
                    <div key={d.day} onClick={() => d.day && handleDayClick(d.day)} style={{ position: 'relative', padding: '6px 4px 10px 4px', borderRadius: '12px', cursor: 'pointer', background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent', border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent', zIndex: 0 }}>
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>{d.day}</div>
                      {mode === 'concert' && musicEvents.length > 0 && (
                        <div style={{ marginTop: '6px', display: 'flex', gap: '3px', flexWrap: 'wrap', justifyContent: 'center' }}>
                          {musicEvents.slice(0, 3).map((ev, evIdx) => (
                            <div key={evIdx} style={{ width: '6px', height: '6px', borderRadius: '999px', background: ev.type === '公演' ? theme.colors.primary : '#F7893F', opacity: 0.9 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}<br />{ex.venueName || ex.venue}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPickerPopover 
        isOpen={isWheelPickerOpen} 
        onClose={() => setIsWheelPickerOpen(false)} 
        onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }} 
        initialYear={currentDate.getFullYear()} 
        initialMonth={currentDate.getMonth() + 1} 
        anchorRect={anchorRect}
      />
      <CalendarMenu isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart} showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped} />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '9999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Wheel Picker Popover Component ---
const WheelPickerPopover = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
  anchorRect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
  anchorRect: DOMRect | null;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;
  const POPOVER_WIDTH = Math.min(340, window.innerWidth - 32);
  const POPOVER_HEIGHT = 330; 

  // Positioning Logic
  const position = useMemo(() => {
    if (!anchorRect) return { top: 0, left: 0 };
    let left = anchorRect.left + anchorRect.width / 2 - POPOVER_WIDTH / 2;
    left = Math.min(Math.max(left, 16), window.innerWidth - 16 - POPOVER_WIDTH);

    let top = anchorRect.bottom + 10;
    if (top + POPOVER_HEIGHT > window.innerHeight - 16) {
      top = anchorRect.top - 10 - POPOVER_HEIGHT;
    }
    return { top, left };
  }, [anchorRect, POPOVER_WIDTH, POPOVER_HEIGHT]);

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      const target = ref.current.children[idx] as HTMLElement;
      if (target) {
        target.scrollIntoView({ block: 'center', behavior: 'auto' });
      }
    }
  };

  useLayoutEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Use double RAF to ensure the DOM is painted and scrollable
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          syncScroll(yearListRef, initialYear, years);
          syncScroll(monthListRef, initialMonth, months);
          setSelectedY(initialYear);
          setSelectedM(initialMonth);
        });
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);

    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;

      const children = Array.from(el.children) as HTMLElement[];
      const containerRect = el.getBoundingClientRect();
      const containerCenter = containerRect.top + containerRect.height / 2;

      let closestIdx = 0;
      let minDiff = Number.MAX_VALUE;

      children.forEach((child, idx) => {
        const rect = child.getBoundingClientRect();
        const childCenter = rect.top + rect.height / 2;
        const diff = Math.abs(containerCenter - childCenter);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = idx;
        }
      });

      const targetItem = children[closestIdx];
      if (targetItem) {
        targetItem.scrollIntoView({ block: 'center', behavior: 'smooth' });
        const options = type === 'y' ? years : months;
        const val = options[closestIdx];
        if (val !== undefined) {
          if (type === 'y') setSelectedY(val);
          else setSelectedM(val);
        }
      }
    }, 100);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    const target = ref.current.children[idx] as HTMLElement;
    if (target) {
      target.scrollIntoView({ block: 'center', behavior: 'smooth' });
    }
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000 }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      <div 
        style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.25)' }} 
        onClick={onClose} 
      />

      <div 
        className="fade-in"
        onClick={(e) => e.stopPropagation()}
        style={{ 
          position: 'fixed', 
          top: position.top, 
          left: position.left,
          width: POPOVER_WIDTH,
          height: POPOVER_HEIGHT,
          background: '#FFFFFF', 
          borderRadius: '24px', 
          padding: '16px', 
          boxShadow: '0 18px 50px rgba(0,0,0,0.12)',
          border: '1px solid rgba(15, 23, 42, 0.06)',
          display: 'flex',
          flexDirection: 'column',
          pointerEvents: 'auto'
        }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px', alignItems: 'center', padding: '0 4px' }}>
          <button onClick={onClose} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: 'bold', color: theme.colors.textSecondary, cursor: 'pointer' }}>キャンセル</button>
          <span style={{ fontWeight: '900', fontSize: '15px', color: theme.colors.text }}>年月を選択</span>
          <button onClick={() => onConfirm(selectedY, selectedM)} style={{ border: 'none', background: 'none', fontSize: '14px', fontWeight: '900', color: theme.colors.primary, cursor: 'pointer' }}>確定</button>
        </div>

        <div style={{ position: 'relative', flex: 1, display: 'flex', overflow: 'hidden', background: 'rgba(0,0,0,0.02)', borderRadius: '16px' }}>
          {/* Central Highlight Layer: top:50% + translateY(-50%) for perfect centering */}
          <div style={{ 
            position: 'absolute', 
            top: '50%', 
            left: 12, 
            right: 12, 
            height: ITEM_HEIGHT, 
            transform: 'translateY(-50%)',
            background: 'rgba(83, 190, 232, 0.08)', 
            borderRadius: '10px', 
            zIndex: 0, 
            pointerEvents: 'none',
            borderTop: '0.5px solid rgba(83, 190, 232, 0.12)', 
            borderBottom: '0.5px solid rgba(83, 190, 232, 0.12)'
          }} />

          {/* Year Wheel */}
          <div 
            ref={yearListRef} 
            onScroll={() => handleScroll(yearListRef, 'y')} 
            style={{ 
              flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, 
              WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3, paddingBottom: ITEM_HEIGHT * 3
            }} 
            className="hide-scrollbar"
          >
            {years.map((y, idx) => (
              <div 
                key={y} 
                onClick={() => handleItemClick(yearListRef, idx)} 
                style={{ 
                  height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', 
                  fontSize: y === selectedY ? '18px' : '16px', fontWeight: y === selectedY ? '900' : '500', 
                  color: y === selectedY ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', 
                  cursor: 'pointer', userSelect: 'none' 
                }}
              >
                {y}年
              </div>
            ))}
          </div>

          {/* Month Wheel */}
          <div 
            ref={monthListRef} 
            onScroll={() => handleScroll(monthListRef, 'm')} 
            style={{ 
              flex: 1, height: '100%', overflowY: 'auto', scrollSnapType: 'y mandatory', textAlign: 'center', zIndex: 1, 
              WebkitOverflowScrolling: 'touch', touchAction: 'pan-y', pointerEvents: 'auto', overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3, paddingBottom: ITEM_HEIGHT * 3
            }} 
            className="hide-scrollbar"
          >
            {months.map((m, idx) => (
              <div 
                key={m} 
                onClick={() => handleItemClick(monthListRef, idx)} 
                style={{ 
                  height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', justifyContent: 'center', scrollSnapAlign: 'center', 
                  fontSize: m === selectedM ? '18px' : '16px', fontWeight: m === selectedM ? '900' : '500', 
                  color: m === selectedM ? theme.colors.text : theme.colors.textWeak, transition: 'all 0.2s ease', 
                  cursor: 'pointer', userSelect: 'none' 
                }}
              >
                {m}月
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');
  const [mode, setMode] = useState<CalendarMode>('concert');
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const monthAnchorRef = useRef<HTMLDivElement>(null);

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => { touchStartX.current = e.targetTouches[0].clientX; };
  const handleTouchMove = (e: React.TouchEvent) => { touchEndX.current = e.targetTouches[0].clientX; };
  const handleTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > 60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    else if (distance < -60) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    touchStartX.current = null; touchEndX.current = null;
  };

  useEffect(() => { setSelectedDateKey(null); }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const musicEventMap = useMemo(() => {
    const events = buildCalendarEvents(artists, { showAttended, showSkipped });
    const map = new Map<string, CalendarEvent[]>();
    events.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [artists, showAttended, showSkipped]);

  const getExhibitionsForDay = (dateKey: string) => {
    const d = dayjs(dateKey);
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (d.isAfter(start) || d.isSame(start)) && (d.isBefore(end) || d.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = new Date(year, month + 1, 0).getDate();
    const firstDayIndex = new Date(year, month, 1).getDay();
    let startOffset = 0;
    if (weekStart === 'sun') startOffset = firstDayIndex;
    else startOffset = firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const days: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) days.push({ day: null, dateKey: null });
    for (let i = 1; i <= count; i++) {
      days.push({ day: i, dateKey: `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}` });
    }
    while (days.length % 7 !== 0) days.push({ day: null, dateKey: null });

    const weeks = [];
    for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => dayjs().format('YYYY-MM-DD'), []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find(d => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find(d => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    const weekExhibitions = exhibitions.filter(ex => {
      const start = dayjs(ex.startDate).startOf('day');
      const end = dayjs(ex.endDate).endOf('day');
      return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
    }).sort((a, b) => {
      const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
      const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
      if (prioA !== prioB) return prioA - prioB;
      return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
    });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex(d => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex(d => d.dateKey !== null);

          const left = (startCol * (100 / 7)) + 0.5;
          const width = ((endCol - startCol + 1) * (100 / 7)) - 1;
          const shouldShowText = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));

          return (
            <div key={ex.id} style={{ position: 'absolute', top: `${idx * 8}px`, left: `${left}%`, width: `${width}%`, height: '6px', background: theme.colors.primary, opacity: idx === 0 ? 0.75 : 0.45, borderRadius: '999px', display: 'flex', alignItems: 'center', overflow: 'hidden' }}>
              {shouldShowText && <span style={{ fontSize: '8px', fontWeight: '900', color: 'white', paddingLeft: '4px', whiteSpace: 'nowrap', textShadow: '0 1px 2px rgba(0,0,0,0.1)' }}>{ex.title}</span>}
            </div>
          );
        })}
        {hasMore && <div style={{ position: 'absolute', top: '18px', right: '4px', fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak }}>+{weekExhibitions.length - 2}</div>}
      </div>
    );
  };

  const handleOpenPicker = () => {
    if (monthAnchorRef.current) {
      setAnchorRect(monthAnchorRef.current.getBoundingClientRect());
      setIsWheelPickerOpen(true);
    }
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div style={{ display: 'inline-flex', background: 'white', padding: '3px', borderRadius: '999px', border: '1px solid rgba(0,0,0,0.06)', boxShadow: '0 2px 8px rgba(0,0,0,0.03)', whiteSpace: 'nowrap' }}>
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>公演</button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>展覧</button>
          </div>

          <div 
            ref={monthAnchorRef}
            onClick={handleOpenPicker} 
            style={{ justifySelf: 'center', fontSize: '17px', fontWeight: '900', color: theme.colors.text, cursor: 'pointer', display: 'inline-flex', alignItems: 'center', padding: '6px 10px', borderRadius: '12px', maxWidth: '100%' }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button onClick={() => setCurrentDate(new Date())} style={{ border: '1px solid rgba(0,0,0,0.06)', background: 'white', color: theme.colors.primary, fontSize: '12px', fontWeight: 800, padding: '8px 14px', borderRadius: '999px', cursor: 'pointer', whiteSpace: 'nowrap' }}>今日</button>
        </div>

        <div onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} style={{ background: 'white', borderRadius: '28px', padding: '16px 10px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 20px rgba(0,0,0,0.03)', overflow: 'hidden', userSelect: 'none', touchAction: 'pan-y' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun' ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT] : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];
                  return (
                    <div key={d.day} onClick={() => d.day && handleDayClick(d.day)} style={{ position: 'relative', padding: '6px 4px 10px 4px', borderRadius: '12px', cursor: 'pointer', background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent', border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent', zIndex: 0 }}>
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>{d.day}</div>
                      {mode === 'concert' && musicEvents.length > 0 && (
                        <div style={{ marginTop: '6px', display: 'flex', gap: '3px', flexWrap: 'wrap', justifyContent: 'center' }}>
                          {musicEvents.slice(0, 3).map((ev, evIdx) => (
                            <div key={evIdx} style={{ width: '6px', height: '6px', borderRadius: '999px', background: ev.type === '公演' ? theme.colors.primary : '#F7893F', opacity: 0.9 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}<br />{ex.venueName || ex.venue}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPickerPopover 
        isOpen={isWheelPickerOpen} 
        onClose={() => setIsWheelPickerOpen(false)} 
        onConfirm={(y, m) => { setCurrentDate(new Date(y, m - 1, 1)); setIsWheelPickerOpen(false); }} 
        initialYear={currentDate.getFullYear()} 
        initialMonth={currentDate.getMonth() + 1} 
        anchorRect={anchorRect}
      />
      <CalendarMenu isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} weekStart={weekStart} setWeekStart={setWeekStart} showAttended={showAttended} setShowAttended={setShowAttended} showSkipped={showSkipped} setShowSkipped={setShowSkipped} />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = { border: 'none', padding: '6px 14px', borderRadius: '9999px', fontSize: '13px', fontWeight: '800', cursor: 'pointer', transition: 'all 0.2s' };
const eventCardStyle: React.CSSProperties = { background: 'white', borderRadius: '20px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' };

import React, { useEffect, useMemo, useRef, useState, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Music calendar dot rules (restored from legacy CalendarPage.tsx) ---
const typeColorMap: Record<CalendarEventType, string> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: theme.colors.status['参戦予定'],
  [TEXT.CALENDAR.EVENT_RESULT]: theme.colors.status['抽選中'],
  [TEXT.CALENDAR.EVENT_DEADLINE]: theme.colors.status['検討中'],
  [TEXT.CALENDAR.EVENT_SALE]: theme.colors.status['発売前'],
};

// 公演日（EVENT_CONCERT）は「参加確定度」で色分け（参戦予定/参戦済み=参戦予定色、未確定=濃いめ、见送=グレー）
const CONCERT_DOT_COLOR_UNDECIDED = '#377D99';
const CONCERT_DOT_COLOR_SKIPPED = '#6B7280';

const isConcertType = (t: any): boolean => t === TEXT.CALENDAR.EVENT_CONCERT || t === '公演';

const getConcertDotColor = (status: string): string => {
  if (status === '参戦予定' || status === '参戦済み') return theme.colors.status['参戦予定'];
  if (status === '抽選中' || status === '発売前' || status === '検討中') return CONCERT_DOT_COLOR_UNDECIDED;
  if (status === '見送' || status === '見送り') return CONCERT_DOT_COLOR_SKIPPED;
  return CONCERT_DOT_COLOR_UNDECIDED;
};

// --- Wheel Picker Popover Component ---
const WheelPickerPopover = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
  anchorRect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
  anchorRect: DOMRect | null;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;
  const POPOVER_WIDTH = Math.min(340, window.innerWidth - 32);
  const POPOVER_HEIGHT = 330;

  // Positioning Logic
  const position = useMemo(() => {
    if (!anchorRect) return { top: 0, left: 0 };
    let left = anchorRect.left + anchorRect.width / 2 - POPOVER_WIDTH / 2;
    left = Math.min(Math.max(left, 16), window.innerWidth - 16 - POPOVER_WIDTH);

    let top = anchorRect.bottom + 10;
    if (top + POPOVER_HEIGHT > window.innerHeight - 16) {
      top = anchorRect.top - 10 - POPOVER_HEIGHT;
    }
    return { top, left };
  }, [anchorRect, POPOVER_WIDTH, POPOVER_HEIGHT]);

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      const target = ref.current.children[idx] as HTMLElement;
      if (target) {
        target.scrollIntoView({ block: 'center', behavior: 'auto' });
      }
    }
  };

  useLayoutEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Use double RAF to ensure the DOM is painted and scrollable
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          syncScroll(yearListRef, initialYear, years);
          syncScroll(monthListRef, initialMonth, months);
          setSelectedY(initialYear);
          setSelectedM(initialMonth);
        });
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);

    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;

      const children = Array.from(el.children) as HTMLElement[];
      const containerRect = el.getBoundingClientRect();
      const containerCenter = containerRect.top + containerRect.height / 2;

      let closestIdx = 0;
      let minDiff = Number.MAX_VALUE;

      children.forEach((child, idx) => {
        const rect = child.getBoundingClientRect();
        const childCenter = rect.top + rect.height / 2;
        const diff = Math.abs(containerCenter - childCenter);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = idx;
        }
      });

      const targetItem = children[closestIdx];
      if (targetItem) {
        targetItem.scrollIntoView({ block: 'center', behavior: 'smooth' });
        const options = type === 'y' ? years : months;
        const val = options[closestIdx];
        if (val !== undefined) {
          if (type === 'y') setSelectedY(val);
          else setSelectedM(val);
        }
      }
    }, 100);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    const target = ref.current.children[idx] as HTMLElement;
    if (target) {
      target.scrollIntoView({ block: 'center', behavior: 'smooth' });
    }
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000 }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.25)' }} onClick={onClose} />

      <div
        className="fade-in"
        onClick={(e) => e.stopPropagation()}
        style={{
          position: 'fixed',
          top: position.top,
          left: position.left,
          width: POPOVER_WIDTH,
          height: POPOVER_HEIGHT,
          background: '#FFFFFF',
          borderRadius: '24px',
          padding: '16px',
          boxShadow: '0 18px 50px rgba(0,0,0,0.12)',
          border: '1px solid rgba(15, 23, 42, 0.06)',
          display: 'flex',
          flexDirection: 'column',
          pointerEvents: 'auto',
        }}
      >
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            marginBottom: '16px',
            alignItems: 'center',
            padding: '0 4px',
          }}
        >
          <button
            onClick={onClose}
            style={{
              border: 'none',
              background: 'none',
              fontSize: '14px',
              fontWeight: 'bold',
              color: theme.colors.textSecondary,
              cursor: 'pointer',
            }}
          >
            キャンセル
          </button>
          <span style={{ fontWeight: '900', fontSize: '15px', color: theme.colors.text }}>年月を選択</span>
          <button
            onClick={() => onConfirm(selectedY, selectedM)}
            style={{
              border: 'none',
              background: 'none',
              fontSize: '14px',
              fontWeight: '900',
              color: theme.colors.primary,
              cursor: 'pointer',
            }}
          >
            確定
          </button>
        </div>

        <div
          style={{
            position: 'relative',
            flex: 1,
            display: 'flex',
            overflow: 'hidden',
            background: 'rgba(0,0,0,0.02)',
            borderRadius: '16px',
          }}
        >
          {/* Central Highlight Layer: top:50% + translateY(-50%) for perfect centering */}
          <div
            style={{
              position: 'absolute',
              top: '50%',
              left: 12,
              right: 12,
              height: ITEM_HEIGHT,
              transform: 'translateY(-50%)',
              background: 'rgba(83, 190, 232, 0.08)',
              borderRadius: '10px',
              zIndex: 0,
              pointerEvents: 'none',
              borderTop: '0.5px solid rgba(83, 190, 232, 0.12)',
              borderBottom: '0.5px solid rgba(83, 190, 232, 0.12)',
            }}
          />

          {/* Year Wheel */}
          <div
            ref={yearListRef}
            onScroll={() => handleScroll(yearListRef, 'y')}
            style={{
              flex: 1,
              height: '100%',
              overflowY: 'auto',
              scrollSnapType: 'y mandatory',
              textAlign: 'center',
              zIndex: 1,
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto',
              overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3,
              paddingBottom: ITEM_HEIGHT * 3,
            }}
            className="hide-scrollbar"
          >
            {years.map((y, idx) => (
              <div
                key={y}
                onClick={() => handleItemClick(yearListRef, idx)}
                style={{
                  height: ITEM_HEIGHT,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  scrollSnapAlign: 'center',
                  fontSize: y === selectedY ? '18px' : '16px',
                  fontWeight: y === selectedY ? '900' : '500',
                  color: y === selectedY ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  userSelect: 'none',
                }}
              >
                {y}年
              </div>
            ))}
          </div>

          {/* Month Wheel */}
          <div
            ref={monthListRef}
            onScroll={() => handleScroll(monthListRef, 'm')}
            style={{
              flex: 1,
              height: '100%',
              overflowY: 'auto',
              scrollSnapType: 'y mandatory',
              textAlign: 'center',
              zIndex: 1,
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto',
              overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3,
              paddingBottom: ITEM_HEIGHT * 3,
            }}
            className="hide-scrollbar"
          >
            {months.map((m, idx) => (
              <div
                key={m}
                onClick={() => handleItemClick(monthListRef, idx)}
                style={{
                  height: ITEM_HEIGHT,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  scrollSnapAlign: 'center',
                  fontSize: m === selectedM ? '18px' : '16px',
                  fontWeight: m === selectedM ? '900' : '500',
                  color: m === selectedM ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  userSelect: 'none',
                }}
              >
                {m}月
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  onRefreshAll,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const [mode, setMode] = useState<CalendarMode>('concert');

  const monthAnchorRef = useRef<HTMLDivElement | null>(null);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);

  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [touchCurrentX, setTouchCurrentX] = useState<number | null>(null);

  useEffect(() => {
    setSelectedDateKey(null);
  }, [currentDate.getFullYear(), currentDate.getMonth(), mode]);

  const allEvents = useMemo(() => {
    return buildCalendarEvents(artists, { showAttended, showSkipped });
  }, [artists, showAttended, showSkipped]);

  const musicEventMap = useMemo(() => {
    const map = new Map<string, CalendarEvent[]>();
    allEvents.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [allEvents]);

  const getExhibitionsForDay = (dateKey: string): Exhibition[] => {
    const day = dayjs(dateKey).startOf('day');
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (day.isAfter(start) || day.isSame(start)) && (day.isBefore(end) || day.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();

    const firstOfMonth = dayjs(new Date(year, month, 1));
    const daysInMonth = firstOfMonth.daysInMonth();

    const firstDayIndex = firstOfMonth.day(); // 0=Sun..6=Sat
    const startOffset = weekStart === 'sun' ? firstDayIndex : firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const cells: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) cells.push({ day: null, dateKey: null });
    for (let d = 1; d <= daysInMonth; d++) {
      const dateKey = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      cells.push({ day: d, dateKey });
    }

    const weeks: Array<Array<{ day: number | null; dateKey: string | null }>> = [];
    for (let i = 0; i < cells.length; i += 7) weeks.push(cells.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => {
    const t = new Date();
    return `${t.getFullYear()}-${String(t.getMonth() + 1).padStart(2, '0')}-${String(t.getDate()).padStart(2, '0')}`;
  }, []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (isWheelPickerOpen) return;
    setTouchStartX(e.touches[0].clientX);
    setTouchCurrentX(e.touches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (touchStartX === null) return;
    setTouchCurrentX(e.touches[0].clientX);
  };

  const handleTouchEnd = () => {
    if (touchStartX === null || touchCurrentX === null) {
      setTouchStartX(null);
      setTouchCurrentX(null);
      return;
    }
    const dx = touchCurrentX - touchStartX;
    const threshold = 70;
    if (Math.abs(dx) > threshold) {
      if (dx < 0) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
      else setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    }
    setTouchStartX(null);
    setTouchCurrentX(null);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find((d) => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find((d) => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    const weekExhibitions = exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex((d) => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex((d) => d.dateKey !== null);

          const left = startCol * (100 / 7) + 0.5;
          const width = (endCol - startCol + 1) * (100 / 7) - 1;
          const shouldShowText = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));

          return (
            <div
              key={ex.id}
              style={{
                position: 'absolute',
                top: `${idx * 8}px`,
                left: `${left}%`,
                width: `${width}%`,
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                display: 'flex',
                alignItems: 'center',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && (
                <span
                  style={{
                    fontSize: '8px',
                    fontWeight: '900',
                    color: 'white',
                    paddingLeft: '4px',
                    whiteSpace: 'nowrap',
                    textShadow: '0 1px 2px rgba(0,0,0,0.1)',
                  }}
                >
                  {ex.title}
                </span>
              )}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ position: 'absolute', top: '18px', right: '4px', fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak }}>
            +{weekExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  const handleOpenPicker = () => {
    if (monthAnchorRef.current) {
      setAnchorRect(monthAnchorRef.current.getBoundingClientRect());
      setIsWheelPickerOpen(true);
    }
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div
            style={{
              display: 'inline-flex',
              background: 'white',
              padding: '3px',
              borderRadius: '999px',
              border: '1px solid rgba(0,0,0,0.06)',
              boxShadow: '0 2px 8px rgba(0,0,0,0.03)',
              whiteSpace: 'nowrap',
            }}
          >
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>
              公演
            </button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>
              展覧
            </button>
          </div>

          <div
            ref={monthAnchorRef}
            onClick={handleOpenPicker}
            style={{
              justifySelf: 'center',
              fontSize: '17px',
              fontWeight: '900',
              color: theme.colors.text,
              cursor: 'pointer',
              display: 'inline-flex',
              alignItems: 'center',
              padding: '6px 10px',
              borderRadius: '12px',
              maxWidth: '100%',
            }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button
            onClick={() => setCurrentDate(new Date())}
            style={{
              border: '1px solid rgba(0,0,0,0.06)',
              background: 'white',
              color: theme.colors.primary,
              fontSize: '12px',
              fontWeight: 800,
              padding: '8px 14px',
              borderRadius: '999px',
              cursor: 'pointer',
              whiteSpace: 'nowrap',
            }}
          >
            今日
          </button>
        </div>

        <div
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          style={{
            background: 'white',
            borderRadius: '28px',
            padding: '16px 10px',
            border: '1px solid rgba(0,0,0,0.04)',
            boxShadow: '0 4px 20px rgba(0,0,0,0.03)',
            overflow: 'hidden',
            userSelect: 'none',
            touchAction: 'pan-y',
          }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun'
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT]
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>
                {l}
              </div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];
                  return (
                    <div
                      key={d.day}
                      onClick={() => d.day && handleDayClick(d.day)}
                      style={{
                        position: 'relative',
                        padding: '6px 4px 10px 4px',
                        borderRadius: '12px',
                        cursor: 'pointer',
                        background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent',
                        border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent',
                        zIndex: 0,
                      }}
                    >
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>
                        {d.day}
                      </div>

                      {mode === 'concert' && musicEvents.length > 0 && (() => {
                        const sorted = [...musicEvents].sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
                        const primary = sorted[0];
                        let primaryDotColor: string | null = null;

                        if (primary) {
                          if (isConcertType(primary.type)) primaryDotColor = getConcertDotColor(primary.status);
                          else primaryDotColor = typeColorMap[primary.type] || theme.colors.primary;
                        }

                        return (
                          <div style={{ marginTop: '6px', height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                            {primaryDotColor && <div style={{ width: '6px', height: '6px', borderRadius: '999px', background: primaryDotColor }} />}
                            {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '999px', background: '#CBD5E1' }} />}
                          </div>
                        );
                      })()}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>
                        {dayjs(ex.startDate).format('YYYY/MM/DD')} 〜 {dayjs(ex.endDate).format('YYYY/MM/DD')}
                        <br />
                        {ex.venueName || ex.venue}
                      </div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      <WheelPickerPopover
        isOpen={isWheelPickerOpen}
        onClose={() => setIsWheelPickerOpen(false)}
        onConfirm={(y, m) => {
          setCurrentDate(new Date(y, m - 1, 1));
          setIsWheelPickerOpen(false);
        }}
        initialYear={currentDate.getFullYear()}
        initialMonth={currentDate.getMonth() + 1}
        anchorRect={anchorRect}
      />
      <CalendarMenu
        isOpen={!!isMenuOpenExternally}
        onClose={() => onMenuClose?.()}
        weekStart={weekStart}
        setWeekStart={setWeekStart}
        showAttended={showAttended}
        setShowAttended={setShowAttended}
        showSkipped={showSkipped}
        setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

const modeBtnStyle: React.CSSProperties = {
  border: 'none',
  padding: '6px 14px',
  borderRadius: '9999px',
  fontSize: '13px',
  fontWeight: '800',
  cursor: 'pointer',
  transition: 'all 0.2s',
};
const eventCardStyle: React.CSSProperties = {
  background: 'white',
  borderRadius: '20px',
  padding: '12px 16px',
  border: '1px solid rgba(0,0,0,0.04)',
  boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  cursor: 'pointer',
};

import React, { useEffect, useMemo, useRef, useState, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { Artist, CalendarEvent, CalendarEventType, Exhibition, ExhibitionOverallStatus } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { buildCalendarEvents, EVENT_PRIORITY } from '../domain/logic';
import { Icons } from '../ui/IconButton';
import dayjs from 'dayjs';

interface Props {
  artists: Artist[];
  exhibitions: Exhibition[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onOpenExhibition: (exhibitionId: string) => void;
  onRefreshAll: () => void;
  isMenuOpenExternally?: boolean;
  onMenuClose?: () => void;
}

type CalendarMode = 'concert' | 'exhibition';

const exhibitionPriorityMap: Record<ExhibitionOverallStatus, number> = {
  running: 1,
  preparing: 2,
  visited: 3,
  ended_not_visited: 4,
};

// --- Music calendar dot rules (restored from legacy CalendarPage.tsx) ---
const typeColorMap: Record<CalendarEventType, string> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: theme.colors.status['参戦予定'],
  [TEXT.CALENDAR.EVENT_RESULT]: theme.colors.status['抽選中'],
  [TEXT.CALENDAR.EVENT_DEADLINE]: theme.colors.status['検討中'],
  [TEXT.CALENDAR.EVENT_SALE]: theme.colors.status['発売前'],
  // Fix: Added missing '展覧会' property to Record
  ['展覧会']: theme.colors.primary,
};

// 公演日（EVENT_CONCERT）は「参加確定度」で色分け（参戦予定/参戦済み=参戦予定色、未確定=濃いめ、见送=グレー）
const CONCERT_DOT_COLOR_UNDECIDED = '#377D99';
const CONCERT_DOT_COLOR_SKIPPED = '#6B7280';

const isConcertType = (t: any): boolean => t === TEXT.CALENDAR.EVENT_CONCERT || t === '公演';

const getConcertDotColor = (status: string): string => {
  if (status === '参戦予定' || status === '参戦済み') return theme.colors.status['参戦予定'];
  if (status === '抽選中' || status === '発売前' || status === '検討中') return CONCERT_DOT_COLOR_UNDECIDED;
  if (status === '見送' || status === '見送り') return CONCERT_DOT_COLOR_SKIPPED;
  return CONCERT_DOT_COLOR_UNDECIDED;
};

// --- Wheel Picker Popover Component ---
const WheelPickerPopover = ({
  isOpen,
  onClose,
  onConfirm,
  initialYear,
  initialMonth,
  anchorRect,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (y: number, m: number) => void;
  initialYear: number;
  initialMonth: number;
  anchorRect: DOMRect | null;
}) => {
  const [selectedY, setSelectedY] = useState(initialYear);
  const [selectedM, setSelectedM] = useState(initialMonth);
  const yearListRef = useRef<HTMLDivElement>(null);
  const monthListRef = useRef<HTMLDivElement>(null);
  const scrollDebounceRef = useRef<number | null>(null);

  const years = useMemo(() => {
    const cur = new Date().getFullYear();
    return Array.from({ length: 21 }, (_, i) => cur - 10 + i);
  }, []);
  const months = useMemo(() => Array.from({ length: 12 }, (_, i) => i + 1), []);

  const ITEM_HEIGHT = 44;
  const POPOVER_WIDTH = Math.min(340, window.innerWidth - 32);
  const POPOVER_HEIGHT = 330;

  // Positioning Logic
  const position = useMemo(() => {
    if (!anchorRect) return { top: 0, left: 0 };
    let left = anchorRect.left + anchorRect.width / 2 - POPOVER_WIDTH / 2;
    left = Math.min(Math.max(left, 16), window.innerWidth - 16 - POPOVER_WIDTH);

    let top = anchorRect.bottom + 10;
    if (top + POPOVER_HEIGHT > window.innerHeight - 16) {
      top = anchorRect.top - 10 - POPOVER_HEIGHT;
    }
    return { top, left };
  }, [anchorRect, POPOVER_WIDTH, POPOVER_HEIGHT]);

  const syncScroll = (ref: React.RefObject<HTMLDivElement>, value: number, options: number[]) => {
    if (!ref.current) return;
    const idx = options.indexOf(value);
    if (idx !== -1) {
      const target = ref.current.children[idx] as HTMLElement;
      if (target) {
        target.scrollIntoView({ block: 'center', behavior: 'auto' });
      }
    }
  };

  useLayoutEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Use double RAF to ensure the DOM is painted and scrollable
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          syncScroll(yearListRef, initialYear, years);
          syncScroll(monthListRef, initialMonth, months);
          setSelectedY(initialYear);
          setSelectedM(initialMonth);
        });
      });
    } else {
      document.body.style.overflow = '';
    }
  }, [isOpen, initialYear, initialMonth, years, months]);

  const handleScroll = (ref: React.RefObject<HTMLDivElement>, type: 'y' | 'm') => {
    if (!ref.current) return;
    if (scrollDebounceRef.current) window.clearTimeout(scrollDebounceRef.current);

    scrollDebounceRef.current = window.setTimeout(() => {
      const el = ref.current;
      if (!el) return;

      const children = Array.from(el.children) as HTMLElement[];
      const containerRect = el.getBoundingClientRect();
      const containerCenter = containerRect.top + containerRect.height / 2;

      let closestIdx = 0;
      let minDiff = Number.MAX_VALUE;

      children.forEach((child, idx) => {
        const rect = child.getBoundingClientRect();
        const childCenter = rect.top + rect.height / 2;
        const diff = Math.abs(containerCenter - childCenter);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = idx;
        }
      });

      const targetItem = children[closestIdx];
      if (targetItem) {
        targetItem.scrollIntoView({ block: 'center', behavior: 'smooth' });
        const options = type === 'y' ? years : months;
        const val = options[closestIdx];
        if (val !== undefined) {
          if (type === 'y') setSelectedY(val);
          else setSelectedM(val);
        }
      }
    }, 100);
  };

  const handleItemClick = (ref: React.RefObject<HTMLDivElement>, idx: number) => {
    if (!ref.current) return;
    const target = ref.current.children[idx] as HTMLElement;
    if (target) {
      target.scrollIntoView({ block: 'center', behavior: 'smooth' });
    }
  };

  if (!isOpen) return null;

  return createPortal(
    <div style={{ position: 'fixed', inset: 0, zIndex: 5000 }}>
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.25)' }} onClick={onClose} />

      <div
        className="fade-in"
        onClick={(e) => e.stopPropagation()}
        style={{
          position: 'fixed',
          top: position.top,
          left: position.left,
          width: POPOVER_WIDTH,
          height: POPOVER_HEIGHT,
          background: '#FFFFFF',
          borderRadius: '24px',
          padding: '16px',
          boxShadow: '0 18px 50px rgba(0,0,0,0.12)',
          border: '1px solid rgba(15, 23, 42, 0.06)',
          display: 'flex',
          flexDirection: 'column',
          pointerEvents: 'auto',
        }}
      >
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            marginBottom: '16px',
            alignItems: 'center',
            padding: '0 4px',
          }}
        >
          <button
            onClick={onClose}
            style={{
              border: 'none',
              background: 'none',
              fontSize: '14px',
              fontWeight: 'bold',
              color: theme.colors.textSecondary,
              cursor: 'pointer',
            }}
          >
            キャンセル
          </button>
          <span style={{ fontWeight: '900', fontSize: '15px', color: theme.colors.text }}>年月を選択</span>
          <button
            onClick={() => onConfirm(selectedY, selectedM)}
            style={{
              border: 'none',
              background: 'none',
              fontSize: '14px',
              fontWeight: '900',
              color: theme.colors.primary,
              cursor: 'pointer',
            }}
          >
            確定
          </button>
        </div>

        <div
          style={{
            position: 'relative',
            flex: 1,
            display: 'flex',
            overflow: 'hidden',
            background: 'rgba(0,0,0,0.02)',
            borderRadius: '16px',
          }}
        >
          {/* Central Highlight Layer: top:50% + translateY(-50%) for perfect centering */}
          <div
            style={{
              position: 'absolute',
              top: '50%',
              left: 12,
              right: 12,
              height: ITEM_HEIGHT,
              transform: 'translateY(-50%)',
              background: 'rgba(83, 190, 232, 0.08)',
              borderRadius: '10px',
              zIndex: 0,
              pointerEvents: 'none',
              borderTop: '0.5px solid rgba(83, 190, 232, 0.12)',
              borderBottom: '0.5px solid rgba(83, 190, 232, 0.12)',
            }}
          />

          {/* Year Wheel */}
          <div
            ref={yearListRef}
            onScroll={() => handleScroll(yearListRef, 'y')}
            style={{
              flex: 1,
              height: '100%',
              overflowY: 'auto',
              scrollSnapType: 'y mandatory',
              textAlign: 'center',
              zIndex: 1,
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto',
              overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3,
              paddingBottom: ITEM_HEIGHT * 3,
            }}
            className="hide-scrollbar"
          >
            {years.map((y, idx) => (
              <div
                key={y}
                onClick={() => handleItemClick(yearListRef, idx)}
                style={{
                  height: ITEM_HEIGHT,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  scrollSnapAlign: 'center',
                  fontSize: y === selectedY ? '18px' : '16px',
                  fontWeight: y === selectedY ? '900' : '500',
                  color: y === selectedY ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  userSelect: 'none',
                }}
              >
                {y}年
              </div>
            ))}
          </div>

          {/* Month Wheel */}
          <div
            ref={monthListRef}
            onScroll={() => handleScroll(monthListRef, 'm')}
            style={{
              flex: 1,
              height: '100%',
              overflowY: 'auto',
              scrollSnapType: 'y mandatory',
              textAlign: 'center',
              zIndex: 1,
              WebkitOverflowScrolling: 'touch',
              touchAction: 'pan-y',
              pointerEvents: 'auto',
              overscrollBehavior: 'contain',
              paddingTop: ITEM_HEIGHT * 3,
              paddingBottom: ITEM_HEIGHT * 3,
            }}
            className="hide-scrollbar"
          >
            {months.map((m, idx) => (
              <div
                key={m}
                onClick={() => handleItemClick(monthListRef, idx)}
                style={{
                  height: ITEM_HEIGHT,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  scrollSnapAlign: 'center',
                  fontSize: m === selectedM ? '18px' : '16px',
                  fontWeight: m === selectedM ? '900' : '500',
                  color: m === selectedM ? theme.colors.text : theme.colors.textWeak,
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  userSelect: 'none',
                }}
              >
                {m}月
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export const CalendarPage: React.FC<Props> = ({
  artists,
  exhibitions,
  onOpenArtist,
  onOpenConcert,
  onOpenExhibition,
  onRefreshAll,
  isMenuOpenExternally,
  onMenuClose,
}) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateKey, setSelectedDateKey] = useState<string | null>(null);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('mon');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const [mode, setMode] = useState<CalendarMode>('concert');

  const monthAnchorRef = useRef<HTMLDivElement | null>(null);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const [isWheelPickerOpen, setIsWheelPickerOpen] = useState(false);

  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [touchCurrentX, setTouchCurrentX] = useState<number | null>(null);

  useEffect(() => {
    setSelectedDateKey(null);
  }, [currentDate.getFullYear(), currentDate.getMonth(), mode]);

  const allEvents = useMemo(() => {
    return buildCalendarEvents(artists, { showAttended, showSkipped });
  }, [artists, showAttended, showSkipped]);

  const musicEventMap = useMemo(() => {
    const map = new Map<string, CalendarEvent[]>();
    allEvents.forEach((ev) => {
      const list = map.get(ev.dateKey) || [];
      list.push(ev);
      map.set(ev.dateKey, list);
    });
    return map;
  }, [allEvents]);

  const getExhibitionsForDay = (dateKey: string): Exhibition[] => {
    const day = dayjs(dateKey).startOf('day');
    return exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (day.isAfter(start) || day.isSame(start)) && (day.isBefore(end) || day.isSame(end));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });
  };

  const calendarWeeks = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();

    const firstOfMonth = dayjs(new Date(year, month, 1));
    const daysInMonth = firstOfMonth.daysInMonth();

    const firstDayIndex = firstOfMonth.day(); // 0=Sun..6=Sat
    const startOffset = weekStart === 'sun' ? firstDayIndex : firstDayIndex === 0 ? 6 : firstDayIndex - 1;

    const cells: Array<{ day: number | null; dateKey: string | null }> = [];
    for (let i = 0; i < startOffset; i++) cells.push({ day: null, dateKey: null });
    for (let d = 1; d <= daysInMonth; d++) {
      const dateKey = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      cells.push({ day: d, dateKey });
    }

    const weeks: Array<Array<{ day: number | null; dateKey: string | null }>> = [];
    for (let i = 0; i < cells.length; i += 7) weeks.push(cells.slice(i, i + 7));
    return weeks;
  }, [currentDate, weekStart]);

  const todayKey = useMemo(() => {
    const t = new Date();
    return `${t.getFullYear()}-${String(t.getMonth() + 1).padStart(2, '0')}-${String(t.getDate()).padStart(2, '0')}`;
  }, []);

  const handleDayClick = (day: number) => {
    const dateKey = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateKey(dateKey === selectedDateKey ? null : dateKey);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (isWheelPickerOpen) return;
    setTouchStartX(e.touches[0].clientX);
    setTouchCurrentX(e.touches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (touchStartX === null) return;
    setTouchCurrentX(e.touches[0].clientX);
  };

  const handleTouchEnd = () => {
    if (touchStartX === null || touchCurrentX === null) {
      setTouchStartX(null);
      setTouchCurrentX(null);
      return;
    }
    const dx = touchCurrentX - touchStartX;
    const threshold = 70;
    if (Math.abs(dx) > threshold) {
      if (dx < 0) setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
      else setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    }
    setTouchStartX(null);
    setTouchCurrentX(null);
  };

  const selectedDayEvents = useMemo(() => {
    if (!selectedDateKey) return [];
    if (mode === 'concert') {
      return (musicEventMap.get(selectedDateKey) || []).sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
    }
    return getExhibitionsForDay(selectedDateKey);
  }, [selectedDateKey, musicEventMap, mode, exhibitions]);

  const renderExhibitionRowBars = (week: Array<{ day: number | null; dateKey: string | null }>) => {
    const weekStartDay = week.find((d) => d.dateKey)?.dateKey;
    const weekEndDay = [...week].reverse().find((d) => d.dateKey)?.dateKey;
    if (!weekStartDay || !weekEndDay) return null;

    const startOfWeek = dayjs(weekStartDay).startOf('day');
    const endOfWeek = dayjs(weekEndDay).endOf('day');

    const weekExhibitions = exhibitions
      .filter((ex) => {
        const start = dayjs(ex.startDate).startOf('day');
        const end = dayjs(ex.endDate).endOf('day');
        return (start.isBefore(endOfWeek) || start.isSame(endOfWeek)) && (end.isAfter(startOfWeek) || end.isSame(startOfWeek));
      })
      .sort((a, b) => {
        const prioA = exhibitionPriorityMap[a.exhibitionStatus] || 99;
        const prioB = exhibitionPriorityMap[b.exhibitionStatus] || 99;
        if (prioA !== prioB) return prioA - prioB;
        return dayjs(a.startDate).unix() - dayjs(b.startDate).unix();
      });

    const top2 = weekExhibitions.slice(0, 2);
    const hasMore = weekExhibitions.length > 2;

    return (
      <div style={{ position: 'absolute', inset: 0, top: '28px', pointerEvents: 'none', zIndex: 1, padding: '0 4px' }}>
        {top2.map((ex, idx) => {
          const exStart = dayjs(ex.startDate).startOf('day');
          const exEnd = dayjs(ex.endDate).endOf('day');

          let startCol = -1;
          let endCol = -1;
          week.forEach((d, colIdx) => {
            if (!d.dateKey) return;
            const cur = dayjs(d.dateKey);
            if (cur.isSame(exStart, 'day')) startCol = colIdx;
            if (cur.isSame(exEnd, 'day')) endCol = colIdx;
          });

          if (startCol === -1) startCol = week.findIndex((d) => d.dateKey !== null);
          if (endCol === -1) endCol = 6 - [...week].reverse().findIndex((d) => d.dateKey !== null);

          const left = startCol * (100 / 7) + 0.5;
          const width = (endCol - startCol + 1) * (100 / 7) - 1;
          const shouldShowText = exStart.isAfter(startOfWeek.subtract(1, 'day')) && exStart.isBefore(endOfWeek.add(1, 'day'));

          return (
            <div
              key={ex.id}
              style={{
                position: 'absolute',
                top: `${idx * 8}px`,
                left: `${left}%`,
                width: `${width}%`,
                height: '6px',
                background: theme.colors.primary,
                opacity: idx === 0 ? 0.75 : 0.45,
                borderRadius: '999px',
                display: 'flex',
                alignItems: 'center',
                overflow: 'hidden',
              }}
            >
              {shouldShowText && (
                <span
                  style={{
                    fontSize: '8px',
                    fontWeight: '900',
                    color: 'white',
                    paddingLeft: '4px',
                    whiteSpace: 'nowrap',
                    textShadow: '0 1px 2px rgba(0,0,0,0.1)',
                  }}
                >
                  {ex.title}
                </span>
              )}
            </div>
          );
        })}
        {hasMore && (
          <div style={{ position: 'absolute', top: '18px', right: '4px', fontSize: '8px', fontWeight: '900', color: theme.colors.textWeak }}>
            +{weekExhibitions.length - 2}
          </div>
        )}
      </div>
    );
  };

  const handleOpenPicker = () => {
    if (monthAnchorRef.current) {
      setAnchorRect(monthAnchorRef.current.getBoundingClientRect());
      setIsWheelPickerOpen(true);
    }
  };

  return (
    <PageShell disablePadding>
      <div style={{ padding: 'calc(12px + env(safe-area-inset-top)) 16px 140px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr auto', alignItems: 'center', gap: '10px', marginBottom: '24px', height: '44px', width: '100%' }}>
          <div
            style={{
              display: 'inline-flex',
              background: 'white',
              padding: '3px',
              borderRadius: '999px',
              border: '1px solid rgba(0,0,0,0.06)',
              boxShadow: '0 2px 8px rgba(0,0,0,0.03)',
              whiteSpace: 'nowrap',
            }}
          >
            <button onClick={() => setMode('concert')} style={{ ...modeBtnStyle, background: mode === 'concert' ? theme.colors.primary : 'transparent', color: mode === 'concert' ? 'white' : theme.colors.textSecondary }}>
              公演
            </button>
            <button onClick={() => setMode('exhibition')} style={{ ...modeBtnStyle, background: mode === 'exhibition' ? theme.colors.primary : 'transparent', color: mode === 'exhibition' ? 'white' : theme.colors.textSecondary }}>
              展覧
            </button>
          </div>

          <div
            ref={monthAnchorRef}
            onClick={handleOpenPicker}
            style={{
              justifySelf: 'center',
              fontSize: '17px',
              fontWeight: '900',
              color: theme.colors.text,
              cursor: 'pointer',
              display: 'inline-flex',
              alignItems: 'center',
              padding: '6px 10px',
              borderRadius: '12px',
              maxWidth: '100%',
            }}
          >
            <span style={{ minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
            </span>
            <span style={{ flexShrink: 0, marginLeft: '6px', fontSize: '10px', opacity: 0.35, lineHeight: 1 }}>▼</span>
          </div>

          <button
            onClick={() => setCurrentDate(new Date())}
            style={{
              border: '1px solid rgba(0,0,0,0.06)',
              background: 'white',
              color: theme.colors.primary,
              fontSize: '12px',
              fontWeight: 800,
              padding: '8px 14px',
              borderRadius: '999px',
              cursor: 'pointer',
              whiteSpace: 'nowrap',
            }}
          >
            今日
          </button>
        </div>

        <div
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          style={{
            background: 'white',
            borderRadius: '28px',
            padding: '16px 10px',
            border: '1px solid rgba(0,0,0,0.04)',
            boxShadow: '0 4px 20px rgba(0,0,0,0.03)',
            overflow: 'hidden',
            userSelect: 'none',
            touchAction: 'pan-y',
          }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '8px' }}>
            {(weekStart === 'sun'
              ? [TEXT.CALENDAR.WEEK_SUN, TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT]
              : [TEXT.CALENDAR.WEEK_MON, TEXT.CALENDAR.WEEK_TUE, TEXT.CALENDAR.WEEK_WED, TEXT.CALENDAR.WEEK_THU, TEXT.CALENDAR.WEEK_FRI, TEXT.CALENDAR.WEEK_SAT, TEXT.CALENDAR.WEEK_SUN]
            ).map((l) => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>
                {l}
              </div>
            ))}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {calendarWeeks.map((week, wIdx) => (
              <div key={wIdx} style={{ position: 'relative', display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', minHeight: mode === 'exhibition' ? '48px' : '44px' }}>
                {week.map((d, colIdx) => {
                  if (d.day === null) return <div key={`empty-${colIdx}`} />;
                  const isSelected = selectedDateKey === d.dateKey;
                  const isToday = d.dateKey === todayKey;
                  const musicEvents = d.dateKey ? musicEventMap.get(d.dateKey) || [] : [];
                  return (
                    <div
                      key={d.day}
                      onClick={() => d.day && handleDayClick(d.day)}
                      style={{
                        position: 'relative',
                        padding: '6px 4px 10px 4px',
                        borderRadius: '12px',
                        cursor: 'pointer',
                        background: isSelected ? 'rgba(83, 190, 232, 0.10)' : 'transparent',
                        border: isSelected ? '2px solid rgba(83, 190, 232, 0.55)' : '2px solid transparent',
                        zIndex: 0,
                      }}
                    >
                      <div style={{ textAlign: 'center', fontSize: '12px', fontWeight: isToday ? 900 : 700, color: isToday ? theme.colors.primary : theme.colors.text, lineHeight: 1, paddingTop: '2px' }}>
                        {d.day}
                      </div>

                      {mode === 'concert' && musicEvents.length > 0 && (() => {
                        const sorted = [...musicEvents].sort((a, b) => EVENT_PRIORITY[a.type] - EVENT_PRIORITY[b.type]);
                        const primary = sorted[0];
                        let primaryDotColor: string | null = null;

                        if (primary) {
                          if (isConcertType(primary.type)) primaryDotColor = getConcertDotColor(primary.status);
                          else primaryDotColor = typeColorMap[primary.type] || theme.colors.primary;
                        }

                        return (
                          <div style={{ marginTop: '6px', height: '6px', display: 'flex', alignItems: 'center', gap: '2px', justifyContent: 'center' }}>
                            {primaryDotColor && <div style={{ width: '6px', height: '6px', borderRadius: '9999px', background: primaryDotColor }} />}
                            {musicEvents.length > 1 && <div style={{ width: '4px', height: '4px', borderRadius: '9999px', background: '#CBD5E1' }} />}
                          </div>
                        );
                      })()}
                    </div>
                  );
                })}
                {mode === 'exhibition' && renderExhibitionRowBars(week)}
              </div>
            ))}
          </div>
        </div>

        {selectedDateKey && (
          <div style={{ marginTop: '16px' }} className="fade-in">
            <div style={{ fontWeight: 900, marginBottom: '10px', color: theme.colors.textSecondary, fontSize: '13px' }}>{selectedDateKey.replace(/-/g, '/')} の予定</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {selectedDayEvents.length === 0 ? (
                <div style={{ color: theme.colors.textWeak, fontWeight: 700, padding: '12px 0' }}>予定はありません</div>
              ) : mode === 'concert' ? (
                (selectedDayEvents as CalendarEvent[]).map((ev, idx) => (
                  <div key={idx} style={eventCardStyle} onClick={() => ev.type === '公演' ? onOpenConcert(ev.artistId, ev.tourId, ev.concertId) : onOpenArtist(ev.artistId)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ev.title}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 700 }}>{ev.timeLabel ? `${ev.timeLabel} - ` : ''}{ev.type}</div>
                    </div>
                    <div style={{ color: theme.colors.textWeak, fontWeight: 900 }}>›</div>
                  </div>
                ))
              ) : (
                (selectedDayEvents as Exhibition[]).map((ex) => (
                  <div key={ex.id} style={eventCardStyle} onClick={() => onOpenExhibition(ex.id)}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                      <div style={{ fontWeight: 900 }}>{ex.title}</div>
