        if (Array.isArray(json)) { setStagedImportData(json); setIsImportConfirmOpen(true); }
      } catch (err) { console.error('Import failed:', err); }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <PageShell
      header={hideHeader ? null : (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0 }}>
            {TEXT.GLOBAL.APP_TITLE} <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button onClick={handleRefresh} disabled={refreshState !== 'idle'} style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: refreshState === 'completed' ? theme.colors.success : '#9CA3AF', cursor: refreshState === 'idle' ? 'pointer' : 'default', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            {refreshState === 'completed' ? <Icons.Check /> : <Icons.Refresh className={refreshState === 'refreshing' ? 'animate-spin' : ''} />}
          </button>
        </div>
      )}
      disablePadding={hideHeader}
    >
      <input type="file" ref={fileInputRef} style={{ display: 'none' }} accept=".json" onChange={handleFileChange} />

      <div style={{ paddingBottom: '120px' }}>
        {sortedArtists.length === 0 ? (
          <div style={{ padding: '80px 20px', textAlign: 'center', color: theme.colors.textWeak, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '24px' }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>👤</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>{TEXT.GLOBAL.APP_SUBTITLE}</div>
            <button onClick={onOpenArtistEditor} style={{ padding: '12px 24px', borderRadius: '12px', background: theme.colors.primary, color: 'white', border: 'none', fontWeight: 'bold' }}>＋ {TEXT.BUTTONS.ADD}</button>
          </div>
        ) : (
          <div style={
            sortMode === 'status' 
              ? { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '16px' }
              : { display: 'flex', flexDirection: 'column', gap: '12px' }
          }>
            {sortedArtists.map((artist, index) => (
              sortMode === 'status' ? (
                <ArtistGridCard key={artist.id} artist={artist} onClick={() => onOpenArtist(artist.id)} />
              ) : (
                <ArtistRowCard 
                  key={artist.id} artist={artist} onClick={() => onOpenArtist(artist.id)} 
                  draggable={sortMode === 'manual'} onDragStart={() => handleDragStart(index)} onDragEnter={() => handleDragEnter(index)} onDragEnd={handleDragEnd}
                  noticeKeywords={getNoticeKeywords(artist)} onAcknowledgeNotice={() => onAcknowledgeArtistTracking(artist.id)}
                />
              )
            ))}
          </div>
        )}
      </div>

      <BottomMenu 
        isOpen={!!isMenuOpenExternally} onClose={() => onMenuClose?.()} onAddArtist={onOpenArtistEditor}
        onExport={onExport || (() => {})} onImport={handleImportClick} currentSort={sortMode} onSetSort={onSetSort}
        globalSettings={globalSettings} onUpdateGlobalSettings={onUpdateGlobalSettings} onClearTrackingNotices={onClearAllTrackingNotices}
      />
      <ConfirmDialog isOpen={isImportConfirmOpen} title={TEXT.ALERTS.IMPORT_CONFIRM_TITLE} message={TEXT.ALERTS.IMPORT_CONFIRM_MSG} confirmLabel={TEXT.BUTTONS.IMPORT} isDestructive onClose={() => { setIsImportConfirmOpen(false); setStagedImportData(null); }} onConfirm={() => { if (stagedImportData) onImportData(stagedImportData); setIsImportConfirmOpen(false); }} />
    </PageShell>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { theme } from '../../ui/theme';
import { GlassCard } from '../../ui/GlassCard';
import { Exhibition, ExhibitionOverallStatus, ExhibitionTicketSalesStatus } from '../../domain/types';
import { Icons } from '../../ui/IconButton';
import {
  Select,
  Input,
  Checkbox,
  TimePicker,
  DatePicker,
  Button,
  InputNumber,
  Divider,
  Typography,
  Space,
  Tag
} from 'antd';
import dayjs from 'dayjs';

const { Text } = Typography;

// --- Fixed Modal Style Date Picker for Exhibition Detail Page ---
const CustomExhibitionDatePicker = ({
  value,
  onChange,
  showTime = false,
  placeholder = '未設定'
}: {
  value: string | null | undefined;
  onChange: (val: string) => void;
  showTime?: boolean;
  placeholder?: string;
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const valStr = value || '';
  const initialDateStr = valStr === 'TBD' || !valStr ? '' : valStr.split(' ')[0];
  const initialTimeStr = showTime && valStr && valStr.includes(' ') ? valStr.split('12:00')[1] : '12:00';

  const [viewDate, setViewDate] = useState(initialDateStr ? dayjs(initialDateStr) : dayjs());
  const [selectedTime, setSelectedTime] = useState(initialTimeStr);

  useEffect(() => {
    if (!isOpen) return;
    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = originalOverflow;
    };
  }, [isOpen]);

  const calendarDays = useMemo(() => {
    const first = viewDate.startOf('month').day();
    const count = viewDate.daysInMonth();
    const days: Array<number | null> = [];
    for (let i = 0; i < first; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [viewDate]);

  const handleSelectDay = (day: number) => {
    const datePart = viewDate.date(day).format('YYYY-MM-DD');
    if (showTime) {
      onChange(`${datePart} ${selectedTime}`);
    } else {
      onChange(datePart);
      setIsOpen(false);
    }
  };

  const hours = Array.from({ length: 24 }, (_, i) => String(i).padStart(2, '0'));
  const minuteOptions = Array.from({ length: 12 }, (_, i) => String(i * 5).padStart(2, '0'));

  return (
    <div style={{ position: 'relative' }}>
      <div
        onClick={() => setIsOpen(true)}
        style={{
          width: '100%',
          padding: '10px 12px',
          borderRadius: '10px',
          border: '1px solid rgba(0,0,0,0.08)',
          background: 'white',
          fontSize: '14px',
          outline: 'none',
          cursor: 'pointer',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          minHeight: '40px'
        }}
      >
        <span style={{ color: !valStr ? theme.colors.textWeak : 'inherit' }}>
          {valStr ? valStr.replace(/-/g, '/') : placeholder}
        </span>
        {showTime ? <Icons.Clock style={{ width: 16 }} /> : <Icons.Calendar style={{ width: 16 }} />}
      </div>

      {isOpen &&
        typeof document !== 'undefined' &&
        createPortal(
          <div
            style={{
              position: 'fixed',
              inset: 0,
              zIndex: 5000,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '16px'
            }}
          >
            <div
              style={{
                position: 'absolute',
                inset: 0,
                background: 'rgba(15, 23, 42, 0.45)',
                backdropFilter: 'blur(4px)',
                WebkitBackdropFilter: 'blur(4px)'
              }}
              onClick={() => setIsOpen(false)}
            />

            <GlassCard
              padding="20px"
              style={{
                position: 'relative',
                width: '100%',
                maxWidth: '340px',
                zIndex: 5001,
                boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
                borderRadius: '24px'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                <button type="button" onClick={() => setViewDate(viewDate.subtract(1, 'month'))} style={navBtnStyle}>
                  ◀
                </button>
                <div style={{ fontWeight: '900', fontSize: '15px' }}>{viewDate.format('YYYY年 M月')}</div>
                <button type="button" onClick={() => setViewDate(viewDate.add(1, 'month'))} style={navBtnStyle}>
                  ▶
                </button>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px', textAlign: 'center' }}>
                {['日', '月', '火', '水', '木', '金', '土'].map((d) => (
                  <div
                    key={d}
                    style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak, paddingBottom: '8px' }}
                  >
                    {d}
                  </div>
                ))}
                {calendarDays.map((day, i) => {
                  const isSelected = day && initialDateStr === viewDate.date(day).format('YYYY-MM-DD');
                  return (
                    <div
                      key={i}
                      onClick={() => day && handleSelectDay(day)}
                      style={{
                        padding: '10px 0',
                        fontSize: '14px',
                        borderRadius: '10px',
                        cursor: day ? 'pointer' : 'default',
                        background: isSelected ? theme.colors.primary : 'transparent',
                        color: isSelected ? 'white' : theme.colors.textMain,
                        opacity: day ? 1 : 0,
                        fontWeight: isSelected ? '900' : '600'
                      }}
                    >
                      {day}
                    </div>
                  );
                })}
              </div>

              {showTime && (
                <div style={{ borderTop: '1px solid rgba(0,0,0,0.05)', paddingTop: '16px', marginTop: '16px' }}>
                  <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                    <select
                      value={selectedTime.split(':')[0]}
                      onChange={(e) => {
                        const nextTime = `${e.target.value}:${selectedTime.split(':')[1]}`;
                        setSelectedTime(nextTime);
                        if (initialDateStr) onChange(`${initialDateStr} ${nextTime}`);
                      }}
                      style={selectTimeStyle}
                    >
                      {hours.map((h) => (
                        <option key={h} value={h}>
                          {h}時
                        </option>
                      ))}
                    </select>
                    <select
                      value={selectedTime.split(':')[1]}
                      onChange={(e) => {
                        const nextTime = `${selectedTime.split(':')[0]}:${e.target.value}`;
                        setSelectedTime(nextTime);
                        if (initialDateStr) onChange(`${initialDateStr} ${nextTime}`);
                      }}
                      style={selectTimeStyle}
                    >
                      {minuteOptions.map((m) => (
                        <option key={m} value={m}>
                          {m}分
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button
                  type="button"
                  onClick={() => {
                    onChange('');
                    setIsOpen(false);
                  }}
                  style={{
                    flex: 1,
                    padding: '12px',
                    background: 'rgba(0,0,0,0.05)',
                    borderRadius: '12px',
                    border: 'none',
                    cursor: 'pointer',
                    fontWeight: 'bold',
                    fontSize: '13px',
                    color: theme.colors.textSecondary
                  }}
                >
                  クリア
                </button>
                <button
                  type="button"
                  onClick={() => setIsOpen(false)}
                  style={{
                    flex: 1,
                    padding: '12px',
                    background: theme.colors.primary,
                    color: 'white',
                    borderRadius: '12px',
                    border: 'none',
                    cursor: 'pointer',
                    fontWeight: 'bold',
                    fontSize: '13px'
                  }}
                >
                  確定
                </button>
              </div>
            </GlassCard>
          </div>,
          document.body
        )}
    </div>
  );
};

const navBtnStyle: React.CSSProperties = {
  border: 'none',
  background: 'none',
  padding: '8px',
  cursor: 'pointer',
  fontSize: '14px',
  color: theme.colors.primary
};

const selectTimeStyle: React.CSSProperties = {
  flex: 1,
  padding: '8px',
  borderRadius: '10px',
  border: '1px solid rgba(0,0,0,0.1)',
  background: 'white',
  fontSize: '14px',
  outline: 'none',
  fontWeight: '600'
};

interface Props {
  exhibition: Exhibition;
  allExhibitions: Exhibition[];
  isEditMode: boolean;
  onChange: (updates: Partial<Exhibition>) => void;
}

export const ExhibitionInfoSection: React.FC<Props> = ({ exhibition, allExhibitions, isEditMode, onChange }) => {
  const [isExpanded, setIsExpanded] = useState(true);

  const areaOptions = useMemo(() => {
    const areas = new Set<string>();
    for (const e of allExhibitions) {
      if (e.area) areas.add(e.area);
    }
    return Array.from(areas).sort();
  }, [allExhibitions]);

  const venueOptions = useMemo(() => {
    const venues = new Set<string>();
    for (const e of allExhibitions) {
      const v = e.venueName || (e as any).venue;
      if (v) venues.add(v);
    }
    return Array.from(venues).sort();
  }, [allExhibitions]);

  const Label = ({ children }: { children?: React.ReactNode }) => (
    <div
      style={{
        fontSize: '11px',
        fontWeight: '800',
        color: theme.colors.textWeak,
        marginBottom: '2px',
        textTransform: 'uppercase',
        letterSpacing: '0.05em'
      }}
    >
      {children}
    </div>
  );

  const Value = ({
    children,
    placeholder = '未設定',
    color = theme.colors.textMain
  }: {
    children?: React.ReactNode;
    placeholder?: string;
    color?: string;
  }) => (
    <div style={{ fontSize: '15px', fontWeight: '700', color: children ? color : theme.colors.textWeak }}>
      {children || placeholder}
    </div>
  );

  const SectionTitle = ({ title }: { title: string }) => (
    <div style={{ marginTop: '20px', marginBottom: '12px' }}>
      <Text strong style={{ fontSize: '12px', color: theme.colors.primary, letterSpacing: '0.05em' }}>
        {title}
      </Text>
      <Divider style={{ margin: '4px 0', borderColor: 'rgba(0,0,0,0.04)' }} />
    </div>
  );

  const ticketStatusLabels: Record<ExhibitionTicketSalesStatus, string> = {
    none: 'なし',
    before_sale: '販売前',
    not_purchased: '未購入',
    purchased: '購入済'
  };

  const ticketStatusColors: Record<ExhibitionTicketSalesStatus, string> = {
    none: '#9CA3AF',
    before_sale: '#F59E0B',
    not_purchased: '#9CA3AF',
    purchased: '#10B981'
  };

  return (
    <GlassCard padding="20px">
      <div 
        onClick={() => !isEditMode && setIsExpanded(!isExpanded)}
        style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          cursor: isEditMode ? 'default' : 'pointer',
          marginBottom: (isExpanded || isEditMode) ? '20px' : '0'
        }}
      >
        <h3 style={{ fontSize: '16px', fontWeight: '900', margin: 0, color: theme.colors.primary }}>基本情報</h3>
        {!isEditMode && (
          <Icons.ChevronLeft 
            style={{ 
              width: 20, 
              height: 20, 
              transition: 'transform 0.3s cubic-bezier(0.4, 0, 0.2, 1)', 
              transform: isExpanded ? 'rotate(270deg)' : 'rotate(180deg)',
              color: theme.colors.textSecondary
            }} 
          />
        )}
      </div>

      {(isExpanded || isEditMode) && (
        <>
          {isEditMode ? (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <div>
                <Label>ポスター画像 (URL)</Label>
                <Input value={exhibition.imageUrl} onChange={(e) => onChange({ imageUrl: e.target.value })} placeholder="https://..." />
              </div>

              <div>
                <Label>会期</Label>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                  <CustomExhibitionDatePicker
                    value={exhibition.startDate}
                    placeholder="開始日"
                    onChange={(v) => {
                      const nextStart = v;
                      let nextEnd = exhibition.endDate;
                      if (nextStart && nextEnd && dayjs(nextStart).isAfter(dayjs(nextEnd))) {
                        nextEnd = nextStart;
                      }
                      onChange({ startDate: nextStart, endDate: nextEnd });
                    }}
                  />
                  <CustomExhibitionDatePicker
                    value={exhibition.endDate}
                    placeholder="終了日"
                    onChange={(v) => {
                      const nextEnd = v;
                      let nextStart = exhibition.startDate;
                      if (nextEnd && nextStart && dayjs(nextEnd).isBefore(dayjs(nextStart))) {
                        nextStart = nextEnd;
                      }
                      onChange({ startDate: nextStart, endDate: nextEnd });
                    }}
                  />
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <Label>エリア</Label>
                  <Input
                    value={exhibition.area}
                    onChange={(e) => onChange({ area: e.target.value })}
                    placeholder="エリアを入力/選択"
                    list="exhibition-area-options"
                  />
                  <datalist id="exhibition-area-options">
                    {areaOptions.map((a) => (
                      <option key={a} value={a} />
                    ))}
                  </datalist>
                </div>
                <div>
                  <Label>会場名</Label>
                  <Input
                    value={exhibition.venueName || exhibition.venue}
                    onChange={(e) => onChange({ venueName: e.target.value })}
                    placeholder="会場名を入力/選択"
                    list="exhibition-venue-options"
                  />
                  <datalist id="exhibition-venue-options">
                    {venueOptions.map((v) => (
                      <option key={v} value={v} />
                    ))}
                  </datalist>
                </div>
              </div>

              <SectionTitle title="ステータス・チケット" />
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <Label>参戦日時</Label>
                  <CustomExhibitionDatePicker showTime value={exhibition.visitedAt} placeholder="参戦日時" onChange={(v) => onChange({ visitedAt: v })} />
                  {exhibition.visitedAt && (
                    <Button size="small" danger type="text" onClick={() => onChange({ visitedAt: undefined })} style={{ padding: 0 }}>
                      记录解除
                    </Button>
                  )}
                </div>
                <div>
                  <Label>チケット状態</Label>
                  <Select
                    style={{ width: '100%' }}
                    value={exhibition.ticketSalesStatus || 'none'}
                    onChange={(v) => onChange({ ticketSalesStatus: v })}
                    getPopupContainer={() => document.body}
                    dropdownStyle={{ zIndex: 3000 }}
                    options={[
                      { label: 'なし', value: 'none' },
                      { label: '販売前', value: 'before_sale' },
                      { label: '未購入', value: 'not_purchased' },
                      { label: '購入済', value: 'purchased' }
                    ]}
                  />
                  {exhibition.ticketSalesStatus === 'before_sale' && (
                    <div style={{ marginTop: '8px' }}>
                      <Label>発売開始</Label>
                      <CustomExhibitionDatePicker showTime value={exhibition.saleStartAt} placeholder="発売開始" onChange={(v) => onChange({ saleStartAt: v })} />
                    </div>
                  )}
                </div>
              </div>

              <div>
                <Label>公式サイトURL</Label>
                <Input value={exhibition.websiteUrl} onChange={(e) => onChange({ websiteUrl: e.target.value })} placeholder="https://..." />
