export const ConcertListPage: React.FC<Props> = ({
  artists,
  onOpenArtist,
  onOpenConcert,
  onCreateConcert,
  onRefreshAll,
  onUpdateConcert,
  sortMode,
  onSetSort,
  viewMode,
  onSetViewMode,
  isMenuOpenExternally,
  onMenuClose,
  hideHeader,
}) => {
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach((artist) =>
      artist.tours.forEach((tour) =>
        tour.concerts.forEach((concert) => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            artistImageUrl: artist.imageUrl || '',
            tourName: tour.name,
            tourId: tour.id,
            tourImageUrl: tour.imageUrl || '',
            tourOfficialUrl: tour.officialUrl,
          });
        }),
      ),
    );
    return list;
  }, [artists]);

  const displayList = useMemo(() => {
    const sorted = sortMode === 'lottery' ? sortPerformancesByLotteryDate(allConcerts as any) : sortPerformancesForDisplay(allConcerts as any);
    const filtered = (sorted as ConcertWithMetadata[]).filter((c) => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });

    // Handle grouping logic based on viewMode
    if (viewMode === 'concert') {
      const grouped: (ConcertWithMetadata | { type: 'tour_group'; tourId: string; concerts: ConcertWithMetadata[] })[] = [];
      const processedTourIds = new Set<string>();

      filtered.forEach((item) => {
        if (processedTourIds.has(item.tourId)) return;

        // Find all concerts of this tour that are in the filtered list
        const tourConcerts = filtered.filter(c => c.tourId === item.tourId);

        if (tourConcerts.length > 1) {
          grouped.push({ type: 'tour_group', tourId: item.tourId, concerts: tourConcerts });
        } else {
          grouped.push(item);
        }
        processedTourIds.add(item.tourId);
      });
      return grouped;
    }

    return filtered;
  }, [allConcerts, showAttended, showSkipped, sortMode, viewMode]);

  return (
    <PageShell
      header={
        hideHeader ? null : (
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
            <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0 }}>
              {TEXT.GLOBAL.APP_TITLE} <span style={{ color: '#53BEE8' }}>JP</span>
            </h1>
            <button
              onClick={onRefreshAll}
              style={{
                padding: '12px',
                borderRadius: '9999px',
                background: 'white',
                border: '1px solid #F3F4F6',
                color: '#9CA3AF',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Icons.Refresh />
            </button>
          </div>
        )
      }
      disablePadding={hideHeader}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {displayList.length === 0 ? (
          <div style={{ padding: '80px 20px', textAlign: 'center', color: theme.colors.textWeak, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '24px' }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>{TEXT.LABELS.SCHEDULE_EMPTY}</div>
            <button onClick={onCreateConcert} style={{ padding: '12px 24px', borderRadius: '12px', background: theme.colors.primary, color: 'white', border: 'none', fontWeight: 'bold' }}>
              ＋ {TEXT.BUTTONS.ADD}
            </button>
          </div>
        ) : (
          displayList.map((item) => {
            if ('type' in item && item.type === 'tour_group') {
              const main = item.concerts[0];
              return (
                <TourGroupCard
                  key={`group-${item.tourId}`}
                  tourName={main.tourName}
                  artistName={main.artistName}
                  imageUrl={main.tourImageUrl || main.artistImageUrl}
                  status={main.status}
                  concerts={item.concerts}
                  onOpenConcert={onOpenConcert}
                />
              );
            } else {
              const concert = item as ConcertWithMetadata;
              if (viewMode === 'concert') {
                return (
                  <TourGroupCard
                    key={concert.id}
                    tourName={concert.tourName}
                    artistName={concert.artistName}
                    imageUrl={concert.tourImageUrl || concert.artistImageUrl}
                    status={concert.status}
                    concerts={[concert]}
                    onOpenConcert={onOpenConcert}
                  />
                );
              } else {
                return (
                  <MilestoneRowCard key={concert.id} concert={concert} sortMode={sortMode} onClick={() => onOpenArtist(concert.artistId)} />
                );
              }
            }
          })
        )}
      </div>

      <ConcertMenu
        isOpen={!!isMenuOpenExternally}
        onClose={() => onMenuClose?.()}
        onAddConcert={onCreateConcert}
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
        sortMode={sortMode}
        onSetSort={onSetSort}
        viewMode={viewMode}
        onSetViewMode={onSetViewMode}
      />
    </PageShell>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
