      );
      setEditArtist({ ...editArtist, concerts: newConcerts });
      setConcertUrlInputs(prev => ({ ...prev, [concertId]: '' }));
    }
  } finally {
    setConcertUrlLoading(prev => ({ ...prev, [concertId]: false }));
  }
