          latestKeyword: result.keyword || artist.latestKeyword, 
          hasUpdate: true, 
          lastChecked: new Date().toISOString() 
        };
      }
      return { ...artist, lastChecked: new Date().toISOString() };
    }));
    setArtists(updatedArtists);
    setIsRefreshing(false);
  };

