                <button onClick={() => setEditArtist({...editArtist, websiteUrls: [...(editArtist.websiteUrls || []), { name: '', url: '' }]})} className="text-[10px] font-black text-[#53BEE8]">+ 追加</button>
              </div>
              {(editArtist.websiteUrls || []).map((item, i) => (
