                    {Array.from({length: 48}).map((_, i) => {
                      const h = Math.floor(i / 2).toString().padStart(2, '0');
                      const m = (i % 2 === 0 ? '00' : '30');
                      return <option key={i} value={`${h}:${m}`}>{h}:{m}</option>;
                    })}
                  </select>
                </div>
              </div>
