                          <input value={concert.name} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; newC[cIdx].name = e.target.value; setEditArtist({ ...editArtist, concerts: newC }); }} placeholder="公演名" className="w-full text-lg font-black border-b border-slate-100 outline-none p-1" />
                          <input value={concert.websiteUrl || ''} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; newC[cIdx].websiteUrl = e.target.value; setEditArtist({ ...editArtist, concerts: newC }); }} placeholder="公演公式サイトURL" className="w-full text-xs font-bold border-b border-slate-50 outline-none p-1 text-gray-400" />
                        </div>
                        <button onClick={() => { if (!editArtist.concerts) return; const newC = editArtist.concerts.filter((_, idx) => idx !== cIdx); setEditArtist({...editArtist, concerts: newC}); }} className="text-red-300 hover:text-red-500 self-start mt-2">✕</button>
