                                <DatePicker 
                                  placeholder="公演日"
                                  className="flex-grow !rounded-[12px] h-10"
                                  disabled={perf.isUndetermined}
                                  value={perf.date ? dayjs(perf.date) : null}
                                  onChange={(date) => {
                                    if (!editArtist.concerts) return;
                                    const newC = [...editArtist.concerts];
                                    const dateStr = date ? date.format('YYYY-MM-DD') : '';
                                    (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].date = dateStr;
                                    const isNewDatePast = isValidDate(dateStr) && (new Date(dateStr) < new Date(now.getFullYear(), now.getMonth(), now.getDate()));
                                    if (isNewDatePast && newC[cIdx].performances![pIdx].status === ConcertStatus.PENDING) {
                                      newC[cIdx].performances![pIdx].status = ConcertStatus.SKIPPED;
                                    }
                                    setEditArtist({ ...editArtist, concerts: newC });
                                  }}
                                />
                                <label className="flex items-center gap-1 cursor-pointer">
                                  <input type="checkbox" checked={perf.isUndetermined} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].isUndetermined = e.target.checked; if(e.target.checked) newC[cIdx].performances![pIdx].date = ''; setEditArtist({ ...editArtist, concerts: newC }); }} />
