                                <button onClick={() => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; newC[cIdx].performances = (newC[cIdx].performances || []).filter(p => String(p.id) !== String(perf.id)); setEditArtist({ ...editArtist, concerts: newC }); }} className="text-gray-300 hover:text-red-400">✕</button>
