                                <div className="grid grid-cols-2 gap-2">
                                  <input value={perf.price || ''} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].price = e.target.value; setEditArtist({ ...editArtist, concerts: newC }); }} placeholder="价格" className="p-2 rounded-lg text-[10px] font-bold bg-white border border-slate-100" />
                                  <input value={perf.ticketUrl || ''} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].ticketUrl = e.target.value; setEditArtist({ ...editArtist, concerts: newC }); }} placeholder="チケットURL" className="p-2 rounded-lg text-[10px] font-bold bg-white border border-slate-100" />
