interface ArtistDetailPageProps {
  selectedArtist: Artist | null;
  now: Date;

  getArtistStatus: (artist: Artist, now: Date) => {
    label: string;
    color: string;
  };

  setCurrentPage: (page: 'HOME' | 'DETAIL' | 'SETTINGS' | 'CONCERT_SUMMARY') => void;
