/**
 * Simulates the AI monitoring of artist websites for new concert or ticket info.
 */
export const simulateMonitor = async (artist: Artist): Promise<MonitorResult> => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  // 10% chance to detect a change for demonstration purposes
  if (Math.random() > 0.9) {
    if (artist.stage === MonitoringStage.MONITORING_CONCERT) {
      return {
        hasChange: true,
        newStage: MonitoringStage.CONCERT_DETECTED,
        keyword: '2024 Tour Announced'
      };
    }
    if (artist.stage === MonitoringStage.MONITORING_TICKETS) {
      return {
        hasChange: true,
        keyword: 'General Sale Started'
      };
    }
  }

  return { hasChange: false };
};

