              <button onClick={() => setEditArtist({ ...editArtist, concerts: [...(editArtist.concerts || []), { id: Date.now().toString(), name: '', date: 'TBD', venue: '', price: 0, saleLink: '', status: '発売前', isParticipated: false, imageIds: [], performances: [] }] })} className="text-xs font-black text-[#53BEE8]">+ 公演を追加</button>
            </div>
            {(!editArtist.concerts || editArtist.concerts.length === 0) && (
              <div className="p-10 text-center bg-gray-50/50 rounded-[2rem] border border-dashed border-gray-200">
                <p className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">公演情報なし</p>
              </div>
            )}
            {(editArtist.concerts || []).map((concert, cIdx) => {
              const now = new Date();
              return (
                <div key={concert.id} className="p-6 bg-white border border-slate-100 rounded-[2.5rem] shadow-sm space-y-6">
                  <div className="flex flex-col sm:flex-row gap-6">
                    <div className="flex-shrink-0 flex flex-col items-center space-y-3">
                      <div
                        className="w-24 h-24 sm:w-32 sm:h-32 rounded-2xl overflow-hidden bg-slate-100 border-2 border-slate-200 shadow-inner flex items-center justify-center"
                      >
                        {concert.imageUrl ? (
                          <img
                            src={concert.imageUrl}
                            onError={(e) => {
                              (e.target as HTMLImageElement).removeAttribute('src');
                            }}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <svg className="w-10 h-10 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 7h18M3 7v13h18V7M7 7V4h10v3M8 12l3 3 5-6" />
                          </svg>
                        )}
                      </div>

                      <div className="mt-2 w-full max-w-[120px]">
                        <div className="flex flex-col gap-1.5">
                          <input 
                            type="text" 
                            value={concertUrlInputs[concert.id] || ''} 
