                                  <input value={perf.ticketUrl || ''} onChange={(e) => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].ticketUrl = e.target.value; setEditArtist({ ...editArtist, concerts: newC }); }} placeholder="チケットURL" className="p-2 rounded-lg text-[10px] font-bold bg-white border border-slate-100" />
                                </div>
                              </div>
                              <div className="flex gap-1">
                                {[ConcertStatus.PENDING, ConcertStatus.SKIPPED, ConcertStatus.LOST, ConcertStatus.JOINED].map(s => {
                                  const isDisabled = s === ConcertStatus.PENDING && isPastDate;
                                  return (
                                    <button 
                                      key={s} 
                                      disabled={isDisabled}
                                      onClick={() => { if (!editArtist.concerts) return; const newC = [...editArtist.concerts]; (newC[cIdx].performances || (newC[cIdx].performances = []))[pIdx].status = s; setEditArtist({ ...editArtist, concerts: newC }); }} 
                                      className={`flex-1 py-1.5 text-[9px] font-black rounded-lg border transition-all ${perf.status === s ? 'bg-[#53BEE8] text-white border-[#53BEE8]' : 'bg-white text-gray-400 border-slate-100'} ${isDisabled ? 'opacity-20 cursor-not-allowed bg-gray-100' : ''}`}
                                    >
                                      {s === 'PENDING' ? '検討' : s === 'SKIPPED' ? '見送り' : s === 'LOST' ? '落選' : '参戦'}
                                    </button>
                                  );
                                })}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </section>

          <div className="pt-10 flex flex-col items-center">
            <button disabled={!isDirty} onClick={() => saveArtistSettings()} className={`px-16 py-4 rounded-full text-sm font-black transition-all ${isDirty ? 'bg-[#53BEE8] text-white shadow-xl shadow-[#53BEE8]/20' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>保存</button>
          </div>
        </div>
